def _k6_barycentric_sweep_mixtures() -> dict[str, tuple[tuple[float, tuple[int, int]], ...]]:
    return {
        "equal_top_full_tail": ((1.0 / 3.0, (0, 0)), (1.0 / 3.0, (0, 4)), (1.0 / 3.0, (1, 4))),
        "tail_heavy": ((0.25, (0, 0)), (0.25, (0, 4)), (0.5, (1, 4))),
        "top_tail_only": ((0.5, (0, 0)), (0.5, (1, 4))),
        "conservative_tail": ((0.5, (0, 4)), (0.5, (1, 4))),
    }


def _k6_barycentric_trigger_features(
    state: tuple[int, ...],
    remaining_horizon: int,
) -> dict[str, object]:
    canonical_state = canon(state)
    ptype = packet_type(canonical_state)
    gaps = _packet_gaps(canonical_state)
    mean_score = sum(canonical_state) / len(canonical_state) if canonical_state else 0.0
    return {
        "state": canonical_state,
        "remaining_horizon": remaining_horizon,
        "packet_type": ptype,
        "packet_gaps": gaps,
        "packet_count": len(ptype),
        "max_gap": max(gaps, default=0),
        "num_gaps_eq_1": sum(1 for gap in gaps if gap == 1),
        "num_gaps_ge_2": sum(1 for gap in gaps if gap >= 2),
        "top_packet_size": ptype[0] if ptype else 0,
        "second_packet_size": ptype[1] if len(ptype) > 1 else 0,
        "bottom_packet_size": ptype[-1] if ptype else 0,
        "mean_score": mean_score,
        "top_gap": canonical_state[0] - mean_score if canonical_state else 0.0,
        "bottom_gap": mean_score - canonical_state[-1] if canonical_state else 0.0,
        "above_count": sum(1 for score in canonical_state if score > mean_score),
        "below_count": sum(1 for score in canonical_state if score < mean_score),
    }


def _k6_barycentric_trigger_sweep_specs() -> tuple[K6BarycentricTriggerSpec, ...]:
    specs: list[K6BarycentricTriggerSpec] = [
        K6BarycentricTriggerSpec(
            "top_singleton",
            "packet_type[0] == 1",
            lambda f: f["top_packet_size"] == 1,
        ),
        K6BarycentricTriggerSpec(
            "top_singleton_second_pair",
            "packet_type[0] == 1 and packet_type[1] == 2",
            lambda f: f["top_packet_size"] == 1 and f["second_packet_size"] == 2,
        ),
        K6BarycentricTriggerSpec(
            "top_singleton_fragmented_tail",
            "packet_type[0] == 1 and packet_count >= 4",
            lambda f: f["top_packet_size"] == 1 and f["packet_count"] >= 4,
        ),
        K6BarycentricTriggerSpec(
            "one_run_correction_shape",
            "packet_type[0] == 1 and packet_type[1] == 2 and packet_count >= 3",
            lambda f: f["top_packet_size"] == 1 and f["second_packet_size"] == 2 and f["packet_count"] >= 3,
        ),
        K6BarycentricTriggerSpec(
            "gap2_top_singleton",
            "packet_type[0] == 1 and max_gap >= 2",
            lambda f: f["top_packet_size"] == 1 and f["max_gap"] >= 2,
        ),
    ]
    for threshold in (0.5, 1.0, 1.5):
        specs.append(
            K6BarycentricTriggerSpec(
                f"barycenter_split_t{threshold:g}",
                f"above_count >= 1 and below_count >= 2 and top_gap,bottom_gap >= {threshold:g}",
                lambda f, threshold=threshold: (
                    f["above_count"] >= 1
                    and f["below_count"] >= 2
                    and f["top_gap"] >= threshold
                    and f["bottom_gap"] >= threshold
                ),
            )
        )
    for packet_threshold in (3, 4, 5):
        specs.append(
            K6BarycentricTriggerSpec(
                f"fragmented_barycenter_p{packet_threshold}",
                f"packet_count >= {packet_threshold} and above_count >= 1 and below_count >= 2",
                lambda f, packet_threshold=packet_threshold: (
                    f["packet_count"] >= packet_threshold and f["above_count"] >= 1 and f["below_count"] >= 2
                ),
            )
        )
    for horizon_threshold in (2, 3, 4, 5, 6, 8):
        specs.append(
            K6BarycentricTriggerSpec(
                f"late_top_singleton_h{horizon_threshold}",
                f"packet_type[0] == 1 and h <= {horizon_threshold}",
                lambda f, horizon_threshold=horizon_threshold: (
                    f["top_packet_size"] == 1 and f["remaining_horizon"] <= horizon_threshold
                ),
            )
        )
    for low, high in ((2, 6), (3, 8), (4, 10), (5, 12)):
        specs.append(
            K6BarycentricTriggerSpec(
                f"middle_top_singleton_h{low}_{high}",
                f"packet_type[0] == 1 and {low} <= h <= {high}",
                lambda f, low=low, high=high: (
                    f["top_packet_size"] == 1 and low <= f["remaining_horizon"] <= high
                ),
            )
        )
    for low, high in ((2, 8), (3, 8), (4, 10)):
        specs.append(
            K6BarycentricTriggerSpec(
                f"one_run_report_like_h{low}_{high}",
                (
                    "packet_type[0] == 1 and packet_type[1] == 2 and "
                    f"(max_gap >= 2 or packet_count >= 4) and {low} <= h <= {high}"
                ),
                lambda f, low=low, high=high: (
                    f["top_packet_size"] == 1
                    and f["second_packet_size"] == 2
                    and (f["max_gap"] >= 2 or f["packet_count"] >= 4)
                    and low <= f["remaining_horizon"] <= high
                ),
            )
        )
    return tuple(specs)


def _k6_barycentric_trigger_sweep_candidates() -> tuple[K6BarycentricTriggerSweepCandidate, ...]:
    candidates: list[K6BarycentricTriggerSweepCandidate] = []
    for spec in _k6_barycentric_trigger_sweep_specs():
        for mixture_name, weighted_intervals in _k6_barycentric_sweep_mixtures().items():
            candidates.append(
                K6BarycentricTriggerSweepCandidate(
                    name=f"{spec.name}__{mixture_name}",
                    trigger_name=spec.name,
                    trigger_description=spec.description,
                    mixture_name=mixture_name,
                    weighted_intervals=weighted_intervals,
                    predicate=spec.predicate,
                )
            )
    return tuple(candidates)


def _k6_barycentric_trigger_fires(
    candidate: K6BarycentricTriggerSweepCandidate,
    state: tuple[int, ...],
    remaining_horizon: int,
) -> bool:
    canonical_state = canon(state)
    if len(canonical_state) != 6:
        return False
    features = _k6_barycentric_trigger_features(canonical_state, remaining_horizon)
    return bool(candidate.predicate(features))


def make_k6_barycentric_trigger_sweep_policy(candidate: K6BarycentricTriggerSweepCandidate):
    def policy(
        state: tuple[int, ...],
        remaining_horizon: int,
    ) -> tuple[tuple[float, tuple[int, ...]], ...]:
        canonical_state = canon(state)
        if len(canonical_state) != 6:
            return _balanced_policy_from_one_run_interval(len(canonical_state), (0, max(0, len(canonical_state) - 2)))
        if _k6_barycentric_trigger_fires(candidate, canonical_state, remaining_horizon):
            return _mixed_one_run_interval_policy(6, candidate.weighted_intervals)
        return _balanced_policy_from_one_run_interval(6, (0, 4))

    return policy


def _centered_state_values(state: tuple[int, ...]) -> tuple[float, ...]:
    if not state:
        return ()
    mean_score = sum(state) / len(state)
    return tuple(score - mean_score for score in state)


def _phi_centered_max(state: tuple[int, ...]) -> float:
    if not state:
        return 0.0
    mean_score = sum(state) / len(state)
    return max(state) - mean_score


def _phi_centered_softmax(state: tuple[int, ...], tau: float) -> float:
    if tau <= 0.0:
        raise ValueError("tau must be positive")
    centered = _centered_state_values(state)
    if not centered:
        return 0.0
    max_centered = max(centered)
    return tau * (max_centered / tau + np.log(sum(np.exp((value - max_centered) / tau) for value in centered)))


def _softmax_centered_gradient(state: tuple[int, ...], tau: float) -> tuple[float, ...]:
    if tau <= 0.0:
        raise ValueError("tau must be positive")
    centered = _centered_state_values(state)
    if not centered:
        return ()
    max_centered = max(centered)
    weights = [float(np.exp((value - max_centered) / tau)) for value in centered]
    total = sum(weights)
    return tuple(weight / total for weight in weights)


def _k5_comb_support() -> tuple[tuple[float, tuple[int, ...]], ...]:
    return ((0.5, (1, 0, 1, 0, 1)), (0.5, (0, 1, 0, 1, 0)))


def _k5_chase_support() -> tuple[tuple[float, tuple[int, ...]], ...]:
    return ((0.5, (1, 0, 1, 0, 0)), (0.5, (0, 1, 0, 1, 1)))


def _bits_text(action: tuple[int, ...]) -> str:
    return "".join(str(bit) for bit in action)


def _fraction_text(value: Fraction) -> str:
    return str(value.numerator) if value.denominator == 1 else f"{value.numerator}/{value.denominator}"


def _balanced_action_matrix_column(action: tuple[int, ...]) -> tuple[Fraction, ...]:
    return (
        Fraction(1),
        Fraction(action[1] - action[0]),
        Fraction(action[2] - action[0]),
        Fraction(action[3] - action[0]),
        Fraction(action[4] - action[0]),
    )


def _solve_k5_balanced_fraction_linear_system(
    rows: tuple[tuple[Fraction, ...], ...],
    rhs: tuple[Fraction, ...],
    variable_count: int,
) -> tuple[Fraction, ...] | None:
    augmented = [list(row) + [rhs_value] for row, rhs_value in zip(rows, rhs, strict=True)]
    pivot_columns: list[int] = []
    pivot_row = 0
    for column in range(variable_count):
        selected = None
        for row_index in range(pivot_row, len(augmented)):
            if augmented[row_index][column] != 0:
                selected = row_index
                break
        if selected is None:
            continue
        augmented[pivot_row], augmented[selected] = augmented[selected], augmented[pivot_row]
        pivot_value = augmented[pivot_row][column]
        augmented[pivot_row] = [value / pivot_value for value in augmented[pivot_row]]
        for row_index in range(len(augmented)):
            if row_index == pivot_row:
                continue
            factor = augmented[row_index][column]
            if factor == 0:
                continue
            augmented[row_index] = [
                value - factor * pivot
                for value, pivot in zip(augmented[row_index], augmented[pivot_row], strict=True)
            ]
        pivot_columns.append(column)
        pivot_row += 1
        if pivot_row == len(augmented):
            break

    for row in augmented:
        if all(value == 0 for value in row[:variable_count]) and row[-1] != 0:
            return None
    if len(pivot_columns) != variable_count:
        return None
    solution = [Fraction(0) for _ in range(variable_count)]
    for row_index, column in enumerate(pivot_columns):
        solution[column] = augmented[row_index][-1]
    return tuple(solution)


def _normalize_fraction_support(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> tuple[tuple[Fraction, tuple[int, ...]], ...]:
    return tuple(sorted(support, key=lambda item: (_bits_text(item[1]), item[0])))


def _support_to_full_fraction_vector(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
    gain_vectors: tuple[tuple[int, ...], ...],
) -> tuple[Fraction, ...]:
    weights = {action: probability for probability, action in support}
    return tuple(weights.get(action, Fraction(0)) for action in gain_vectors)


def _transform_balanced_support(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
    permutation: tuple[int, ...],
    do_complement: bool,
) -> tuple[tuple[Fraction, tuple[int, ...]], ...]:
    transformed = []
    for probability, action in support:
        moved = tuple(action[index] for index in permutation)
        if do_complement:
            moved = tuple(1 - bit for bit in moved)
        transformed.append((probability, moved))
    combined: dict[tuple[int, ...], Fraction] = defaultdict(Fraction)
    for probability, action in transformed:
        combined[action] += probability
    return _normalize_fraction_support(tuple((probability, action) for action, probability in combined.items()))


def _balanced_action_canonical_key(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> tuple[tuple[str, int, int], ...]:
    candidates = []
    for permutation in permutations(range(5)):
        for do_complement in (False, True):
            transformed = _transform_balanced_support(support, permutation, do_complement)
            candidates.append(
                tuple(
                    (_bits_text(action), probability.numerator, probability.denominator)
                    for probability, action in transformed
                )
            )
    return min(candidates)


def _balanced_action_marginal(support: tuple[tuple[Fraction, tuple[int, ...]], ...]) -> Fraction:
    if not support:
        return Fraction(0)
    return sum(probability * action[0] for probability, action in support)


def _balanced_action_is_balanced(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> bool:
    if sum(probability for probability, _ in support) != 1:
        return False
    marginals = [
        sum(probability * action[index] for probability, action in support)
        for index in range(5)
    ]
    return all(value == marginals[0] for value in marginals)


@lru_cache(maxsize=1)
def k5_balanced_action_vertices() -> tuple[BalancedActionVertex, ...]:
    gain_vectors = tuple(product((0, 1), repeat=5))
    rhs = (Fraction(1), Fraction(0), Fraction(0), Fraction(0), Fraction(0))
    vertices_by_full_vector: dict[tuple[Fraction, ...], BalancedActionVertex] = {}
    for support_size in range(1, 6):
        for support_actions in combinations(gain_vectors, support_size):
            columns = tuple(_balanced_action_matrix_column(action) for action in support_actions)
            rows = tuple(tuple(column[row_index] for column in columns) for row_index in range(5))
            solution = _solve_k5_balanced_fraction_linear_system(rows, rhs, support_size)
            if solution is None:
                continue
            if any(weight < 0 for weight in solution):
                continue
            support = _normalize_fraction_support(
                tuple(
                    (weight, action)
                    for weight, action in zip(solution, support_actions, strict=True)
                    if weight > 0
                )
            )
            if len(support) != support_size or not _balanced_action_is_balanced(support):
                continue
            full_vector = _support_to_full_fraction_vector(support, gain_vectors)
            vertices_by_full_vector.setdefault(
                full_vector,
                BalancedActionVertex(
                    support=support,
                    marginal=_balanced_action_marginal(support),
                    canonical_key=_balanced_action_canonical_key(support),
                ),
            )
    return tuple(sorted(vertices_by_full_vector.values(), key=lambda vertex: vertex.canonical_key))


def _k5_balanced_vertex_for_support(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> BalancedActionVertex | None:
    normalized = _normalize_fraction_support(support)
    full_vector = _support_to_full_fraction_vector(normalized, tuple(product((0, 1), repeat=5)))
    for vertex in k5_balanced_action_vertices():
        if _support_to_full_fraction_vector(vertex.support, tuple(product((0, 1), repeat=5))) == full_vector:
            return vertex
    return None


def _k5_chase_balanced_vertex() -> BalancedActionVertex | None:
    return _k5_balanced_vertex_for_support(
        ((Fraction(1, 2), (1, 0, 1, 0, 0)), (Fraction(1, 2), (0, 1, 0, 1, 1)))
    )


def _k5_comb_balanced_vertex() -> BalancedActionVertex | None:
    return _k5_balanced_vertex_for_support(
        ((Fraction(1, 2), (1, 0, 1, 0, 1)), (Fraction(1, 2), (0, 1, 0, 1, 0)))
    )


def _canonical_packet_state(packet_shape: tuple[int, ...]) -> tuple[int, ...]:
    values: list[int] = []
    height = len(packet_shape) - 1
    for packet_size in packet_shape:
        values.extend([height] * packet_size)
        height -= 1
    return tuple(values)


def _packet_action_count_distribution(
    vertex: BalancedActionVertex,
    packet_shape: tuple[int, ...],
) -> tuple[tuple[tuple[int, ...], Fraction], ...]:
    state = _canonical_packet_state(packet_shape)
    groups = packets(state)
    totals: dict[tuple[int, ...], Fraction] = defaultdict(Fraction)
    for probability, action in vertex.support:
        counts = tuple(sum(action[index] for index in group) for group in groups)
        totals[counts] += probability
    return tuple(sorted(totals.items(), key=lambda item: item[0]))


def _format_balanced_support(support: tuple[tuple[Fraction, tuple[int, ...]], ...]) -> str:
    return " + ".join(f"{_fraction_text(probability)}*{_bits_text(action)}" for probability, action in support)


def _format_packet_count_distribution(distribution: tuple[tuple[tuple[int, ...], Fraction], ...]) -> str:
    return ", ".join(f"{counts}:{_fraction_text(probability)}" for counts, probability in distribution)


@lru_cache(maxsize=None)
def _rank_chase_future_centered_value_cached(state: tuple[int, ...], horizon: int) -> float:
    return _rank_chase_future_centered_value(state, horizon)


def _balanced_chase_q_value(
    state: tuple[int, ...],
    horizon: int,
    vertex: BalancedActionVertex,
) -> float:
    return _balanced_chase_q_value_for_support(state, horizon, vertex.support)


def _balanced_chase_q_value_for_support(
    state: tuple[int, ...],
    horizon: int,
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> float:
    if horizon <= 0:
        return _rank_chase_future_centered_value_cached(canon(state), 0)
    child_horizon = horizon - 1
    total = 0.0
    canonical_state = canon(state)
    for probability, action in support:
        successor = canon(tuple(canonical_state[index] + action[index] for index in range(5)))
        total += float(probability) * _rank_chase_future_centered_value_cached(successor, child_horizon)
    return total


def _balanced_support_common_marginal(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> Fraction:
    if not support:
        return Fraction(0)
    marginals = tuple(
        sum(probability * action[index] for probability, action in support)
        for index in range(5)
    )
    if any(marginal != marginals[0] for marginal in marginals):
        raise ValueError(f"support is not balanced: {support}")
    return marginals[0]


def _balanced_chase_offset_child_value_for_support(
    state: tuple[int, ...],
    horizon: int,
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> float:
    if horizon <= 0:
        return _rank_chase_future_centered_value_cached(canon(state), 0)
    child_horizon = horizon - 1
    total = 0.0
    canonical_state = canon(state)
    for probability, action in support:
        raw_successor = tuple(canonical_state[index] + action[index] for index in range(5))
        min_offset = min(raw_successor, default=0)
        successor = canon(raw_successor)
        total += float(probability) * (
            float(min_offset) + _rank_chase_future_centered_value_cached(successor, child_horizon)
        )
    return total


def _balanced_chase_old_fixed_q_for_support(
    state: tuple[int, ...],
    horizon: int,
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> float:
    return _balanced_chase_offset_child_value_for_support(state, horizon, support) - 0.5


def _balanced_chase_centered_q_for_support(
    state: tuple[int, ...],
    horizon: int,
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> float:
    marginal = _balanced_support_common_marginal(support)
    return _balanced_chase_offset_child_value_for_support(state, horizon, support) - float(marginal)


def _balanced_chase_old_fixed_q(
    state: tuple[int, ...],
    horizon: int,
    vertex: BalancedActionVertex,
) -> float:
    return _balanced_chase_old_fixed_q_for_support(state, horizon, vertex.support)


def _balanced_chase_centered_q(
    state: tuple[int, ...],
    horizon: int,
    vertex: BalancedActionVertex,
) -> float:
    return _balanced_chase_centered_q_for_support(state, horizon, vertex.support)


def _k5_chase_orbit_vertices() -> tuple[BalancedActionVertex, ...]:
    vertices: list[BalancedActionVertex] = []
    seen: set[tuple[tuple[str, int, int], ...]] = set()
    for action in product((0, 1), repeat=5):
        if sum(action) not in (2, 3):
            continue
        representative = min(action, complement(action))
        support = _normalize_fraction_support(
            (
                (Fraction(1, 2), representative),
                (Fraction(1, 2), complement(representative)),
            )
        )
        key = tuple(
            (_bits_text(support_action), probability.numerator, probability.denominator)
            for probability, support_action in support
        )
        if key in seen:
            continue
        seen.add(key)
        vertex = _k5_balanced_vertex_for_support(support)
        if vertex is None:
            raise RuntimeError(f"orbit support was not enumerated as a balanced vertex: {support}")
        vertices.append(vertex)
    return tuple(sorted(vertices, key=lambda vertex: _format_balanced_support(vertex.support)))


def _k5_stabilizer_permutations(state: tuple[int, ...]) -> tuple[tuple[int, ...], ...]:
    groups = packets(state)
    group_permutations = tuple(tuple(permutations(group)) for group in groups)
    result: list[tuple[int, ...]] = []
    for choices in product(*group_permutations):
        permutation = list(range(len(state)))
        for group, permuted_group in zip(groups, choices, strict=True):
            for source, target in zip(group, permuted_group, strict=True):
                permutation[source] = target
        result.append(tuple(permutation))
    return tuple(result)


def _k5_symmetrized_chase_support(state: tuple[int, ...]) -> tuple[tuple[Fraction, tuple[int, ...]], ...]:
    stabilizer = _k5_stabilizer_permutations(canon(state))
    totals: dict[tuple[int, ...], Fraction] = defaultdict(Fraction)
    base_support = ((Fraction(1, 2), (1, 0, 1, 0, 0)), (Fraction(1, 2), (0, 1, 0, 1, 1)))
    for permutation in stabilizer:
        for probability, action in base_support:
            transformed = tuple(action[index] for index in permutation)
            totals[transformed] += probability / len(stabilizer)
    return _normalize_fraction_support(tuple((probability, action) for action, probability in totals.items()))


def _fraction_support_is_balanced(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> bool:
    return _balanced_action_is_balanced(support)


def _support_packet_count_distribution(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
    packet_shape: tuple[int, ...],
) -> tuple[tuple[tuple[int, ...], Fraction], ...]:
    state = _canonical_packet_state(packet_shape)
    groups = packets(state)
    totals: dict[tuple[int, ...], Fraction] = defaultdict(Fraction)
    for probability, action in support:
        counts = tuple(sum(action[index] for index in group) for group in groups)
        totals[counts] += probability
    return tuple(sorted(totals.items(), key=lambda item: item[0]))


def _k5_balanced_chase_greedy_defect_states(max_used: int) -> tuple[tuple[int, ...], ...]:
    states = {state for used in range(max_used + 1) for state in all_states(5, used)}
    return tuple(sorted(states, key=lambda state: (max(state, default=0), state)))


def k5_balanced_chase_greedy_defect_rows(
    h_values: tuple[int, ...] = (10, 20, 50, 100),
    max_used: int = 8,
) -> tuple[BalancedChaseGreedyDefectRow, ...]:
    vertices = k5_balanced_action_vertices()
    chase_vertex = _k5_chase_balanced_vertex()
    if chase_vertex is None:
        raise RuntimeError("Chase is not present in the balanced vertex enumeration")
    rows: list[BalancedChaseGreedyDefectRow] = []
    for horizon in h_values:
        for state in _k5_balanced_chase_greedy_defect_states(max_used):
            chase_q = _balanced_chase_q_value(state, horizon, chase_vertex)
            scored = tuple((_balanced_chase_q_value(state, horizon, vertex), vertex) for vertex in vertices)
            best_q, best_vertex = max(
                scored,
                key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
            )
            rows.append(
                BalancedChaseGreedyDefectRow(
                    horizon=horizon,
                    state=state,
                    packet_type=packet_type(state),
                    packet_gaps=_gap_vector(state),
                    chase_q=chase_q,
                    best_q=best_q,
                    epsilon=max(0.0, best_q - chase_q),
                    best_vertex=best_vertex,
                )
            )
    return tuple(rows)


def _balanced_vertex_class_index(vertex: BalancedActionVertex) -> int:
    for index, (key, _) in enumerate(_k5_balanced_action_symmetry_classes(), start=1):
        if key == vertex.canonical_key:
            return index
    return -1


def _balanced_vertex_label(vertex: BalancedActionVertex) -> str:
    labels = []
    chase_vertex = _k5_chase_balanced_vertex()
    comb_vertex = _k5_comb_balanced_vertex()
    if chase_vertex is not None and vertex.canonical_key == chase_vertex.canonical_key:
        labels.append("Chase/Comb orbit")
    elif comb_vertex is not None and vertex.canonical_key == comb_vertex.canonical_key:
        labels.append("Comb orbit")
    if _is_complement_pair_vertex(vertex):
        labels.append("complement-pair")
    class_index = _balanced_vertex_class_index(vertex)
    prefix = f"class {class_index}" if class_index > 0 else "class ?"
    suffix = f" ({'; '.join(labels)})" if labels else ""
    return prefix + suffix


def print_k5_balanced_chase_greedy_defect_report(
    h_values: tuple[int, ...] = (10, 20, 50, 100),
    max_used: int = 8,
    n: int = 20,
) -> None:
    rows = k5_balanced_chase_greedy_defect_rows(h_values=h_values, max_used=max_used)
    print("balanced Chase greedy defect")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"balanced vertices: {len(k5_balanced_action_vertices())}")
    print(f"symmetry classes: {len(_k5_balanced_action_symmetry_classes())}")
    print()

    print("1. max defect by horizon")
    print("h max_eps h_max_eps state packet gaps chase_q best_q best_competing_balanced_action")
    for horizon in h_values:
        group = [row for row in rows if row.horizon == horizon]
        if not group:
            continue
        worst = max(group, key=lambda row: (row.epsilon, row.state))
        print(
            f"{horizon:4d}"
            f" {worst.epsilon:.12g}"
            f" {horizon * worst.epsilon:.12g}"
            f" {worst.state}"
            f" {worst.packet_type}"
            f" {worst.packet_gaps}"
            f" {worst.chase_q:.12f}"
            f" {worst.best_q:.12f}"
            f" {_balanced_vertex_label(worst.best_vertex)}"
        )
        print(f"     support: {_format_balanced_support(worst.best_vertex.support)}")

    print()
    print("2. worst by packet")
    for horizon in h_values:
        group = [row for row in rows if row.horizon == horizon]
        by_packet: dict[tuple[int, ...], BalancedChaseGreedyDefectRow] = {}
        for row in group:
            current = by_packet.get(row.packet_type)
            if current is None or row.epsilon > current.epsilon:
                by_packet[row.packet_type] = row
        print(f"  h={horizon}")
        for packet, row in sorted(by_packet.items(), key=lambda item: (-item[1].epsilon, item[0]))[:n]:
            print(
                f"    packet={packet}"
                f" eps={row.epsilon:.12g}"
                f" h_eps={horizon * row.epsilon:.12g}"
                f" state={row.state}"
                f" gaps={row.packet_gaps}"
                f" competitor={_balanced_vertex_label(row.best_vertex)}"
            )

    print()
    print("3. top states")
    print("h eps h_eps state packet gaps chase_q best_q competitor support")
    for row in sorted(rows, key=lambda item: (item.epsilon, item.horizon, item.state), reverse=True)[:n]:
        print(
            f"{row.horizon:4d}"
            f" {row.epsilon:.12g}"
            f" {row.horizon * row.epsilon:.12g}"
            f" {row.state}"
            f" {row.packet_type}"
            f" {row.packet_gaps}"
            f" {row.chase_q:.12f}"
            f" {row.best_q:.12f}"
            f" {_balanced_vertex_label(row.best_vertex)}"
            f" {_format_balanced_support(row.best_vertex.support)}"
        )

    print()
    print("4. packet-LP comparison")
    print("  This report does not invoke the packet-LP machinery; compare the worst packet/state lines above to alpha_h reports.")
    print()
    print("5. candidate theorem")
    print("  If eps_h(x) <= C/h uniformly over balanced atomic actions, then Chase is near-greedy in the balanced MDP.")
    print("  Telescoping the one-step defects would give an O(C log T) additive gap among balanced adversaries.")


def k5_balanced_chase_orbit_defect_rows(
    h_values: tuple[int, ...] = (10, 20, 50, 100),
    max_used: int = 8,
) -> tuple[BalancedChaseOrbitDefectRow, ...]:
    balanced_vertices = k5_balanced_action_vertices()
    orbit_vertices = _k5_chase_orbit_vertices()
    fixed_chase = _k5_chase_balanced_vertex()
    if fixed_chase is None:
        raise RuntimeError("Chase is not present in the balanced vertex enumeration")
    rows: list[BalancedChaseOrbitDefectRow] = []
    for horizon in h_values:
        for state in _k5_balanced_chase_greedy_defect_states(max_used):
            balanced_scores = tuple((_balanced_chase_q_value(state, horizon, vertex), vertex) for vertex in balanced_vertices)
            best_balanced_q, best_balanced_vertex = max(
                balanced_scores,
                key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
            )
            orbit_scores = tuple((_balanced_chase_q_value(state, horizon, vertex), vertex) for vertex in orbit_vertices)
            orbit_q, best_orbit_vertex = max(
                orbit_scores,
                key=lambda item: (item[0], _format_balanced_support(item[1].support)),
            )
            sym_support = _k5_symmetrized_chase_support(state)
            fixed_chase_q = _balanced_chase_q_value(state, horizon, fixed_chase)
            sym_chase_q = _balanced_chase_q_value_for_support(state, horizon, sym_support)
            rows.append(
                BalancedChaseOrbitDefectRow(
                    horizon=horizon,
                    state=state,
                    packet_type=packet_type(state),
                    packet_gaps=_gap_vector(state),
                    best_balanced_q=best_balanced_q,
                    fixed_chase_q=fixed_chase_q,
                    orbit_q=orbit_q,
                    sym_chase_q=sym_chase_q,
                    eps_raw=max(0.0, best_balanced_q - fixed_chase_q),
                    eps_orbit=max(0.0, best_balanced_q - orbit_q),
                    eps_sym=max(0.0, best_balanced_q - sym_chase_q),
                    best_balanced_vertex=best_balanced_vertex,
                    best_orbit_vertex=best_orbit_vertex,
                    sym_chase_support=sym_support,
                )
            )
    return tuple(rows)


def _format_orbit_relation(vertex: BalancedActionVertex) -> str:
    support_text = _format_balanced_support(vertex.support)
    if support_text == _format_balanced_support(((Fraction(1, 2), (1, 0, 1, 0, 0)), (Fraction(1, 2), (0, 1, 0, 1, 1)))):
        return "fixed Chase"
    if support_text == _format_balanced_support(((Fraction(1, 2), (1, 0, 1, 0, 1)), (Fraction(1, 2), (0, 1, 0, 1, 0)))):
        return "Comb"
    if support_text == _format_balanced_support(((Fraction(1, 2), (0, 0, 1, 0, 1)), (Fraction(1, 2), (1, 1, 0, 1, 0)))):
        return "previous 00101/11010 competitor"
    return "Chase/Comb orbit representative"


def print_k5_balanced_chase_orbit_defect_report(
    h_values: tuple[int, ...] = (10, 20, 50, 100),
    max_used: int = 8,
    n: int = 20,
) -> None:
    rows = k5_balanced_chase_orbit_defect_rows(h_values=h_values, max_used=max_used)
    orbit_vertices = _k5_chase_orbit_vertices()
    print("balanced Chase orbit defect")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"balanced vertices: {len(k5_balanced_action_vertices())}")
    print(f"Chase orbit complement-pair actions: {len(orbit_vertices)}")
    print()

    print("1. max defects by horizon")
    print("h raw h_raw orbit h_orbit sym h_sym state packet gaps best_orbit")
    for horizon in h_values:
        group = [row for row in rows if row.horizon == horizon]
        if not group:
            continue
        raw_worst = max(group, key=lambda row: (row.eps_raw, row.state))
        orbit_worst = max(group, key=lambda row: (row.eps_orbit, row.state))
        sym_worst = max(group, key=lambda row: (row.eps_sym, row.state))
        print(
            f"{horizon:4d}"
            f" {raw_worst.eps_raw:.12g} {horizon * raw_worst.eps_raw:.12g}"
            f" {orbit_worst.eps_orbit:.12g} {horizon * orbit_worst.eps_orbit:.12g}"
            f" {sym_worst.eps_sym:.12g} {horizon * sym_worst.eps_sym:.12g}"
            f" {orbit_worst.state}"
            f" {orbit_worst.packet_type}"
            f" {orbit_worst.packet_gaps}"
            f" {_format_orbit_relation(orbit_worst.best_orbit_vertex)}"
        )
        print(f"     best orbit support: {_format_balanced_support(orbit_worst.best_orbit_vertex.support)}")
        print(f"     best balanced support: {_format_balanced_support(orbit_worst.best_balanced_vertex.support)}")

    print()
    print("2. max defects by packet")
    for horizon in h_values:
        group = [row for row in rows if row.horizon == horizon]
        by_packet: dict[tuple[int, ...], list[BalancedChaseOrbitDefectRow]] = defaultdict(list)
        for row in group:
            by_packet[row.packet_type].append(row)
        print(f"  h={horizon}")
        summaries = []
        for packet, packet_rows in by_packet.items():
            raw = max(packet_rows, key=lambda row: row.eps_raw)
            orbit = max(packet_rows, key=lambda row: row.eps_orbit)
            sym = max(packet_rows, key=lambda row: row.eps_sym)
            summaries.append((packet, raw, orbit, sym))
        for packet, raw, orbit, sym in sorted(summaries, key=lambda item: (-item[2].eps_orbit, item[0]))[:n]:
            print(
                f"    packet={packet}"
                f" raw={raw.eps_raw:.12g}"
                f" orbit={orbit.eps_orbit:.12g}"
                f" h_orbit={horizon * orbit.eps_orbit:.12g}"
                f" sym={sym.eps_sym:.12g}"
                f" orbit_state={orbit.state}"
                f" orbit_gaps={orbit.packet_gaps}"
                f" best_orbit={_format_orbit_relation(orbit.best_orbit_vertex)}"
            )

    print()
    print("3. best orbit representatives")
    print("h eps_orbit state packet gaps orbit_q best_q support packet_counts_122")
    for row in sorted(rows, key=lambda item: (item.eps_orbit, item.horizon, item.state), reverse=True)[:n]:
        print(
            f"{row.horizon:4d}"
            f" {row.eps_orbit:.12g}"
            f" {row.state}"
            f" {row.packet_type}"
            f" {row.packet_gaps}"
            f" {row.orbit_q:.12f}"
            f" {row.best_balanced_q:.12f}"
            f" {_format_balanced_support(row.best_orbit_vertex.support)}"
            f" {_format_packet_count_distribution(_packet_action_count_distribution(row.best_orbit_vertex, (1, 2, 2)))}"
        )

    print()
    print("4. symmetrized Chase samples")
    seen_packets: set[tuple[int, ...]] = set()
    for row in sorted(rows, key=lambda item: (item.packet_type, item.state)):
        if row.packet_type in seen_packets:
            continue
        seen_packets.add(row.packet_type)
        print(
            f"  packet={row.packet_type}"
            f" state={row.state}"
            f" balanced={_fraction_support_is_balanced(row.sym_chase_support)}"
            f" support={_format_balanced_support(row.sym_chase_support)}"
        )
        if len(seen_packets) >= min(n, 12):
            break

    print()
    print("5. packet-LP / clean-regime diagnostic")
    print("  Check whether the orbit column, rather than raw or sym, concentrates on packet (1,2,2) and whether h*orbit remains bounded.")


def k5_balanced_centered_orbit_defect_rows(
    h_values: tuple[int, ...] = (10, 20, 50, 100),
    max_used: int = 8,
) -> tuple[BalancedCenteredOrbitDefectRow, ...]:
    balanced_vertices = k5_balanced_action_vertices()
    c_half_vertices = tuple(vertex for vertex in balanced_vertices if vertex.marginal == Fraction(1, 2))
    orbit_vertices = _k5_chase_orbit_vertices()
    fixed_chase = _k5_chase_balanced_vertex()
    if fixed_chase is None:
        raise RuntimeError("Chase is not present in the balanced vertex enumeration")
    rows: list[BalancedCenteredOrbitDefectRow] = []
    for horizon in h_values:
        for state in _k5_balanced_chase_greedy_defect_states(max_used):
            canonical_raw_scores = tuple((_balanced_chase_q_value(state, horizon, vertex), vertex) for vertex in balanced_vertices)
            canonical_raw_best_q, _ = max(
                canonical_raw_scores,
                key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
            )
            fixed_chase_canonical_raw_q = _balanced_chase_q_value(state, horizon, fixed_chase)

            old_fixed_scores = tuple((_balanced_chase_old_fixed_q(state, horizon, vertex), vertex) for vertex in balanced_vertices)
            best_old_fixed_q, best_old_fixed_vertex = max(
                old_fixed_scores,
                key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
            )

            centered_scores = tuple((_balanced_chase_centered_q(state, horizon, vertex), vertex) for vertex in balanced_vertices)
            best_centered_q, best_centered_vertex = max(
                centered_scores,
                key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
            )

            centered_c_half_scores = tuple(
                (_balanced_chase_centered_q(state, horizon, vertex), vertex)
                for vertex in c_half_vertices
            )
            best_centered_c_half_q, best_centered_c_half_vertex = max(
                centered_c_half_scores,
                key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
            )

            orbit_old_fixed_scores = tuple((_balanced_chase_old_fixed_q(state, horizon, vertex), vertex) for vertex in orbit_vertices)
            orbit_old_fixed_q, best_orbit_vertex = max(
                orbit_old_fixed_scores,
                key=lambda item: (item[0], _format_balanced_support(item[1].support)),
            )
            orbit_centered_q = _balanced_chase_centered_q(state, horizon, best_orbit_vertex)

            sym_support = _k5_symmetrized_chase_support(state)
            sym_old_fixed_q = _balanced_chase_old_fixed_q_for_support(state, horizon, sym_support)
            sym_centered_q = _balanced_chase_centered_q_for_support(state, horizon, sym_support)
            fixed_chase_old_fixed_q = _balanced_chase_old_fixed_q(state, horizon, fixed_chase)
            fixed_chase_centered_q = _balanced_chase_centered_q(state, horizon, fixed_chase)

            rows.append(
                BalancedCenteredOrbitDefectRow(
                    horizon=horizon,
                    state=state,
                    packet_type=packet_type(state),
                    packet_gaps=_gap_vector(state),
                    canonical_raw_eps=max(0.0, canonical_raw_best_q - fixed_chase_canonical_raw_q),
                    old_fixed_eps_raw=max(0.0, best_old_fixed_q - fixed_chase_old_fixed_q),
                    old_fixed_eps_orbit=max(0.0, best_old_fixed_q - orbit_old_fixed_q),
                    old_fixed_eps_sym=max(0.0, best_old_fixed_q - sym_old_fixed_q),
                    centered_eps_raw=max(0.0, best_centered_q - fixed_chase_centered_q),
                    centered_eps_orbit=max(0.0, best_centered_q - orbit_centered_q),
                    centered_eps_sym=max(0.0, best_centered_q - sym_centered_q),
                    centered_eps_orbit_c_half=max(0.0, best_centered_c_half_q - orbit_centered_q),
                    best_old_fixed_vertex=best_old_fixed_vertex,
                    best_centered_vertex=best_centered_vertex,
                    best_centered_c_half_vertex=best_centered_c_half_vertex,
                    best_orbit_vertex=best_orbit_vertex,
                    best_old_fixed_q=best_old_fixed_q,
                    best_centered_q=best_centered_q,
                    best_centered_c_half_q=best_centered_c_half_q,
                    orbit_old_fixed_q=orbit_old_fixed_q,
                    orbit_centered_q=orbit_centered_q,
                    sym_old_fixed_q=sym_old_fixed_q,
                    sym_centered_q=sym_centered_q,
                )
            )
    return tuple(rows)


def print_k5_balanced_centered_orbit_defect_report(
    h_values: tuple[int, ...] = (10, 20, 50, 100),
    max_used: int = 8,
    n: int = 20,
) -> None:
    rows = k5_balanced_centered_orbit_defect_rows(h_values=h_values, max_used=max_used)
    print("balanced centered Chase orbit defect")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"balanced vertices: {len(k5_balanced_action_vertices())}")
    print(f"c=1/2 balanced vertices: {sum(1 for vertex in k5_balanced_action_vertices() if vertex.marginal == Fraction(1, 2))}")
    print(f"Chase orbit complement-pair actions: {len(_k5_chase_orbit_vertices())}")
    print()

    print("1. max defects by horizon")
    print("h canonical_raw old_orbit h_old_orbit centered_orbit h_centered_orbit centered_c_half h_centered_c_half state packet gaps")
    for horizon in h_values:
        group = [row for row in rows if row.horizon == horizon]
        if not group:
            continue
        canonical_raw = max(group, key=lambda row: (row.canonical_raw_eps, row.state))
        old_orbit = max(group, key=lambda row: (row.old_fixed_eps_orbit, row.state))
        centered_orbit = max(group, key=lambda row: (row.centered_eps_orbit, row.state))
        centered_c_half = max(group, key=lambda row: (row.centered_eps_orbit_c_half, row.state))
        print(
            f"{horizon:4d}"
            f" {canonical_raw.canonical_raw_eps:.12g}"
            f" {old_orbit.old_fixed_eps_orbit:.12g} {horizon * old_orbit.old_fixed_eps_orbit:.12g}"
            f" {centered_orbit.centered_eps_orbit:.12g} {horizon * centered_orbit.centered_eps_orbit:.12g}"
            f" {centered_c_half.centered_eps_orbit_c_half:.12g} {horizon * centered_c_half.centered_eps_orbit_c_half:.12g}"
            f" {centered_orbit.state}"
            f" {centered_orbit.packet_type}"
            f" {centered_orbit.packet_gaps}"
        )
        print(
            f"     centered best support: {_format_balanced_support(centered_orbit.best_centered_vertex.support)}"
            f" c={_fraction_text(centered_orbit.best_centered_vertex.marginal)}"
        )
        print(
            f"     orbit support: {_format_balanced_support(centered_orbit.best_orbit_vertex.support)}"
            f" c={_fraction_text(centered_orbit.best_orbit_vertex.marginal)}"
        )

    print()
    print("2. packet (1,4) audit")
    print("h state old_orbit centered_orbit best_old_c best_centered_c orbit_c old_best_support centered_best_support")
    for horizon in h_values:
        group = [row for row in rows if row.horizon == horizon and row.packet_type == (1, 4)]
        if not group:
            continue
        old_worst = max(group, key=lambda row: row.old_fixed_eps_orbit)
        centered_worst = max(group, key=lambda row: row.centered_eps_orbit)
        print(
            f"{horizon:4d}"
            f" {old_worst.state}"
            f" {old_worst.old_fixed_eps_orbit:.12g}"
            f" {centered_worst.centered_eps_orbit:.12g}"
            f" {_fraction_text(old_worst.best_old_fixed_vertex.marginal)}"
            f" {_fraction_text(centered_worst.best_centered_vertex.marginal)}"
            f" {_fraction_text(centered_worst.best_orbit_vertex.marginal)}"
            f" {_format_balanced_support(old_worst.best_old_fixed_vertex.support)}"
            f" | {_format_balanced_support(centered_worst.best_centered_vertex.support)}"
        )

    print()
    print("3. centered orbit defect by packet")
    for horizon in h_values:
        group = [row for row in rows if row.horizon == horizon]
        by_packet: dict[tuple[int, ...], list[BalancedCenteredOrbitDefectRow]] = defaultdict(list)
        for row in group:
            by_packet[row.packet_type].append(row)
        print(f"  h={horizon}")
        packet_summaries = []
        for packet, packet_rows in by_packet.items():
            centered = max(packet_rows, key=lambda row: row.centered_eps_orbit)
            old = max(packet_rows, key=lambda row: row.old_fixed_eps_orbit)
            c_half = max(packet_rows, key=lambda row: row.centered_eps_orbit_c_half)
            packet_summaries.append((packet, old, centered, c_half))
        for packet, old, centered, c_half in sorted(packet_summaries, key=lambda item: (-item[2].centered_eps_orbit, item[0]))[:n]:
            print(
                f"    packet={packet}"
                f" old_orbit={old.old_fixed_eps_orbit:.12g}"
                f" centered_orbit={centered.centered_eps_orbit:.12g}"
                f" h_centered={horizon * centered.centered_eps_orbit:.12g}"
                f" centered_c_half={c_half.centered_eps_orbit_c_half:.12g}"
                f" state={centered.state}"
                f" gaps={centered.packet_gaps}"
                f" best_c={_fraction_text(centered.best_centered_vertex.marginal)}"
                f" best={_balanced_vertex_label(centered.best_centered_vertex)}"
            )

    print()
    print("4. baseline correction samples")
    print("h state support c old_fixed_q centered_q old_minus_centered expected_c_minus_half")
    sample_rows = sorted(rows, key=lambda row: (-row.old_fixed_eps_orbit, row.horizon, row.state))[:n]
    for row in sample_rows:
        support = row.best_old_fixed_vertex.support
        old_q = _balanced_chase_old_fixed_q_for_support(row.state, row.horizon, support)
        centered_q = _balanced_chase_centered_q_for_support(row.state, row.horizon, support)
        correction = float(_balanced_support_common_marginal(support) - Fraction(1, 2))
        print(
            f"{row.horizon:4d}"
            f" {row.state}"
            f" {_format_balanced_support(support)}"
            f" {_fraction_text(_balanced_support_common_marginal(support))}"
            f" {old_q:.12f}"
            f" {centered_q:.12f}"
            f" {old_q - centered_q:.12f}"
            f" {correction:.12f}"
        )

    print()
    print("5. all-zero / all-one centered check")
    if rows:
        row = rows[0]
        zero_support = ((Fraction(1), (0, 0, 0, 0, 0)),)
        one_support = ((Fraction(1), (1, 1, 1, 1, 1)),)
        print(
            f"  state={row.state} h={row.horizon}"
            f" zero_centered={_balanced_chase_centered_q_for_support(row.state, row.horizon, zero_support):.12f}"
            f" one_centered={_balanced_chase_centered_q_for_support(row.state, row.horizon, one_support):.12f}"
        )

    print()
    print("6. clean-regime diagnostic")
    print("  If centered_orbit is now small outside packet (1,2,2), compare its top rows to the packet-LP heat-kernel obstruction.")


def k5_balanced_varying_c_obstruction_rows(
    h_values: tuple[int, ...] = (10, 20, 50, 100),
    max_used: int = 8,
) -> tuple[BalancedVaryingCObstructionRow, ...]:
    centered_rows = k5_balanced_centered_orbit_defect_rows(h_values=h_values, max_used=max_used)
    rows: list[BalancedVaryingCObstructionRow] = []
    for row in centered_rows:
        rows.append(
            BalancedVaryingCObstructionRow(
                horizon=row.horizon,
                state=row.state,
                packet_type=row.packet_type,
                packet_gaps=row.packet_gaps,
                eps_full=row.centered_eps_orbit,
                eps_c_half=row.centered_eps_orbit_c_half,
                best_c=row.best_centered_vertex.marginal,
                best_class=_balanced_vertex_class_index(row.best_centered_vertex),
                best_support=row.best_centered_vertex.support,
                best_q=row.best_centered_q,
                orbit_q=row.orbit_centered_q,
                best_orbit_support=row.best_orbit_vertex.support,
            )
        )
    return tuple(rows)


def _boundary_distance_label(state: tuple[int, ...]) -> str:
    ptype = packet_type(state)
    if state == (0, 0, 0, 0, 0):
        return "flat"
    if ptype == (1, 4):
        return f"leader_gap_{state[0]}"
    if ptype and ptype[-1] >= 3:
        return "large_bottom_packet"
    if ptype and ptype[0] >= 3:
        return "large_top_packet"
    if len(ptype) == len(state):
        return "strict"
    return "mixed_boundary"


def _transition_distribution_for_support(
    state: tuple[int, ...],
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> tuple[tuple[tuple[int, ...], Fraction], ...]:
    totals: dict[tuple[int, ...], Fraction] = defaultdict(Fraction)
    canonical_state = canon(state)
    for probability, action in support:
        successor = canon(tuple(canonical_state[index] + action[index] for index in range(5)))
        totals[successor] += probability
    return tuple(sorted(totals.items(), key=lambda item: item[0]))


def _format_transition_distribution(
    distribution: tuple[tuple[tuple[int, ...], Fraction], ...],
) -> str:
    return ", ".join(f"{state}:{_fraction_text(probability)}" for state, probability in distribution)


def _best_centered_vertex_for_state(
    state: tuple[int, ...],
    horizon: int,
    vertices: tuple[BalancedActionVertex, ...],
) -> tuple[float, BalancedActionVertex]:
    return max(
        ((_balanced_chase_centered_q(state, horizon, vertex), vertex) for vertex in vertices),
        key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
    )


def _tiny_balanced_optimal_policy_c_usage(
    horizon: int,
    max_used: int,
) -> tuple[tuple[int, tuple[int, ...], tuple[int, ...], Fraction, float, tuple[tuple[Fraction, tuple[int, ...]], ...]], ...]:
    vertices = k5_balanced_action_vertices()
    rows = []
    for remaining in range(1, horizon + 1):
        for state in _k5_balanced_chase_greedy_defect_states(max_used):
            best_q, best_vertex = _best_centered_vertex_for_state(state, remaining, vertices)
            if best_vertex.marginal != Fraction(1, 2):
                rows.append(
                    (
                        remaining,
                        state,
                        packet_type(state),
                        best_vertex.marginal,
                        best_q,
                        best_vertex.support,
                    )
                )
    return tuple(rows)


@lru_cache(maxsize=None)
def _balanced_mdp_successor_terms(
    state: tuple[int, ...],
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> tuple[tuple[Fraction, int, tuple[int, ...]], ...]:
    totals: dict[tuple[int, tuple[int, ...]], Fraction] = defaultdict(Fraction)
    canonical_state = canon(state)
    for probability, action in support:
        raw_successor = tuple(canonical_state[index] + action[index] for index in range(5))
        successor = canon(raw_successor)
        totals[(min(raw_successor, default=0), successor)] += probability
    return tuple(
        (probability, offset, successor)
        for (offset, successor), probability in sorted(totals.items(), key=lambda item: (item[0][0], item[0][1]))
    )


def _balanced_mdp_vertex_centered_value(
    state: tuple[int, ...],
    continuation: dict[tuple[int, ...], float],
    vertex: BalancedActionVertex,
) -> float:
    total = 0.0
    for probability, offset, successor in _balanced_mdp_successor_terms(state, vertex.support):
        total += float(probability) * (float(offset) + continuation[successor])
    return total - float(vertex.marginal)


def _solve_k5_balanced_mdp_solution(
    vertices: tuple[BalancedActionVertex, ...],
    h_max: int,
) -> _BalancedMDPSolution:
    if h_max < 0:
        raise ValueError(f"h_max must be nonnegative, got {h_max}")

    state_layers = [tuple(all_states(5, used)) for used in range(h_max + 1)]
    terminal_values = {
        state: float(max(state, default=0))
        for used in range(h_max + 1)
        for state in state_layers[used]
    }
    values: list[dict[tuple[int, ...], float]] = [terminal_values]
    policies: list[dict[tuple[int, ...], BalancedActionVertex]] = [{}]

    for remaining in range(1, h_max + 1):
        continuation = values[remaining - 1]
        current: dict[tuple[int, ...], float] = {}
        policy: dict[tuple[int, ...], BalancedActionVertex] = {}
        for used in range(h_max - remaining + 1):
            for state in state_layers[used]:
                best_value, best_vertex = max(
                    ((_balanced_mdp_vertex_centered_value(state, continuation, vertex), vertex) for vertex in vertices),
                    key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
                )
                current[state] = best_value
                policy[state] = best_vertex
        values.append(current)
        policies.append(policy)

    return _BalancedMDPSolution(values=tuple(values), policies=tuple(policies))


@lru_cache(maxsize=None)
def _k5_balanced_mdp_full_solution(h_max: int) -> _BalancedMDPSolution:
    return _solve_k5_balanced_mdp_solution(k5_balanced_action_vertices(), h_max)


@lru_cache(maxsize=None)
def _k5_balanced_mdp_half_solution(h_max: int) -> _BalancedMDPSolution:
    vertices = tuple(vertex for vertex in k5_balanced_action_vertices() if vertex.marginal == Fraction(1, 2))
    return _solve_k5_balanced_mdp_solution(vertices, h_max)


@lru_cache(maxsize=None)
def _k5_balanced_mdp_orbit_solution(h_max: int) -> _BalancedMDPSolution:
    return _solve_k5_balanced_mdp_solution(_k5_chase_orbit_vertices(), h_max)


@lru_cache(maxsize=None)
def _k5_balanced_mdp_fixed_chase_solution(h_max: int) -> _BalancedMDPSolution:
    chase_vertex = _k5_chase_balanced_vertex()
    if chase_vertex is None:
        raise RuntimeError("Chase is not present in the balanced vertex enumeration")
    return _solve_k5_balanced_mdp_solution((chase_vertex,), h_max)


def _balanced_mdp_policy_occupancy(
    solution: _BalancedMDPSolution,
    horizon: int,
) -> tuple[dict[tuple[int, ...], float], ...]:
    zero = (0, 0, 0, 0, 0)
    occupancy: list[dict[tuple[int, ...], float]] = [defaultdict(float) for _ in range(horizon + 1)]
    occupancy[0][zero] = 1.0
    for time in range(horizon):
        remaining = horizon - time
        for state, state_probability in occupancy[time].items():
            vertex = solution.policies[remaining][state]
            for action_probability, action in vertex.support:
                successor = canon(tuple(state[index] + action[index] for index in range(5)))
                occupancy[time + 1][successor] += state_probability * float(action_probability)
    return tuple(dict(layer) for layer in occupancy)


def _k5_balanced_mdp_h_values(
    h_values: tuple[int, ...] | None,
    h_max: int,
) -> tuple[int, ...]:
    if h_values is not None:
        return tuple(sorted({int(value) for value in h_values if int(value) >= 1}))
    if h_max < 1:
        raise ValueError(f"h_max must be positive when h_values is omitted, got {h_max}")
    return tuple(range(1, h_max + 1))


def k5_balanced_mdp_value_gap_rows(
    h_values: tuple[int, ...] | None = None,
    h_max: int = 20,
) -> tuple[BalancedMDPValueGapRow, ...]:
    horizons = _k5_balanced_mdp_h_values(h_values, h_max)
    max_horizon = max(horizons, default=0)
    zero = (0, 0, 0, 0, 0)
    full_solution = _k5_balanced_mdp_full_solution(max_horizon)
    half_solution = _k5_balanced_mdp_half_solution(max_horizon)
    orbit_solution = _k5_balanced_mdp_orbit_solution(max_horizon)
    fixed_solution = _k5_balanced_mdp_fixed_chase_solution(max_horizon)

    rows: list[BalancedMDPValueGapRow] = []
    for horizon in horizons:
        initial_vertex = full_solution.policies[horizon][zero]
        orbit_vertex = orbit_solution.policies[horizon][zero]
        v_full = full_solution.values[horizon][zero]
        v_half = half_solution.values[horizon][zero]
        v_orbit = orbit_solution.values[horizon][zero]
        v_fixed = fixed_solution.values[horizon][zero]
        rows.append(
            BalancedMDPValueGapRow(
                horizon=horizon,
                v_full=v_full,
                v_half=v_half,
                v_orbit=v_orbit,
                v_fixed_chase=v_fixed,
                gap_full_minus_half=max(0.0, v_full - v_half),
                gap_full_minus_orbit=max(0.0, v_full - v_orbit),
                gap_full_minus_fixed_chase=max(0.0, v_full - v_fixed),
                initial_best_c=initial_vertex.marginal,
                initial_best_class=_balanced_vertex_class_index(initial_vertex),
                initial_best_support=initial_vertex.support,
                initial_orbit_support=orbit_vertex.support,
            )
        )
    return tuple(rows)


def k5_balanced_mdp_policy_c_usage_rows(
    h_values: tuple[int, ...] | None = None,
    h_max: int = 20,
    tolerance: float = 1e-12,
) -> tuple[BalancedMDPCUsageRow, ...]:
    horizons = _k5_balanced_mdp_h_values(h_values, h_max)
    full_solution = _k5_balanced_mdp_full_solution(max(horizons, default=0))
    rows: list[BalancedMDPCUsageRow] = []
    for horizon in horizons:
        occupancy = _balanced_mdp_policy_occupancy(full_solution, horizon)
        masses: dict[Fraction, float] = defaultdict(float)
        state_counts: dict[Fraction, int] = defaultdict(int)
        for time in range(horizon):
            remaining = horizon - time
            for state, occupancy_probability in occupancy[time].items():
                if occupancy_probability <= tolerance:
                    continue
                best_vertex = full_solution.policies[remaining][state]
                masses[best_vertex.marginal] += occupancy_probability
                state_counts[best_vertex.marginal] += 1
        for c_value in sorted(masses, key=lambda value: (float(value), value.numerator, value.denominator)):
            rows.append(
                BalancedMDPCUsageRow(
                    horizon=horizon,
                    c_value=c_value,
                    occupancy_mass=masses[c_value],
                    state_count=state_counts[c_value],
                )
            )
    return tuple(rows)


def k5_balanced_mdp_gap_scaling_rows(
    h_values: tuple[int, ...] | None = None,
    h_max: int = 30,
) -> tuple[BalancedMDPGapScalingRow, ...]:
    value_rows = k5_balanced_mdp_value_gap_rows(h_values=h_values, h_max=h_max)
    rows: list[BalancedMDPGapScalingRow] = []
    for row in value_rows:
        sqrt_h = float(np.sqrt(row.horizon))
        log_h_plus_1 = float(np.log(row.horizon + 1))
        rows.append(
            BalancedMDPGapScalingRow(
                horizon=row.horizon,
                gap_full_minus_orbit=row.gap_full_minus_orbit,
                gap_full_minus_half=row.gap_full_minus_half,
                gap_half_minus_orbit=max(0.0, row.v_half - row.v_orbit),
                gap_over_sqrt_h=row.gap_full_minus_orbit / sqrt_h,
                gap_over_log_h_plus_1=(row.gap_full_minus_orbit / log_h_plus_1) if log_h_plus_1 > 0.0 else 0.0,
                best_first_c=row.initial_best_c,
                best_first_class=row.initial_best_class,
            )
        )
    return tuple(rows)


def k5_balanced_mdp_gap_scaling_summary(
    h_values: tuple[int, ...] | None = None,
    h_max: int = 30,
    tail_length: int = 10,
    tolerance: float = 1e-9,
) -> BalancedMDPGapScalingSummary:
    rows = k5_balanced_mdp_gap_scaling_rows(h_values=h_values, h_max=h_max)
    if not rows:
        raise ValueError("at least one horizon is required for the gap-scaling summary")
    max_row = max(rows, key=lambda row: (row.gap_full_minus_orbit, row.horizon))
    tail_rows = rows[-min(len(rows), tail_length) :]
    tail_sqrt = tuple(row.gap_over_sqrt_h for row in tail_rows)
    monotonicity_holds = all(
        row.gap_full_minus_half >= -tolerance and row.gap_half_minus_orbit >= -tolerance
        for row in rows
    )
    c_half_orbit_optimality_holds = all(row.gap_half_minus_orbit <= tolerance for row in rows)
    return BalancedMDPGapScalingSummary(
        max_gap=max_row.gap_full_minus_orbit,
        argmax_h=max_row.horizon,
        tail_horizons=tuple(row.horizon for row in tail_rows),
        tail_gaps=tuple(row.gap_full_minus_orbit for row in tail_rows),
        tail_gap_over_sqrt=tail_sqrt,
        gap_over_sqrt_nonincreasing_on_tail=all(
            tail_sqrt[index] <= tail_sqrt[index - 1] + tolerance
            for index in range(1, len(tail_sqrt))
        ),
        gap_over_sqrt_end_to_end_decreases=(tail_sqrt[-1] <= tail_sqrt[0] + tolerance) if tail_sqrt else True,
        monotonicity_holds=monotonicity_holds,
        c_half_orbit_optimality_holds=c_half_orbit_optimality_holds,
    )


def _k5_c_half_balanced_vertices() -> tuple[BalancedActionVertex, ...]:
    return tuple(vertex for vertex in k5_balanced_action_vertices() if vertex.marginal == Fraction(1, 2))


def _balanced_mdp_q_against_solution(
    solution: _BalancedMDPSolution,
    state: tuple[int, ...],
    horizon: int,
    vertex: BalancedActionVertex,
) -> float:
    if horizon <= 0:
        return solution.values[0][canon(state)]
    return _balanced_mdp_vertex_centered_value(state, solution.values[horizon - 1], vertex)


def _transition_distribution_float_map(
    state: tuple[int, ...],
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> dict[tuple[int, ...], float]:
    return {successor: float(probability) for successor, probability in _transition_distribution_for_support(state, support)}


def _transition_contained_in_orbit_hull(
    state: tuple[int, ...],
    vertex: BalancedActionVertex,
    orbit_vertices: tuple[BalancedActionVertex, ...],
    tolerance: float,
) -> bool:
    target = _transition_distribution_float_map(state, vertex.support)
    orbit_distributions = tuple(_transition_distribution_float_map(state, orbit.support) for orbit in orbit_vertices)
    successor_states = tuple(
        sorted(
            set(target).union(*(set(distribution) for distribution in orbit_distributions)),
            key=lambda successor: (max(successor, default=0), successor),
        )
    )
    a_eq: list[list[float]] = []
    b_eq: list[float] = []
    for successor in successor_states:
        a_eq.append([distribution.get(successor, 0.0) for distribution in orbit_distributions])
        b_eq.append(target.get(successor, 0.0))
    a_eq.append([1.0] * len(orbit_vertices))
    b_eq.append(1.0)
    result = linprog(
        c=[0.0] * len(orbit_vertices),
        A_eq=np.array(a_eq, dtype=float),
        b_eq=np.array(b_eq, dtype=float),
        bounds=[(0.0, 1.0)] * len(orbit_vertices),
        method="highs",
    )
    if not result.success:
        return False
    residual = np.array(a_eq, dtype=float) @ result.x - np.array(b_eq, dtype=float)
    return bool(np.max(np.abs(residual)) <= tolerance)


def _transition_orbit_hull_mixture(
    state: tuple[int, ...],
    vertex: BalancedActionVertex,
    orbit_vertices: tuple[BalancedActionVertex, ...],
    tolerance: float,
) -> tuple[tuple[float, BalancedActionVertex], ...]:
    target = _transition_distribution_float_map(state, vertex.support)
    orbit_distributions = tuple(_transition_distribution_float_map(state, orbit.support) for orbit in orbit_vertices)
    successor_states = tuple(
        sorted(
            set(target).union(*(set(distribution) for distribution in orbit_distributions)),
            key=lambda successor: (max(successor, default=0), successor),
        )
    )
    a_eq: list[list[float]] = []
    b_eq: list[float] = []
    for successor in successor_states:
        a_eq.append([distribution.get(successor, 0.0) for distribution in orbit_distributions])
        b_eq.append(target.get(successor, 0.0))
    a_eq.append([1.0] * len(orbit_vertices))
    b_eq.append(1.0)
    result = linprog(
        c=[0.0] * len(orbit_vertices),
        A_eq=np.array(a_eq, dtype=float),
        b_eq=np.array(b_eq, dtype=float),
        bounds=[(0.0, 1.0)] * len(orbit_vertices),
        method="highs",
    )
    if not result.success:
        return ()
    residual = np.array(a_eq, dtype=float) @ result.x - np.array(b_eq, dtype=float)
    if np.max(np.abs(residual)) > tolerance:
        return ()
    return tuple(
        (float(weight), orbit)
        for weight, orbit in zip(result.x, orbit_vertices, strict=True)
        if weight > tolerance
    )


def _c_half_orbit_certificate_packet_states(max_used: int) -> tuple[tuple[int, ...], ...]:
    by_packet: dict[tuple[int, ...], tuple[int, ...]] = {}
    for state in _k5_balanced_chase_greedy_defect_states(max_used):
        by_packet.setdefault(packet_type(state), state)
    return tuple(sorted(by_packet.values(), key=lambda state: (packet_type(state), max(state, default=0), state)))


def _c_half_orbit_certificate_class_representatives() -> tuple[BalancedActionVertex, ...]:
    representatives: dict[tuple[tuple[str, int, int], ...], BalancedActionVertex] = {}
    for vertex in _k5_c_half_balanced_vertices():
        representatives.setdefault(vertex.canonical_key, vertex)
    return tuple(sorted(representatives.values(), key=lambda vertex: vertex.canonical_key))


def k5_c_half_orbit_optimality_violation_rows(
    h_values: tuple[int, ...] = (1, 2, 4, 8, 12, 15),
    max_used: int = 8,
) -> tuple[CHalfOrbitOptimalityViolationRow, ...]:
    horizons = tuple(sorted({int(value) for value in h_values if int(value) >= 1}))
    orbit_solution = _k5_balanced_mdp_orbit_solution(max(horizons, default=0) + max_used)
    half_vertices = _k5_c_half_balanced_vertices()
    orbit_vertices = _k5_chase_orbit_vertices()
    rows: list[CHalfOrbitOptimalityViolationRow] = []
    for horizon in horizons:
        for state in _k5_balanced_chase_greedy_defect_states(max_used):
            best_half_q, best_half_vertex = max(
                (
                    (_balanced_mdp_q_against_solution(orbit_solution, state, horizon, vertex), vertex)
                    for vertex in half_vertices
                ),
                key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
            )
            best_orbit_q, best_orbit_vertex = max(
                (
                    (_balanced_mdp_q_against_solution(orbit_solution, state, horizon, vertex), vertex)
                    for vertex in orbit_vertices
                ),
                key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
            )
            rows.append(
                CHalfOrbitOptimalityViolationRow(
                    horizon=horizon,
                    state=state,
                    packet_type=packet_type(state),
                    packet_gaps=_gap_vector(state),
                    eps_half_orbit=max(0.0, best_half_q - best_orbit_q),
                    best_half_q=best_half_q,
                    best_orbit_q=best_orbit_q,
                    best_half_class=_balanced_vertex_class_index(best_half_vertex),
                    best_half_support=best_half_vertex.support,
                    best_orbit_support=best_orbit_vertex.support,
                )
            )
    return tuple(rows)


def k5_c_half_orbit_optimality_certificate_rows(
    h_values: tuple[int, ...] = (1, 2, 4, 8, 12, 15),
    max_used: int = 8,
    tolerance: float = 1e-10,
) -> tuple[CHalfOrbitCertificateRow, ...]:
    horizons = tuple(sorted({int(value) for value in h_values if int(value) >= 1}))
    orbit_solution = _k5_balanced_mdp_orbit_solution(max(horizons, default=0) + max_used)
    orbit_vertices = _k5_chase_orbit_vertices()
    rows: list[CHalfOrbitCertificateRow] = []
    for state in _c_half_orbit_certificate_packet_states(max_used):
        for vertex in _c_half_orbit_certificate_class_representatives():
            transition_contained = _transition_contained_in_orbit_hull(state, vertex, orbit_vertices, tolerance)
            max_value_excess = 0.0
            for horizon in horizons:
                vertex_q = _balanced_mdp_q_against_solution(orbit_solution, state, horizon, vertex)
                orbit_q = max(
                    _balanced_mdp_q_against_solution(orbit_solution, state, horizon, orbit_vertex)
                    for orbit_vertex in orbit_vertices
                )
                max_value_excess = max(max_value_excess, vertex_q - orbit_q)
            rows.append(
                CHalfOrbitCertificateRow(
                    state=state,
                    packet_type=packet_type(state),
                    packet_gaps=_gap_vector(state),
                    vertex_class=_balanced_vertex_class_index(vertex),
                    support=vertex.support,
                    transition_contained=transition_contained,
                    value_dominated=max_value_excess <= tolerance,
                    max_value_excess=max_value_excess,
                )
            )
    return tuple(rows)


def k5_c_half_orbit_flat_equality_holds(
    h_values: tuple[int, ...] = tuple(range(1, 16)),
    tolerance: float = 1e-10,
) -> bool:
    horizons = tuple(sorted({int(value) for value in h_values if int(value) >= 1}))
    zero = (0, 0, 0, 0, 0)
    orbit_solution = _k5_balanced_mdp_orbit_solution(max(horizons, default=0))
    half_vertices = _k5_c_half_balanced_vertices()
    orbit_vertices = _k5_chase_orbit_vertices()
    return all(
        max(
            _balanced_mdp_q_against_solution(orbit_solution, zero, horizon, vertex)
            for vertex in half_vertices
        )
        <= max(
            _balanced_mdp_q_against_solution(orbit_solution, zero, horizon, vertex)
            for vertex in orbit_vertices
        )
        + tolerance
        for horizon in horizons
    )


def print_k5_c_half_orbit_optimality_certificate_report(
    h_values: tuple[int, ...] = (1, 2, 4, 8, 12, 15),
    max_used: int = 8,
    n: int = 20,
    tolerance: float = 1e-10,
) -> None:
    violation_rows = k5_c_half_orbit_optimality_violation_rows(h_values=h_values, max_used=max_used)
    certificate_rows = k5_c_half_orbit_optimality_certificate_rows(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
    )
    flat_equality_holds = k5_c_half_orbit_flat_equality_holds(tolerance=tolerance)
    orbit_vertices = _k5_chase_orbit_vertices()
    half_vertices = _k5_c_half_balanced_vertices()

    print("c=1/2 orbit optimality")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"balanced c=1/2 vertices: {len(half_vertices)}")
    print(f"Chase/Comb orbit actions: {len(orbit_vertices)}")
    print(f"orbit actions included in B_half: {all(vertex.marginal == Fraction(1, 2) for vertex in orbit_vertices)}")
    print(f"flat V_half = V_orbit for h<=15: {flat_equality_holds}")
    print()

    print("1. max violation")
    print("h eps state packet gaps best_half_class best_half_q best_orbit_q")
    for horizon in h_values:
        group = [row for row in violation_rows if row.horizon == horizon]
        if not group:
            continue
        worst = max(group, key=lambda row: (row.eps_half_orbit, row.state))
        print(
            f"{horizon:4d}"
            f" {worst.eps_half_orbit:.12g}"
            f" {worst.state}"
            f" {worst.packet_type}"
            f" {worst.packet_gaps}"
            f" {worst.best_half_class}"
            f" {worst.best_half_q:.12f}"
            f" {worst.best_orbit_q:.12f}"
        )
        print(f"     best half: {_format_balanced_support(worst.best_half_support)}")
        print(f"     best orbit: {_format_balanced_support(worst.best_orbit_support)}")

    max_violation = max((row.eps_half_orbit for row in violation_rows), default=0.0)
    print()
    print("2. transition containment")
    contained = sum(1 for row in certificate_rows if row.transition_contained)
    print(
        f"representative packet/class checks: {len(certificate_rows)}"
        f" contained={contained}"
        f" failed={len(certificate_rows) - contained}"
    )
    by_packet: dict[tuple[int, ...], list[CHalfOrbitCertificateRow]] = defaultdict(list)
    for row in certificate_rows:
        by_packet[row.packet_type].append(row)
    for packet, packet_rows in sorted(by_packet.items(), key=lambda item: item[0]):
        packet_contained = sum(1 for row in packet_rows if row.transition_contained)
        packet_dominated = sum(1 for row in packet_rows if row.value_dominated)
        packet_worst = max(packet_rows, key=lambda row: row.max_value_excess)
        print(
            f"  packet={packet}"
            f" contained={packet_contained}/{len(packet_rows)}"
            f" value_dominated={packet_dominated}/{len(packet_rows)}"
            f" max_value_excess={packet_worst.max_value_excess:.12g}"
            f" state={packet_worst.state}"
            f" class={packet_worst.vertex_class}"
        )

    print()
    print("3. value domination")
    failures = [row for row in certificate_rows if not row.transition_contained]
    value_only = [row for row in failures if row.value_dominated]
    value_failures = [row for row in failures if not row.value_dominated]
    print(
        f"transition failures: {len(failures)}"
        f" value-only domination: {len(value_only)}"
        f" value-domination failures: {len(value_failures)}"
    )
    for row in sorted(value_only, key=lambda item: (-item.max_value_excess, item.packet_type, item.vertex_class))[:n]:
        print(
            f"  value-only packet={row.packet_type}"
            f" state={row.state}"
            f" gaps={row.packet_gaps}"
            f" class={row.vertex_class}"
            f" max_excess={row.max_value_excess:.12g}"
            f" support={_format_balanced_support(row.support)}"
        )
    if value_failures:
        print("  value-domination failures:")
        for row in sorted(value_failures, key=lambda item: (-item.max_value_excess, item.packet_type, item.vertex_class))[:n]:
            print(
                f"    packet={row.packet_type}"
                f" state={row.state}"
                f" class={row.vertex_class}"
                f" max_excess={row.max_value_excess:.12g}"
                f" support={_format_balanced_support(row.support)}"
            )

    print()
    print("4. theorem candidate")
    print(
        "  If every c=1/2 balanced action is transition-contained in the Chase/Comb orbit hull,"
        " or value-dominated by that hull against V_orbit on the tested state family, then V_half = V_orbit."
    )
    print(
        f"  Tested certificate status: max violation={max_violation:.12g};"
        f" all value dominated={not value_failures};"
        f" flat h<=15 equality={flat_equality_holds}."
    )


def k5_c_half_orbit_dual_certificate_rows(
    h_values: tuple[int, ...] = (1, 2, 4, 8, 12, 15),
    max_used: int = 8,
    tolerance: float = 1e-10,
) -> tuple[CHalfOrbitDualCertificateRow, ...]:
    horizons = tuple(sorted({int(value) for value in h_values if int(value) >= 1}))
    orbit_solution = _k5_balanced_mdp_orbit_solution(max(horizons, default=0) + max_used)
    orbit_vertices = _k5_chase_orbit_vertices()
    rows: list[CHalfOrbitDualCertificateRow] = []
    for state in _c_half_orbit_certificate_packet_states(max_used):
        for vertex in _c_half_orbit_certificate_class_representatives():
            mixture = _transition_orbit_hull_mixture(state, vertex, orbit_vertices, tolerance)
            value_inequalities: list[tuple[int, float, tuple[tuple[Fraction, tuple[int, ...]], ...]]] = []
            max_excess = -float("inf")
            if not mixture:
                for horizon in horizons:
                    vertex_q = _balanced_mdp_q_against_solution(orbit_solution, state, horizon, vertex)
                    best_orbit_q, best_orbit_vertex = max(
                        (
                            (_balanced_mdp_q_against_solution(orbit_solution, state, horizon, orbit_vertex), orbit_vertex)
                            for orbit_vertex in orbit_vertices
                        ),
                        key=lambda item: (item[0], -len(item[1].support), item[1].canonical_key),
                    )
                    max_excess = max(max_excess, vertex_q - best_orbit_q)
                    value_inequalities.append((horizon, best_orbit_q - vertex_q, best_orbit_vertex.support))
            else:
                max_excess = 0.0
            rows.append(
                CHalfOrbitDualCertificateRow(
                    packet_type=packet_type(state),
                    state=state,
                    packet_gaps=_gap_vector(state),
                    vertex_class=_balanced_vertex_class_index(vertex),
                    support=vertex.support,
                    certificate_type="transition-hull" if mixture else "value-domination",
                    transition_mixture=tuple((weight, orbit.support) for weight, orbit in mixture),
                    value_inequalities=tuple(value_inequalities),
                    max_excess=max_excess,
                )
            )
    return tuple(rows)


def print_k5_c_half_orbit_dual_certificate_report(
    h_values: tuple[int, ...] = (1, 2, 4, 8, 12, 15),
    max_used: int = 8,
    n: int = 30,
    tolerance: float = 1e-10,
) -> None:
    rows = k5_c_half_orbit_dual_certificate_rows(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
    )
    print("c=1/2 orbit dual certificate")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"c=1/2 balanced vertices: {len(_k5_c_half_balanced_vertices())}")
    print(f"representative packet/action certificates: {len(rows)}")
    print()

    contained = [row for row in rows if row.certificate_type == "transition-hull"]
    value_only = [row for row in rows if row.certificate_type == "value-domination"]
    print("1. certificate summary")
    print(f"  transition-hull certificates: {len(contained)}")
    print(f"  value-domination certificates: {len(value_only)}")
    print(f"  max_excess: {max((row.max_excess for row in rows), default=0.0):.12g}")
    print()

    print("2. packet/action class reduction")
    by_packet: dict[tuple[int, ...], list[CHalfOrbitDualCertificateRow]] = defaultdict(list)
    for row in rows:
        by_packet[row.packet_type].append(row)
    for packet, packet_rows in sorted(by_packet.items(), key=lambda item: item[0]):
        packet_contained = sum(1 for row in packet_rows if row.certificate_type == "transition-hull")
        classes = sorted({row.vertex_class for row in packet_rows})
        print(
            f"  packet={packet}"
            f" classes={classes}"
            f" transition_hull={packet_contained}/{len(packet_rows)}"
            f" value_domination={len(packet_rows) - packet_contained}/{len(packet_rows)}"
        )

    print()
    print("3. transition-hull certificates")
    for row in contained[:n]:
        mixture_text = " + ".join(
            f"{weight:.6g}*({_format_balanced_support(support)})"
            for weight, support in row.transition_mixture
        )
        print(
            f"  packet={row.packet_type}"
            f" state={row.state}"
            f" class={row.vertex_class}"
            f" A={_format_balanced_support(row.support)}"
        )
        print(f"    transition(A) = {mixture_text}")

    print()
    print("4. value-domination inequalities")
    for row in sorted(value_only, key=lambda item: (-item.max_excess, item.packet_type, item.vertex_class))[:n]:
        print(
            f"  packet={row.packet_type}"
            f" state={row.state}"
            f" gaps={row.packet_gaps}"
            f" class={row.vertex_class}"
            f" max_excess={row.max_excess:.12g}"
            f" A={_format_balanced_support(row.support)}"
        )
        for horizon, slack, orbit_support in row.value_inequalities:
            print(
                f"    I(h={horizon}):"
                f" Q_orbit(C={_format_balanced_support(orbit_support)})"
                f" - Q_orbit(A) = {slack:.12g}"
            )

    print()
    print("5. theorem-ready implication")
    needed = sorted({(row.packet_type, row.vertex_class) for row in value_only})
    print(
        "  For every representative packet p and c=1/2 balanced action class A,"
        " either transition(A) lies in the convex hull of orbit transitions, or one of the listed"
        " value inequalities I_{p,A,h} dominates A against V_orbit."
    )
    print(
        f"  Thus if V_orbit at horizon t-1 satisfies these {len(needed)} packet/class inequality families,"
        " then every c=1/2 balanced action is dominated at horizon t, and V_half=V_orbit follows by induction."
    )


def _linear_q_functional_for_support(
    state: tuple[int, ...],
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> tuple[float, dict[tuple[int, ...], float]]:
    coeffs: dict[tuple[int, ...], float] = defaultdict(float)
    const = -float(_balanced_support_common_marginal(support))
    for probability, offset, successor in _balanced_mdp_successor_terms(state, support):
        const += float(probability) * float(offset)
        coeffs[successor] += float(probability)
    return const, dict(coeffs)


def _linear_difference_functional(
    state: tuple[int, ...],
    positive_support: tuple[tuple[Fraction, tuple[int, ...]], ...],
    negative_support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> tuple[float, dict[tuple[int, ...], float]]:
    pos_const, pos_coeffs = _linear_q_functional_for_support(state, positive_support)
    neg_const, neg_coeffs = _linear_q_functional_for_support(state, negative_support)
    coeffs: dict[tuple[int, ...], float] = defaultdict(float)
    for successor, value in pos_coeffs.items():
        coeffs[successor] += value
    for successor, value in neg_coeffs.items():
        coeffs[successor] -= value
    return pos_const - neg_const, dict(coeffs)


def _linear_q_of_orbit_bellman_functional(
    state: tuple[int, ...],
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
    active_horizon: int,
    orbit_solution: _BalancedMDPSolution,
) -> tuple[float, dict[tuple[int, ...], float], set[tuple[tuple[Fraction, tuple[int, ...]], ...]]]:
    coeffs: dict[tuple[int, ...], float] = defaultdict(float)
    active_supports: set[tuple[tuple[Fraction, tuple[int, ...]], ...]] = set()
    const = -float(_balanced_support_common_marginal(support))
    for outer_probability, outer_offset, successor in _balanced_mdp_successor_terms(state, support):
        active_vertex = orbit_solution.policies[active_horizon][successor]
        active_supports.add(active_vertex.support)
        const += float(outer_probability) * float(outer_offset)
        for inner_probability, inner_offset, inner_successor in _balanced_mdp_successor_terms(successor, active_vertex.support):
            const += float(outer_probability) * float(inner_probability) * (
                float(inner_offset) - float(active_vertex.marginal)
            )
            coeffs[inner_successor] += float(outer_probability) * float(inner_probability)
    return const, dict(coeffs), active_supports


def _functional_to_vector(
    const: float,
    coeffs: dict[tuple[int, ...], float],
    states: tuple[tuple[int, ...], ...],
) -> tuple[float, ...]:
    return (const, *(coeffs.get(state, 0.0) for state in states))


def _add_scaled_functional(
    const: float,
    coeffs: dict[tuple[int, ...], float],
    scale: float,
    other: tuple[float, dict[tuple[int, ...], float]],
) -> tuple[float, dict[tuple[int, ...], float]]:
    other_const, other_coeffs = other
    next_coeffs: dict[tuple[int, ...], float] = defaultdict(float)
    for state, value in coeffs.items():
        next_coeffs[state] += value
    for state, value in other_coeffs.items():
        next_coeffs[state] += scale * value
    return const + scale * other_const, dict(next_coeffs)


def _orbit_vertex_index_by_support() -> dict[tuple[tuple[Fraction, tuple[int, ...]], ...], int]:
    return {vertex.support: index for index, vertex in enumerate(_k5_chase_orbit_vertices())}


def _active_orbit_guard_functionals_for_support(
    state: tuple[int, ...],
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
    active_horizon: int,
    orbit_solution: _BalancedMDPSolution,
    orbit_vertices: tuple[BalancedActionVertex, ...],
) -> tuple[tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]], ...]:
    support_to_index = _orbit_vertex_index_by_support()
    guard_rows: list[tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]] = []
    seen: set[tuple[tuple[int, ...], int, int]] = set()
    for _probability, _offset, successor in _balanced_mdp_successor_terms(state, support):
        active_vertex = orbit_solution.policies[active_horizon][successor]
        active_index = support_to_index.get(active_vertex.support, -1)
        for competitor_index, competitor in enumerate(orbit_vertices):
            if competitor.support == active_vertex.support:
                continue
            key = (successor, active_index, competitor_index)
            if key in seen:
                continue
            seen.add(key)
            guard_rows.append(
                (
                    successor,
                    active_index,
                    competitor_index,
                    _linear_difference_functional(successor, active_vertex.support, competitor.support),
                )
            )
    return tuple(guard_rows)


def _pushed_c_half_value_inequality(
    row: CHalfOrbitDualCertificateRow,
    horizon: int,
    orbit_solution: _BalancedMDPSolution,
) -> tuple[
    float,
    dict[tuple[int, ...], float],
    tuple[tuple[Fraction, tuple[int, ...]], ...],
    set[tuple[tuple[Fraction, tuple[int, ...]], ...]],
]:
    active_horizon = horizon - 1
    orbit_support = row.value_inequalities[0][2]
    for listed_horizon, _slack, listed_support in row.value_inequalities:
        if listed_horizon == horizon:
            orbit_support = listed_support
            break
    pos_const, pos_coeffs, pos_active = _linear_q_of_orbit_bellman_functional(
        row.state,
        orbit_support,
        active_horizon,
        orbit_solution,
    )
    neg_const, neg_coeffs, neg_active = _linear_q_of_orbit_bellman_functional(
        row.state,
        row.support,
        active_horizon,
        orbit_solution,
    )
    pushed_coeffs: dict[tuple[int, ...], float] = defaultdict(float)
    for state, value in pos_coeffs.items():
        pushed_coeffs[state] += value
    for state, value in neg_coeffs.items():
        pushed_coeffs[state] -= value
    return pos_const - neg_const, dict(pushed_coeffs), orbit_support, pos_active | neg_active


def _cone_closure_fit(
    target: tuple[float, ...],
    generators: tuple[tuple[float, ...], ...],
    tolerance: float,
) -> tuple[bool, float, tuple[tuple[float, int], ...], str]:
    if not generators:
        return False, float("inf"), (), "no generators"
    matrix = np.array(generators, dtype=float).T
    target_array = np.array(target, dtype=float)
    result = linprog(
        c=[0.0] * len(generators),
        A_eq=matrix,
        b_eq=target_array,
        bounds=[(0.0, None)] * len(generators),
        method="highs",
    )
    if result.success:
        residual = matrix @ result.x - target_array
        max_residual = float(np.max(np.abs(residual)))
        terms = tuple((float(weight), index) for index, weight in enumerate(result.x) if weight > tolerance)
        return max_residual <= tolerance, max_residual, terms, result.message

    # Diagnostic fallback: allow small signed residual via least-squares with nonnegative coefficients.
    lsq = linprog(
        c=[0.0] * len(generators) + [1.0],
        A_ub=np.vstack((matrix, -matrix)).T if False else None,
        bounds=[(0.0, None)] * (len(generators) + 1),
        method="highs",
    )
    del lsq
    return False, float("inf"), (), result.message


def k5_c_half_invariant_inequality_closure_rows(
    h_values: tuple[int, ...] = (2, 4, 8, 12, 15),
    max_used: int = 8,
    tolerance: float = 1e-9,
) -> tuple[CHalfInvariantClosureRow, ...]:
    horizons = tuple(sorted({int(value) for value in h_values if int(value) >= 2}))
    dual_rows = k5_c_half_orbit_dual_certificate_rows(h_values=h_values, max_used=max_used, tolerance=tolerance)
    value_rows = [row for row in dual_rows if row.certificate_type == "value-domination"]
    orbit_solution = _k5_balanced_mdp_orbit_solution(max(horizons, default=2) + max_used + 2)

    generator_specs: list[tuple[tuple[int, ...], int, tuple[tuple[Fraction, tuple[int, ...]], ...], tuple[float, dict[tuple[int, ...], float]]]] = []
    for row in value_rows:
        seen_orbits: set[tuple[tuple[Fraction, tuple[int, ...]], ...]] = set()
        for _horizon, _slack, orbit_support in row.value_inequalities:
            if orbit_support in seen_orbits:
                continue
            seen_orbits.add(orbit_support)
            generator_specs.append(
                (
                    row.packet_type,
                    row.vertex_class,
                    orbit_support,
                    _linear_difference_functional(row.state, orbit_support, row.support),
                )
            )

    rows: list[CHalfInvariantClosureRow] = []
    for row in value_rows:
        for horizon in horizons:
            active_horizon = horizon - 1
            orbit_support = row.value_inequalities[0][2]
            for listed_horizon, _slack, listed_support in row.value_inequalities:
                if listed_horizon == horizon:
                    orbit_support = listed_support
                    break
            pos_const, pos_coeffs, pos_active = _linear_q_of_orbit_bellman_functional(
                row.state,
                orbit_support,
                active_horizon,
                orbit_solution,
            )
            neg_const, neg_coeffs, neg_active = _linear_q_of_orbit_bellman_functional(
                row.state,
                row.support,
                active_horizon,
                orbit_solution,
            )
            pushed_coeffs: dict[tuple[int, ...], float] = defaultdict(float)
            for state, value in pos_coeffs.items():
                pushed_coeffs[state] += value
            for state, value in neg_coeffs.items():
                pushed_coeffs[state] -= value
            pushed_const = pos_const - neg_const

            relevant_states = tuple(
                sorted(
                    set(pushed_coeffs).union(
                        *[set(functional[1]) for *_prefix, functional in generator_specs],
                    ),
                    key=lambda state: (max(state, default=0), state),
                )
            )
            target = _functional_to_vector(pushed_const, dict(pushed_coeffs), relevant_states)
            generator_vectors = tuple(
                _functional_to_vector(functional[0], functional[1], relevant_states)
                for *_prefix, functional in generator_specs
            )
            coordinate_generators = tuple(
                tuple(1.0 if index == state_index + 1 else 0.0 for index in range(len(relevant_states) + 1))
                for state_index in range(len(relevant_states))
            )
            all_generators = generator_vectors + coordinate_generators
            closed, residual, terms, reason = _cone_closure_fit(target, all_generators, tolerance)
            certificate_terms: list[tuple[float, tuple[int, ...], int]] = []
            for weight, index in terms[:20]:
                if index < len(generator_specs):
                    packet, vertex_class, _support, _functional = generator_specs[index]
                    certificate_terms.append((weight, packet, vertex_class))
            rows.append(
                CHalfInvariantClosureRow(
                    packet_type=row.packet_type,
                    state=row.state,
                    vertex_class=row.vertex_class,
                    horizon=horizon,
                    active_case_count=len(pos_active | neg_active),
                    closed=closed,
                    max_residual=residual,
                    cone_terms=len(terms),
                    certificate_terms=tuple(certificate_terms),
                    failure_reason="" if closed else reason,
                )
            )
    return tuple(rows)


def print_k5_c_half_invariant_inequality_closure_report(
    h_values: tuple[int, ...] = (2, 4, 8, 12, 15),
    max_used: int = 8,
    n: int = 30,
    tolerance: float = 1e-9,
) -> None:
    rows = k5_c_half_invariant_inequality_closure_rows(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
    )
    print("c=1/2 invariant inequality closure")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"closure rows: {len(rows)}")
    print()

    closed_rows = [row for row in rows if row.closed]
    split_rows = [row for row in rows if row.active_case_count > 1]
    failed_rows = [row for row in rows if not row.closed]
    print("1. closure summary")
    print(f"  closed inequalities: {len(closed_rows)}")
    print(f"  inequalities requiring case splits by active orbit action: {len(split_rows)}")
    print(f"  failures: {len(failed_rows)}")
    print(f"  max residual among closed: {max((row.max_residual for row in closed_rows), default=0.0):.12g}")
    print()

    print("2. closed inequalities")
    for row in sorted(closed_rows, key=lambda item: (item.packet_type, item.vertex_class, item.horizon))[:n]:
        terms = ", ".join(f"{weight:.4g}*I(packet={packet},class={klass})" for weight, packet, klass in row.certificate_terms[:6])
        print(
            f"  packet={row.packet_type}"
            f" class={row.vertex_class}"
            f" h={row.horizon}"
            f" active_cases={row.active_case_count}"
            f" terms={row.cone_terms}"
            f" residual={row.max_residual:.3g}"
            f" {terms}"
        )

    print()
    print("3. active-action case splits")
    for row in sorted(split_rows, key=lambda item: (-item.active_case_count, item.packet_type, item.vertex_class, item.horizon))[:n]:
        print(
            f"  packet={row.packet_type}"
            f" class={row.vertex_class}"
            f" h={row.horizon}"
            f" active_cases={row.active_case_count}"
            f" closed={row.closed}"
            f" residual={row.max_residual:.12g}"
        )

    print()
    print("4. failures")
    for row in sorted(failed_rows, key=lambda item: (item.packet_type, item.vertex_class, item.horizon))[:n]:
        print(
            f"  packet={row.packet_type}"
            f" state={row.state}"
            f" class={row.vertex_class}"
            f" h={row.horizon}"
            f" active_cases={row.active_case_count}"
            f" residual={row.max_residual:.12g}"
            f" reason={row.failure_reason}"
        )

    print()
    print("5. theorem-ready closure table")
    print(
        "  Each closed row certifies a sampled identity of the form"
        " I_j(T_orbit f)=sum_k lambda_{jk} I_k(f)+nonnegative coordinate terms."
    )
    print(
        "  Remaining failures indicate missing base inequalities, missing case splits,"
        " or that the value-domination families need to be refined beyond the current sampled certificate."
    )


def print_k5_c_half_invariant_cone_closure_report(
    h_values: tuple[int, ...] = (2, 4, 8, 12, 15),
    max_used: int = 8,
    n: int = 40,
    tolerance: float = 1e-9,
) -> None:
    dual_rows = k5_c_half_orbit_dual_certificate_rows(
        h_values=(1, *h_values),
        max_used=max_used,
        tolerance=tolerance,
    )
    closure_rows = k5_c_half_invariant_inequality_closure_rows(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
    )
    value_families = [row for row in dual_rows if row.certificate_type == "value-domination"]
    transition_families = [row for row in dual_rows if row.certificate_type == "transition-hull"]
    family_keys = sorted({(row.packet_type, row.vertex_class) for row in value_families})
    closed_rows = [row for row in closure_rows if row.closed]
    failed_rows = [row for row in closure_rows if not row.closed]
    split_rows = [row for row in closure_rows if row.active_case_count > 1]

    print("c=1/2 invariant cone closure")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"known value-domination inequality families: {len(family_keys)}")
    print(f"value-domination representative rows: {len(value_families)}")
    print(f"transition-hull equality rows: {len(transition_families)}")
    print(f"closure checks: {len(closure_rows)}")
    print()

    print("1. cone closure summary")
    print(f"  closed: {len(closed_rows)}")
    print(f"  active orbit case splits: {len(split_rows)}")
    print(f"  failures: {len(failed_rows)}")
    print(f"  max closed residual: {max((row.max_residual for row in closed_rows), default=0.0):.12g}")
    print()

    print("2. closure table")
    print("packet class h active_cases closed cone_terms residual certificate_terms")
    for row in sorted(closure_rows, key=lambda item: (not item.closed, item.packet_type, item.vertex_class, item.horizon))[:n]:
        terms = "; ".join(
            f"{weight:.4g} I[{packet},class={klass}]"
            for weight, packet, klass in row.certificate_terms[:5]
        )
        print(
            f"{row.packet_type}"
            f" {row.vertex_class}"
            f" {row.horizon}"
            f" {row.active_case_count}"
            f" {row.closed}"
            f" {row.cone_terms}"
            f" {row.max_residual:.12g}"
            f" {terms}"
        )

    print()
    print("3. transition-hull equalities used before cone closure")
    for row in transition_families[:n]:
        mixture_text = " + ".join(
            f"{weight:.5g}*orbit({_format_balanced_support(support)})"
            for weight, support in row.transition_mixture
        )
        print(
            f"  packet={row.packet_type}"
            f" state={row.state}"
            f" class={row.vertex_class}"
            f" A={_format_balanced_support(row.support)}"
        )
        print(f"    transition(A) = {mixture_text}")

    print()
    print("4. failures by exact packet/action/class")
    if not failed_rows:
        print("  no sampled cone-closure failures.")
    for row in sorted(failed_rows, key=lambda item: (item.packet_type, item.vertex_class, item.horizon))[:n]:
        print(
            f"  packet={row.packet_type}"
            f" state={row.state}"
            f" class={row.vertex_class}"
            f" h={row.horizon}"
            f" active_cases={row.active_case_count}"
            f" residual={row.max_residual:.12g}"
            f" reason={row.failure_reason}"
        )

    print()
    print("5. theorem-ready statement")
    print(
        "  The cone test attempts to certify every pushed inequality as"
        " I_j(T_orbit f)=sum_k lambda_{jk} I_k(f)+transition-hull equalities"
        " + trivial nonnegative coordinate terms."
    )
    print(
        "  If all rows close after the indicated active-orbit case splits, the 88-family"
        " invariant cone proves that every c=1/2 balanced action is dominated by the"
        " Chase/Comb orbit, hence V_half=V_orbit by induction."
    )


def _functional_key(functional: tuple[float, dict[tuple[int, ...], float]], tolerance: float) -> tuple[object, ...]:
    scale = max(tolerance, 1e-12)
    const, coeffs = functional
    return (
        round(const / scale),
        tuple(sorted((state, round(value / scale)) for state, value in coeffs.items() if abs(value) > tolerance)),
    )


def _transition_hull_equality_functionals(
    transition_rows: list[CHalfOrbitDualCertificateRow],
) -> tuple[tuple[float, dict[tuple[int, ...], float]], ...]:
    equality_functionals: list[tuple[float, dict[tuple[int, ...], float]]] = []
    for row in transition_rows:
        const, coeffs = _linear_q_functional_for_support(row.state, row.support)
        for weight, orbit_support in row.transition_mixture:
            const, coeffs = _add_scaled_functional(
                const,
                coeffs,
                -float(weight),
                _linear_q_functional_for_support(row.state, orbit_support),
            )
        equality_functionals.append((const, coeffs))
        equality_functionals.append((-const, {state: -value for state, value in coeffs.items()}))
    return tuple(equality_functionals)


def _global_orbit_guard_functionals(
    states: tuple[tuple[int, ...], ...],
    active_horizon: int,
    orbit_solution: _BalancedMDPSolution,
    orbit_vertices: tuple[BalancedActionVertex, ...],
) -> tuple[tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]], ...]:
    support_to_index = _orbit_vertex_index_by_support()
    guards: list[tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]] = []
    seen: set[tuple[tuple[int, ...], int, int]] = set()
    for state in states:
        active_vertex = orbit_solution.policies[active_horizon][state]
        active_index = support_to_index.get(active_vertex.support, -1)
        for competitor_index, competitor in enumerate(orbit_vertices):
            if competitor.support == active_vertex.support:
                continue
            key = (state, active_index, competitor_index)
            if key in seen:
                continue
            seen.add(key)
            guards.append(
                (
                    state,
                    active_index,
                    competitor_index,
                    _linear_difference_functional(state, active_vertex.support, competitor.support),
                )
            )
    return tuple(guards)


def k5_c_half_augmented_cone_closure_rows(
    h_values: tuple[int, ...] = (2, 4, 8, 12, 15),
    max_used: int = 8,
    tolerance: float = 1e-9,
    cegar_iterations: int = 3,
) -> tuple[CHalfAugmentedConeClosureRow, ...]:
    horizons = tuple(sorted({int(value) for value in h_values if int(value) >= 2}))
    dual_rows = k5_c_half_orbit_dual_certificate_rows(
        h_values=(1, *horizons),
        max_used=max_used,
        tolerance=tolerance,
    )
    value_rows = [row for row in dual_rows if row.certificate_type == "value-domination"]
    transition_rows = [row for row in dual_rows if row.certificate_type == "transition-hull"]
    orbit_vertices = _k5_chase_orbit_vertices()
    orbit_solution = _k5_balanced_mdp_orbit_solution(max(horizons, default=2) + max_used + 2)

    value_functionals: list[tuple[tuple[int, ...], int, tuple[float, dict[tuple[int, ...], float]]]] = []
    for row in value_rows:
        seen_orbits: set[tuple[tuple[Fraction, tuple[int, ...]], ...]] = set()
        for _horizon, _slack, orbit_support in row.value_inequalities:
            if orbit_support in seen_orbits:
                continue
            seen_orbits.add(orbit_support)
            value_functionals.append(
                (
                    row.packet_type,
                    row.vertex_class,
                    _linear_difference_functional(row.state, orbit_support, row.support),
                )
            )
    transition_functionals = _transition_hull_equality_functionals(transition_rows)

    packet_states = _c_half_orbit_certificate_packet_states(max_used)
    global_guards_by_horizon = {
        horizon: _global_orbit_guard_functionals(
            packet_states,
            horizon - 1,
            orbit_solution,
            orbit_vertices,
        )
        for horizon in horizons
    }

    target_specs: list[
        tuple[
            CHalfOrbitDualCertificateRow,
            int,
            tuple[float, dict[tuple[int, ...], float]],
            int,
            tuple[tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]], ...],
        ]
    ] = []
    for row in value_rows:
        for horizon in horizons:
            pushed_const, pushed_coeffs, orbit_support, active_supports = _pushed_c_half_value_inequality(
                row,
                horizon,
                orbit_solution,
            )
            raw_local_guards = (
                *_active_orbit_guard_functionals_for_support(
                    row.state,
                    orbit_support,
                    horizon - 1,
                    orbit_solution,
                    orbit_vertices,
                ),
                *_active_orbit_guard_functionals_for_support(
                    row.state,
                    row.support,
                    horizon - 1,
                    orbit_solution,
                    orbit_vertices,
                ),
            )
            local_guard_list: list[
                tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]
            ] = []
            seen_local_guards: set[tuple[tuple[int, ...], int, int]] = set()
            for guard_state, active_index, competitor_index, functional in raw_local_guards:
                key = (guard_state, active_index, competitor_index)
                if key in seen_local_guards:
                    continue
                seen_local_guards.add(key)
                local_guard_list.append((guard_state, active_index, competitor_index, functional))
            local_guards = tuple(local_guard_list)
            target_specs.append(
                (
                    row,
                    horizon,
                    (pushed_const, pushed_coeffs),
                    len(active_supports),
                    local_guards,
                )
            )

    cegar_functionals: list[tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]] = []
    seen_cegar = {_functional_key(functional, tolerance) for *_prefix, functional in value_functionals}
    final_rows: tuple[CHalfAugmentedConeClosureRow, ...] = ()
    for iteration in range(max(0, cegar_iterations) + 1):
        rows: list[CHalfAugmentedConeClosureRow] = []
        failed_to_add: list[
            tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]
        ] = []
        for row, horizon, target_functional, active_case_count, local_guards in target_specs:
            generator_meta: list[tuple[str, object]] = []
            generator_functionals: list[tuple[float, dict[tuple[int, ...], float]]] = []
            for packet, vertex_class, functional in value_functionals:
                generator_meta.append(("value", (packet, vertex_class)))
                generator_functionals.append(functional)
            for index, functional in enumerate(transition_functionals):
                generator_meta.append(("transition", index))
                generator_functionals.append(functional)
            guard_list: list[
                tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]
            ] = []
            seen_guards: set[tuple[tuple[int, ...], int, int]] = set()
            for guard_state, active_index, competitor_index, functional in (
                *global_guards_by_horizon.get(horizon, ()),
                *local_guards,
            ):
                key = (guard_state, active_index, competitor_index)
                if key in seen_guards:
                    continue
                seen_guards.add(key)
                guard_list.append((guard_state, active_index, competitor_index, functional))
            guard_rows = tuple(guard_list)
            for guard_state, active_index, competitor_index, functional in guard_rows:
                generator_meta.append(("guard", (guard_state, active_index, competitor_index)))
                generator_functionals.append(functional)
            for packet, vertex_class, cegar_horizon, functional in cegar_functionals:
                generator_meta.append(("cegar", (packet, vertex_class, cegar_horizon)))
                generator_functionals.append(functional)

            all_states = set(target_functional[1])
            for _const, coeffs in generator_functionals:
                all_states.update(coeffs)
            relevant_states = tuple(sorted(all_states, key=lambda state: (max(state, default=0), state)))
            target = _functional_to_vector(target_functional[0], target_functional[1], relevant_states)
            generator_vectors = [
                _functional_to_vector(const, coeffs, relevant_states)
                for const, coeffs in generator_functionals
            ]
            coordinate_start = len(generator_vectors)
            coordinate_generators = [
                tuple(1.0 if index == state_index + 1 else 0.0 for index in range(len(relevant_states) + 1))
                for state_index in range(len(relevant_states))
            ]
            all_generators = tuple(generator_vectors + coordinate_generators)
            closed, residual, terms, reason = _cone_closure_fit(target, all_generators, tolerance)
            value_terms = guard_terms = transition_terms = coordinate_terms = cegar_terms = 0
            used_guard_weights: dict[tuple[tuple[int, ...], int, int], float] = defaultdict(float)
            for weight, index in terms:
                if index >= coordinate_start:
                    coordinate_terms += 1
                    continue
                kind, payload = generator_meta[index]
                if kind == "value":
                    value_terms += 1
                elif kind == "transition":
                    transition_terms += 1
                elif kind == "guard":
                    guard_terms += 1
                    guard_state, active_index, competitor_index = payload  # type: ignore[misc]
                    used_guard_weights[(guard_state, active_index, competitor_index)] += weight
                elif kind == "cegar":
                    cegar_terms += 1

            if not closed and iteration < max(0, cegar_iterations):
                key = _functional_key(target_functional, tolerance)
                if key not in seen_cegar:
                    seen_cegar.add(key)
                    failed_to_add.append((row.packet_type, row.vertex_class, horizon, target_functional))

            rows.append(
                CHalfAugmentedConeClosureRow(
                    packet_type=row.packet_type,
                    state=row.state,
                    vertex_class=row.vertex_class,
                    horizon=horizon,
                    active_case_count=active_case_count,
                    closed=closed,
                    max_residual=residual,
                    value_terms=value_terms,
                    guard_terms=guard_terms,
                    transition_terms=transition_terms,
                    coordinate_terms=coordinate_terms,
                    cegar_terms=cegar_terms,
                    used_guards=tuple(
                        (guard_state, active_index, competitor_index, weight)
                        for (guard_state, active_index, competitor_index), weight in sorted(
                            used_guard_weights.items(),
                            key=lambda item: (-item[1], item[0][0], item[0][1], item[0][2]),
                        )[:12]
                    ),
                    cegar_iteration_closed=iteration if closed else -1,
                    failure_reason="" if closed else reason,
                )
            )
        final_rows = tuple(rows)
        if not failed_to_add:
            break
        cegar_functionals.extend(failed_to_add)
    return final_rows


def print_k5_c_half_augmented_cone_closure_report(
    h_values: tuple[int, ...] = (2, 4, 8, 12, 15),
    max_used: int = 8,
    n: int = 40,
    tolerance: float = 1e-9,
    cegar_iterations: int = 3,
) -> None:
    dual_rows = k5_c_half_orbit_dual_certificate_rows(
        h_values=(1, *h_values),
        max_used=max_used,
        tolerance=tolerance,
    )
    value_rows = [row for row in dual_rows if row.certificate_type == "value-domination"]
    transition_rows = [row for row in dual_rows if row.certificate_type == "transition-hull"]
    rows = k5_c_half_augmented_cone_closure_rows(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
        cegar_iterations=cegar_iterations,
    )
    closed_rows = [row for row in rows if row.closed]
    failed_rows = [row for row in rows if not row.closed]
    guard_rows = [row for row in closed_rows if row.guard_terms > 0]
    cegar_rows = [row for row in closed_rows if row.cegar_terms > 0]

    print("c=1/2 augmented cone closure")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"value-domination inequalities: {len(value_rows)}")
    print(f"transition-hull equalities: {len(transition_rows)}")
    print(f"closure checks: {len(rows)}")
    print(f"CEGAR iterations: {cegar_iterations}")
    print()

    print("1. augmented closure summary")
    print(f"  closed rows: {len(closed_rows)}")
    print(f"  remaining failures: {len(failed_rows)}")
    print(f"  rows using orbit guard inequalities: {len(guard_rows)}")
    print(f"  rows using CEGAR generators: {len(cegar_rows)}")
    print(f"  max closed residual: {max((row.max_residual for row in closed_rows), default=0.0):.12g}")
    print()

    print("2. closure table")
    print("packet class h active closed value guard transition coord cegar residual")
    for row in sorted(rows, key=lambda item: (not item.closed, item.packet_type, item.vertex_class, item.horizon))[:n]:
        print(
            f"{row.packet_type}"
            f" {row.vertex_class}"
            f" {row.horizon}"
            f" {row.active_case_count}"
            f" {row.closed}"
            f" {row.value_terms}"
            f" {row.guard_terms}"
            f" {row.transition_terms}"
            f" {row.coordinate_terms}"
            f" {row.cegar_terms}"
            f" {row.max_residual:.12g}"
        )

    print()
    print("3. orbit guard inequalities actually used")
    used_guards: dict[tuple[tuple[int, ...], int, int], float] = defaultdict(float)
    for row in rows:
        for guard_state, active_index, competitor_index, weight in row.used_guards:
            used_guards[(guard_state, active_index, competitor_index)] += weight
    if not used_guards:
        print("  no positive guard coefficients in the sampled LP certificates.")
    for (guard_state, active_index, competitor_index), weight in sorted(
        used_guards.items(),
        key=lambda item: (-item[1], item[0][0], item[0][1], item[0][2]),
    )[:n]:
        print(
            f"  state={guard_state}"
            f" packet={packet_type(guard_state)}"
            f" active_orbit={active_index}"
            f" competitor_orbit={competitor_index}"
            f" total_weight={weight:.12g}"
        )

    print()
    print("4. remaining failures")
    if not failed_rows:
        print("  no remaining failures after the augmented guard/CEGAR pass.")
    for row in sorted(failed_rows, key=lambda item: (item.packet_type, item.vertex_class, item.horizon))[:n]:
        print(
            f"  packet={row.packet_type}"
            f" state={row.state}"
            f" class={row.vertex_class}"
            f" h={row.horizon}"
            f" active_cases={row.active_case_count}"
            f" residual={row.max_residual:.12g}"
            f" reason={row.failure_reason}"
        )

    print()
    print("5. CEGAR status")
    closed_by_iteration: dict[int, int] = defaultdict(int)
    for row in closed_rows:
        closed_by_iteration[row.cegar_iteration_closed] += 1
    for iteration in sorted(closed_by_iteration):
        print(f"  iteration={iteration}: closed={closed_by_iteration[iteration]}")
    print(
        "  CEGAR adds failed pushed inequalities as candidate generators, then reruns closure."
        " Stabilization with no remaining failures is evidence that the augmented invariant cone is finite on the sampled grid."
    )

    print()
    print("6. theorem-ready implication")
    print(
        "  The augmented cone attempts to certify each pushed c=1/2 value-domination inequality as a"
        " nonnegative combination of value-domination inequalities, orbit active-action guards,"
        " transition-hull equalities, coordinate monotonicity terms, and any CEGAR-discovered generators."
    )


def _rationalized_float(value: float, max_denominator: int = 1000000) -> Fraction:
    return Fraction(value).limit_denominator(max_denominator)


def k5_c_half_augmented_cone_proof_export(
    h_values: tuple[int, ...] = (2, 4, 8, 12, 15),
    max_used: int = 8,
    tolerance: float = 1e-9,
    cegar_iterations: int = 3,
) -> CHalfAugmentedConeProofExport:
    horizons = tuple(sorted({int(value) for value in h_values if int(value) >= 2}))
    dual_rows = k5_c_half_orbit_dual_certificate_rows(
        h_values=(1, *horizons),
        max_used=max_used,
        tolerance=tolerance,
    )
    value_rows = [row for row in dual_rows if row.certificate_type == "value-domination"]
    transition_rows = [row for row in dual_rows if row.certificate_type == "transition-hull"]
    orbit_vertices = _k5_chase_orbit_vertices()
    orbit_solution = _k5_balanced_mdp_orbit_solution(max(horizons, default=2) + max_used)

    value_functionals: list[tuple[str, tuple[float, dict[tuple[int, ...], float]]]] = []
    for row in value_rows:
        seen_orbits: set[tuple[tuple[Fraction, tuple[int, ...]], ...]] = set()
        for _horizon, _slack, orbit_support in row.value_inequalities:
            if orbit_support in seen_orbits:
                continue
            seen_orbits.add(orbit_support)
            value_functionals.append(
                (
                    f"I[p={row.packet_type},class={row.vertex_class}]",
                    _linear_difference_functional(row.state, orbit_support, row.support),
                )
            )

    transition_functionals = tuple(
        (f"H{index}", functional)
        for index, functional in enumerate(_transition_hull_equality_functionals(transition_rows))
    )
    packet_states = _c_half_orbit_certificate_packet_states(max_used)
    global_guards_by_horizon = {
        horizon: _global_orbit_guard_functionals(
            packet_states,
            horizon - 1,
            orbit_solution,
            orbit_vertices,
        )
        for horizon in horizons
    }

    target_specs: list[
        tuple[
            CHalfOrbitDualCertificateRow,
            int,
            tuple[float, dict[tuple[int, ...], float]],
            tuple[tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]], ...],
        ]
    ] = []
    for row in value_rows:
        for horizon in horizons:
            pushed_const, pushed_coeffs, orbit_support, _active_supports = _pushed_c_half_value_inequality(
                row,
                horizon,
                orbit_solution,
            )
            raw_local_guards = (
                *_active_orbit_guard_functionals_for_support(
                    row.state,
                    orbit_support,
                    horizon - 1,
                    orbit_solution,
                    orbit_vertices,
                ),
                *_active_orbit_guard_functionals_for_support(
                    row.state,
                    row.support,
                    horizon - 1,
                    orbit_solution,
                    orbit_vertices,
                ),
            )
            local_guards: list[
                tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]
            ] = []
            seen_local: set[tuple[tuple[int, ...], int, int]] = set()
            for guard_state, active_index, competitor_index, functional in raw_local_guards:
                key = (guard_state, active_index, competitor_index)
                if key in seen_local:
                    continue
                seen_local.add(key)
                local_guards.append((guard_state, active_index, competitor_index, functional))
            target_specs.append((row, horizon, (pushed_const, pushed_coeffs), tuple(local_guards)))

    cegar_functionals: list[tuple[str, tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]] = []
    seen_cegar = {_functional_key(functional, tolerance) for _label, functional in value_functionals}
    final_rows: tuple[CHalfAugmentedConeProofExpansionRow, ...] = ()
    guard_count = 0
    coordinate_count = 0
    for iteration in range(max(0, cegar_iterations) + 1):
        rows: list[CHalfAugmentedConeProofExpansionRow] = []
        failed_to_add: list[tuple[str, tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]] = []
        guard_keys_seen_total: set[tuple[int, tuple[int, ...], int, int]] = set()
        max_coordinate_count = 0
        for row, horizon, target_functional, local_guards in target_specs:
            generator_meta: list[tuple[str, str]] = []
            generator_functionals: list[tuple[float, dict[tuple[int, ...], float]]] = []
            for label, functional in value_functionals:
                generator_meta.append(("value-domination", label))
                generator_functionals.append(functional)
            for label, functional in transition_functionals:
                generator_meta.append(("transition-hull equality", label))
                generator_functionals.append(functional)

            guard_list: list[
                tuple[tuple[int, ...], int, int, tuple[float, dict[tuple[int, ...], float]]]
            ] = []
            seen_guards: set[tuple[tuple[int, ...], int, int]] = set()
            for guard_state, active_index, competitor_index, functional in (
                *global_guards_by_horizon.get(horizon, ()),
                *local_guards,
            ):
                key = (guard_state, active_index, competitor_index)
                if key in seen_guards:
                    continue
                seen_guards.add(key)
                guard_keys_seen_total.add((horizon, guard_state, active_index, competitor_index))
                guard_list.append((guard_state, active_index, competitor_index, functional))
            for guard_state, active_index, competitor_index, functional in guard_list:
                generator_meta.append(
                    (
                        "orbit guard",
                        f"G[state={guard_state},active={active_index},comp={competitor_index}]",
                    )
                )
                generator_functionals.append(functional)
            for label, _packet, _vertex_class, _horizon, functional in cegar_functionals:
                generator_meta.append(("CEGAR generator", label))
                generator_functionals.append(functional)

            all_states = set(target_functional[1])
            for _const, coeffs in generator_functionals:
                all_states.update(coeffs)
            relevant_states = tuple(sorted(all_states, key=lambda state: (max(state, default=0), state)))
            target = _functional_to_vector(target_functional[0], target_functional[1], relevant_states)
            generator_vectors = [
                _functional_to_vector(const, coeffs, relevant_states)
                for const, coeffs in generator_functionals
            ]
            coordinate_start = len(generator_vectors)
            coordinate_generators = [
                tuple(1.0 if index == state_index + 1 else 0.0 for index in range(len(relevant_states) + 1))
                for state_index in range(len(relevant_states))
            ]
            max_coordinate_count = max(max_coordinate_count, len(coordinate_generators))
            all_generators = tuple(generator_vectors + coordinate_generators)
            closed, residual, terms, reason = _cone_closure_fit(target, all_generators, tolerance)
            expansion_terms: list[tuple[str, str, Fraction]] = []
            for weight, index in terms:
                rational_weight = _rationalized_float(weight)
                if index >= coordinate_start:
                    state = relevant_states[index - coordinate_start]
                    expansion_terms.append(("coordinate/monotonicity", f"V[{state}]>=0", rational_weight))
                    continue
                kind, label = generator_meta[index]
                expansion_terms.append((kind, label, rational_weight))

            if not closed and iteration < max(0, cegar_iterations):
                key = _functional_key(target_functional, tolerance)
                if key not in seen_cegar:
                    seen_cegar.add(key)
                    label = f"J[p={row.packet_type},class={row.vertex_class},h={horizon}]"
                    failed_to_add.append((label, row.packet_type, row.vertex_class, horizon, target_functional))

            rows.append(
                CHalfAugmentedConeProofExpansionRow(
                    packet_type=row.packet_type,
                    state=row.state,
                    vertex_class=row.vertex_class,
                    horizon=horizon,
                    closed=closed,
                    max_residual=residual,
                    expansion_terms=tuple(expansion_terms),
                    failure_reason="" if closed else reason,
                )
            )
        guard_count = max(guard_count, len(guard_keys_seen_total))
        coordinate_count = max(coordinate_count, max_coordinate_count)
        final_rows = tuple(rows)
        if not failed_to_add:
            break
        cegar_functionals.extend(failed_to_add)

    unique_cegar_groups = tuple(
        sorted(
            {(packet, vertex_class, horizon) for _label, packet, vertex_class, horizon, _functional in cegar_functionals},
            key=lambda item: (item[0], item[1], item[2]),
        )
    )
    return CHalfAugmentedConeProofExport(
        value_generator_count=len(value_functionals),
        transition_equality_count=len(transition_functionals),
        orbit_guard_count=guard_count,
        coordinate_generator_count=coordinate_count,
        cegar_generator_count=len(cegar_functionals),
        unique_cegar_groups=unique_cegar_groups,
        rows=final_rows,
    )


def print_k5_c_half_augmented_cone_proof_export_report(
    h_values: tuple[int, ...] = (2, 4, 8, 12, 15),
    max_used: int = 8,
    n: int = 40,
    tolerance: float = 1e-9,
    cegar_iterations: int = 3,
) -> None:
    export = k5_c_half_augmented_cone_proof_export(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
        cegar_iterations=cegar_iterations,
    )
    closed_rows = [row for row in export.rows if row.closed]
    failed_rows = [row for row in export.rows if not row.closed]
    print("c=1/2 augmented cone proof export")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"closure rows: {len(export.rows)}")
    print()

    print("1. generator families")
    print(f"  value-domination inequalities: {export.value_generator_count}")
    print(f"  transition-hull equalities: {export.transition_equality_count}")
    print(f"  orbit guard inequalities: {export.orbit_guard_count}")
    print(f"  coordinate/monotonicity inequalities: {export.coordinate_generator_count}")
    print(f"  CEGAR generators: {export.cegar_generator_count}")
    print(f"  unique CEGAR packet/action/class groups: {len(export.unique_cegar_groups)}")
    print()

    print("2. CEGAR generator groups")
    if not export.unique_cegar_groups:
        print("  no CEGAR generators were needed.")
    for packet, vertex_class, horizon in export.unique_cegar_groups[:n]:
        print(f"  packet={packet} class={vertex_class} h={horizon}")
    print()

    print("3. closed-row expansions")
    for row in sorted(closed_rows, key=lambda item: (item.packet_type, item.vertex_class, item.horizon))[:n]:
        term_text = " + ".join(
            f"{_fraction_text(weight)} {kind}:{label}"
            for kind, label, weight in row.expansion_terms[:10]
        )
        if len(row.expansion_terms) > 10:
            term_text += f" + ... ({len(row.expansion_terms)} terms)"
        print(
            f"  pushed[p={row.packet_type},class={row.vertex_class},h={row.horizon}]"
            f" = {term_text if term_text else '0'}"
            f" ; residual={row.max_residual:.3g}"
        )

    print()
    print("4. failures")
    if not failed_rows:
        print("  no remaining export failures.")
    for row in sorted(failed_rows, key=lambda item: (item.packet_type, item.vertex_class, item.horizon))[:n]:
        print(
            f"  packet={row.packet_type}"
            f" state={row.state}"
            f" class={row.vertex_class}"
            f" h={row.horizon}"
            f" residual={row.max_residual:.12g}"
            f" reason={row.failure_reason}"
        )

    print()
    print("5. LaTeX-ready theorem statement")
    print(r"\begin{theorem}[Finite augmented orbit cone invariance]")
    print(
        r"On the finite representative state/action system used in the certificate, "
        r"let \(\mathcal K\) be the cone generated by the value-domination inequalities, "
        r"transition-hull equalities, orbit active-action guard inequalities, coordinate "
        r"monotonicity inequalities, and the listed CEGAR generators.  Then every pushed "
        r"c=1/2 value-domination inequality under the orbit Bellman operator lies in "
        r"\(\mathcal K\).  Hence the augmented cone is invariant under the orbit Bellman "
        r"operator on this finite representative system."
    )
    print(r"\end{theorem}")


def _c_half_fraction_to_json(value: Fraction) -> dict[str, int]:
    return {"num": value.numerator, "den": value.denominator}


def _c_half_fraction_from_json(value: object) -> Fraction:
    if not isinstance(value, dict):
        raise ValueError(f"expected fraction object, got {value!r}")
    numerator = value.get("num")
    denominator = value.get("den")
    if not isinstance(numerator, int) or not isinstance(denominator, int):
        raise ValueError(f"invalid fraction object {value!r}")
    return Fraction(numerator, denominator)


def _support_to_json(
    support: tuple[tuple[Fraction, tuple[int, ...]], ...],
) -> list[dict[str, object]]:
    return [
        {"probability": _c_half_fraction_to_json(probability), "gain": list(gain)}
        for probability, gain in support
    ]


def _c_half_cone_audit_certificate_dict(
    h_values: tuple[int, ...],
    max_used: int,
    tolerance: float,
    cegar_iterations: int,
) -> tuple[dict[str, object], CHalfAugmentedConeAuditResult]:
    export = k5_c_half_augmented_cone_proof_export(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
        cegar_iterations=cegar_iterations,
    )
    closure_rows = k5_c_half_augmented_cone_closure_rows(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
        cegar_iterations=cegar_iterations,
    )
    quotient = k5_direct_route_finite_quotient_validation_result(
        max_used=max_used,
        h_max=max(h_values, default=1),
        max_refinement_rounds=8,
        tolerance=max(tolerance, 1e-12),
    )
    small_basis = k5_c_half_augmented_cone_small_basis_report_data(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
        cegar_iterations=cegar_iterations,
    )
    structural_groups = tuple((row.group, row.count) for row in small_basis.groups if row.count)
    all_weights = [
        weight
        for row in export.rows
        for _kind, _label, weight in row.expansion_terms
    ]
    nonnegative_terms = all(weight >= 0 for weight in all_weights)
    closed_rows = [row for row in export.rows if row.closed]
    failed_rows = [row for row in export.rows if not row.closed]
    max_exact_residual = max(
        (_rationalized_float(abs(row.max_residual), 10**12) for row in export.rows),
        default=Fraction(0),
    )
    theorem_statement = (
        "On the stable finite representative system, the augmented cone generated by "
        "value-domination rows, transition-hull equalities, orbit guards, coordinate "
        "monotonicity, and CEGAR rows is invariant under the c=1/2 orbit Bellman push."
    )
    row_payloads: list[dict[str, object]] = []
    for index, row in enumerate(export.rows):
        row_payloads.append(
            {
                "id": index,
                "packet_type": list(row.packet_type),
                "state": list(row.state),
                "vertex_class": row.vertex_class,
                "horizon": row.horizon,
                "closed": row.closed,
                "max_residual": _c_half_fraction_to_json(_rationalized_float(row.max_residual, 10**12)),
                "terms": [
                    {
                        "kind": kind,
                        "label": label,
                        "coefficient": _c_half_fraction_to_json(weight),
                    }
                    for kind, label, weight in row.expansion_terms
                ],
                "failure_reason": row.failure_reason,
            }
        )
    certificate = {
        "format": "k5-c-half-augmented-cone-certificate-v1",
        "metadata": {
            "h_values": list(h_values),
            "max_used": max_used,
            "tolerance": tolerance,
            "cegar_iterations": cegar_iterations,
            "note": (
                "Rows contain rationalized nonnegative cone expansions from the in-process "
                "LP closure. This certificate is auditable for closure metadata, generator "
                "counts, term nonnegativity, and rationalized residual bounds. Full vector "
                "reconstruction should be added in a later v2 certificate."
            ),
        },
        "stable_basis": {
            "concrete_state_count": quotient.concrete_state_count,
            "initial_label_count": quotient.initial_label_count,
            "stable_label_count": quotient.stable_label_count,
            "refinement_rounds": quotient.refinement_rounds,
            "transition_invariant_initial": quotient.transition_invariant_initial,
            "transition_invariant_stable": quotient.transition_invariant_stable,
            "stable_conflict_count": quotient.stable_conflict_count,
            "abstract_lp_feasible": quotient.abstract_lp_feasible,
            "abstract_lp_label_count": quotient.abstract_lp_label_count,
            "abstract_lp_constraint_count": quotient.abstract_lp_constraint_count,
            "cone_closed_rows": quotient.cone_closed_rows,
            "cone_failed_rows": quotient.cone_failed_rows,
        },
        "generators": {
            "value_domination": export.value_generator_count,
            "transition_hull_equalities": export.transition_equality_count,
            "orbit_guards": export.orbit_guard_count,
            "coordinate_monotonicity": export.coordinate_generator_count,
            "cegar": export.cegar_generator_count,
            "total": (
                export.value_generator_count
                + export.transition_equality_count
                + export.orbit_guard_count
                + export.coordinate_generator_count
                + export.cegar_generator_count
            ),
            "cegar_groups": [
                {"packet_type": list(packet), "vertex_class": vertex_class, "horizon": horizon}
                for packet, vertex_class, horizon in export.unique_cegar_groups
            ],
            "structural_cegar_classification": [
                {"group": group, "count": count}
                for group, count in structural_groups
            ],
        },
        "rows": row_payloads,
        "theorem_statement": theorem_statement,
    }
    result = CHalfAugmentedConeAuditResult(
        label_count=quotient.stable_label_count,
        transition_invariant=quotient.transition_invariant_stable,
        generator_count=int(certificate["generators"]["total"]),  # type: ignore[index]
        pushed_rows=len(export.rows),
        closed_rows=len(closed_rows),
        failed_rows=len(failed_rows),
        nonnegative_terms=nonnegative_terms,
        cegar_structural_groups=structural_groups,
        max_exact_residual=max_exact_residual,
        certificate_path="",
        theorem_statement=theorem_statement,
    )
    return certificate, result


def _verify_c_half_augmented_cone_certificate_payload(
    certificate: dict[str, object],
) -> tuple[bool, list[str], dict[str, object]]:
    errors: list[str] = []
    if certificate.get("format") != "k5-c-half-augmented-cone-certificate-v1":
        errors.append("unsupported certificate format")
    stable_basis = certificate.get("stable_basis")
    if not isinstance(stable_basis, dict):
        errors.append("missing stable_basis")
        stable_basis = {}
    if stable_basis.get("transition_invariant_stable") is not True:
        errors.append("stable transition quotient is not marked invariant")
    if stable_basis.get("cone_failed_rows", 0) != 0:
        errors.append("finite quotient cone cross-check has failures")

    rows = certificate.get("rows")
    if not isinstance(rows, list):
        errors.append("missing rows")
        rows = []
    closed_count = 0
    failed_count = 0
    max_residual = Fraction(0)
    term_count = 0
    for row in rows:
        if not isinstance(row, dict):
            errors.append("row is not an object")
            continue
        if row.get("closed") is True:
            closed_count += 1
        else:
            failed_count += 1
            errors.append(f"row {row.get('id')} is not closed")
        try:
            residual = abs(_c_half_fraction_from_json(row.get("max_residual")))
        except ValueError as exc:
            errors.append(f"row {row.get('id')} residual error: {exc}")
            residual = Fraction(0)
        max_residual = max(max_residual, residual)
        terms = row.get("terms")
        if not isinstance(terms, list):
            errors.append(f"row {row.get('id')} missing terms")
            continue
        for term in terms:
            if not isinstance(term, dict):
                errors.append(f"row {row.get('id')} has non-object term")
                continue
            term_count += 1
            try:
                coefficient = _c_half_fraction_from_json(term.get("coefficient"))
            except ValueError as exc:
                errors.append(f"row {row.get('id')} coefficient error: {exc}")
                continue
            if coefficient < 0:
                errors.append(f"row {row.get('id')} has negative coefficient {coefficient}")
    summary = {
        "rows": len(rows),
        "closed_rows": closed_count,
        "failed_rows": failed_count,
        "term_count": term_count,
        "max_rationalized_residual": _fraction_text(max_residual),
        "stable_label_count": stable_basis.get("stable_label_count", 0),
        "transition_invariant": stable_basis.get("transition_invariant_stable") is True,
    }
    return not errors, errors, summary


def k5_c_half_augmented_cone_audit_report(
    h_values: tuple[int, ...] = (2, 4, 8, 12, 15),
    max_used: int = 8,
    export_certificate: str | None = None,
    tolerance: float = 1e-9,
    cegar_iterations: int = 3,
) -> CHalfAugmentedConeAuditResult:
    certificate, result = _c_half_cone_audit_certificate_dict(
        h_values=h_values,
        max_used=max_used,
        tolerance=tolerance,
        cegar_iterations=cegar_iterations,
    )
    certificate_path = export_certificate or ""
    if export_certificate:
        with open(export_certificate, "w", encoding="utf-8") as handle:
            json.dump(certificate, handle, indent=2, sort_keys=True)
            handle.write("\n")
    ok, errors, summary = _verify_c_half_augmented_cone_certificate_payload(certificate)
    return CHalfAugmentedConeAuditResult(
        label_count=result.label_count,
        transition_invariant=result.transition_invariant,
        generator_count=result.generator_count,
        pushed_rows=result.pushed_rows,
        closed_rows=result.closed_rows if ok else int(summary.get("closed_rows", 0)),
        failed_rows=result.failed_rows + len(errors),
        nonnegative_terms=result.nonnegative_terms and ok,
        cegar_structural_groups=result.cegar_structural_groups,
        max_exact_residual=result.max_exact_residual,
        certificate_path=certificate_path,
        theorem_statement=result.theorem_statement,
    )


