    print(
        r"  Taking the maximum over balanced actions gives the low-gap supersolution"
        r" \["
        r"   T_{\rm full}^{bal}(V_{\rm orbit,t-1}+A)(x)"
        r"   \le V_{\rm orbit,t}(x)+A(x)+\frac1t."
        r" \]"
    )
    print(
        r"  The six old schemas are recovered as a corollary: they are simply the"
        r" six visible face-transition families in this packet-face maximum-principle"
        r" proof, not separate proof principles."
    )
    print()

    print("LaTeX-ready theorem statement")
    print(
        r"  Theorem (low-gap packet-face maximum principle)."
        r" On the K=5 low-gap packet-face quotient, after permutation-complement"
        r" quotienting of balanced actions, all curvature-gap generators are"
        r" nonpositive up to the harmonic source \(1/t\). Equivalently,"
        r" \(V_{\rm orbit}+A+H_t\) is a Bellman supersolution for the full"
        r" balanced adversary MDP on the low-gap region."
    )


