def _large_gap_merge_paths_from_inputs(
    certificate_paths: Sequence[str] | None = None,
    certificate_dir: str | None = None,
    manifest_path: str | None = None,
) -> tuple[str, ...]:
    paths: list[str] = []
    if certificate_paths:
        paths.extend(str(path) for path in certificate_paths)
    if certificate_dir:
        for name in sorted(os.listdir(certificate_dir)):
            if not name.endswith(".json"):
                continue
            if not name.startswith("k5_large_gap_barrier_certificate_"):
                continue
            paths.append(os.path.join(certificate_dir, name))
    if manifest_path:
        with open(manifest_path, encoding="utf-8") as handle:
            manifest = json.load(handle)
        if manifest.get("format") == "k5-large-gap-barrier-streaming-manifest-v1":
            paths.extend(str(path) for path in manifest.get("chunk_paths", []))
        else:
            paths.append(manifest_path)
    return tuple(dict.fromkeys(paths))


def print_k5_large_gap_barrier_merge_verify_report(
    certificate_paths: Sequence[str] | None = None,
    certificate_dir: str | None = None,
    manifest_path: str | None = None,
) -> None:
    paths = _large_gap_merge_paths_from_inputs(
        certificate_paths=certificate_paths,
        certificate_dir=certificate_dir,
        manifest_path=manifest_path,
    )
    ok, errors, merged = _merge_large_gap_certificate_paths(paths)
    print("k5 large-gap barrier merge verifier")
    print()
    print(f"chunks: {len(paths)}")
    print(f"ok: {ok}")
    for key, value in merged.items():
        print(f"{key}: {value}")
    print()
    print("chunk paths")
    for path in paths[:40]:
        print(f"  {path}")
    if len(paths) > 40:
        print(f"  ... omitted {len(paths) - 40} chunk paths.")
    print()
    print("errors")
    if not errors:
        print("  none")
    for error in errors[:40]:
        print(f"  {error}")


