def _one_dimensional_gap_transition(
    row: K5LargeGapInfluenceConeCertificateRow,
    tolerance: float,
) -> tuple[tuple[str, float], ...]:
    weights: dict[str, float] = defaultdict(float)
    for coefficient, successor in row.delta_terms:
        coefficient_float = float(coefficient)
        if coefficient_float <= tolerance:
            continue
        successor_gap = _gap_at_index(successor, row.gap_index)
        if successor_gap < 2:
            weights["boundary"] += coefficient_float
        else:
            delta = successor_gap - row.gap_value
            label = f"r{delta:+d}" if delta else "r"
            weights[label] += coefficient_float
    return tuple(sorted(weights.items(), key=lambda item: item[0]))


def _one_dimensional_barrier_value(kind: str, gap_value: int, b_shift: float) -> float:
    denominator = gap_value + b_shift
    if denominator <= 0:
        return float("inf")
    if kind == "square":
        return 1.0 / (denominator * denominator)
    if kind == "linear":
        return 1.0 / denominator
    raise ValueError(f"unknown one-dimensional barrier kind: {kind}")


def _fit_one_dimensional_barrier_for_group(
    group: list[K5LargeGapInfluenceConeCertificateRow],
    tolerance: float,
) -> tuple[str, float, float, bool, K5LargeGapInfluenceConeCertificateRow]:
    candidates: list[tuple[float, str, float, float, bool, K5LargeGapInfluenceConeCertificateRow]] = []
    for kind in ("square", "linear"):
        for b_shift in (1.0, 1.5, 2.0, 3.0, 4.0):
            required_a = 0.0
            possible = True
            worst_row = group[0]
            for row in group:
                source = row.source_scaled / ((row.gap_value + 1) ** 2)
                denominator = _one_dimensional_barrier_value(kind, row.gap_value, b_shift)
                for coefficient, successor in row.delta_terms:
                    coefficient_float = float(coefficient)
                    if coefficient_float <= tolerance:
                        continue
                    successor_gap = _gap_at_index(successor, row.gap_index)
                    if successor_gap >= 2:
                        denominator -= coefficient_float * _one_dimensional_barrier_value(kind, successor_gap, b_shift)
                if denominator <= tolerance:
                    possible = False
                    required_a = float("inf")
                    worst_row = row
                    break
                row_required = source / denominator
                if row_required > required_a:
                    required_a = row_required
                    worst_row = row
            if not possible:
                candidates.append((float("inf"), f"A/(r+{b_shift:g})^{2 if kind == 'square' else 1}", required_a, float("inf"), False, worst_row))
                continue
            max_residual = float("-inf")
            worst_residual_row = worst_row
            for row in group:
                source = row.source_scaled / ((row.gap_value + 1) ** 2)
                lhs = source
                for coefficient, successor in row.delta_terms:
                    coefficient_float = float(coefficient)
                    if coefficient_float <= tolerance:
                        continue
                    successor_gap = _gap_at_index(successor, row.gap_index)
                    if successor_gap >= 2:
                        lhs += coefficient_float * required_a * _one_dimensional_barrier_value(kind, successor_gap, b_shift)
                rhs = required_a * _one_dimensional_barrier_value(kind, row.gap_value, b_shift)
                residual = lhs - rhs
                if residual > max_residual:
                    max_residual = residual
                    worst_residual_row = row
            closes = max_residual <= tolerance and required_a < float("inf")
            candidates.append(
                (
                    required_a,
                    f"{required_a:.6g}/(r+{b_shift:g})^{2 if kind == 'square' else 1}",
                    required_a,
                    max_residual,
                    closes,
                    worst_residual_row,
                )
            )
    return min(candidates, key=lambda item: (not item[4], item[0], item[3]))[1:]


def k5_large_gap_one_dimensional_barrier_rows(
    h_max: int = 15,
    max_used: int = 12,
    h_values: tuple[int, ...] | None = None,
    tolerance: float = 1e-10,
) -> tuple[K5LargeGapOneDimensionalBarrierRow, ...]:
    cert_rows, _fitted_b, _feasible, _message = k5_large_gap_influence_cone_certificate_rows(
        h_max=h_max,
        max_used=max_used,
        h_values=h_values,
        tolerance=tolerance,
    )
    grouped: dict[tuple[str, tuple[int, int], tuple[int, int]], list[K5LargeGapInfluenceConeCertificateRow]] = defaultdict(list)
    for row in cert_rows:
        if row.gap_value >= 2:
            grouped[(row.family, row.full_regime, row.orbit_regime)].append(row)

    output_rows: list[K5LargeGapOneDimensionalBarrierRow] = []
    for (family, full_regime, orbit_regime), group in grouped.items():
        transition_weights: dict[str, float] = defaultdict(float)
        for row in group:
            for label, weight in _one_dimensional_gap_transition(row, tolerance):
                transition_weights[label] = max(transition_weights[label], weight)
        psi_name, barrier_constant, max_residual, closes, worst_row = _fit_one_dimensional_barrier_for_group(group, tolerance)
        output_rows.append(
            K5LargeGapOneDimensionalBarrierRow(
                family=family,
                full_regime=full_regime,
                orbit_regime=orbit_regime,
                witness_count=len(group),
                effective_gap=f"gap_index={worst_row.gap_index}",
                gap_transition=tuple(sorted(transition_weights.items(), key=lambda item: item[0])),
                max_source=max(row.source_scaled / ((row.gap_value + 1) ** 2) for row in group),
                psi_name=psi_name,
                barrier_constant=barrier_constant,
                max_residual=max_residual,
                closes=closes,
                worst_horizon=worst_row.horizon,
                worst_gap=worst_row.gap_value,
                worst_state=worst_row.state,
            )
        )
    return tuple(
        sorted(
            output_rows,
            key=lambda row: (not row.closes, row.family, row.full_regime, row.orbit_regime),
        )
    )


def print_k5_large_gap_one_dimensional_barrier_report(
    h_max: int = 15,
    max_used: int = 12,
    h_values: tuple[int, ...] | None = None,
    n: int = 80,
    tolerance: float = 1e-10,
) -> None:
    rows = k5_large_gap_one_dimensional_barrier_rows(
        h_max=h_max,
        max_used=max_used,
        h_values=h_values,
        tolerance=tolerance,
    )
    family_success = {
        family: all(row.closes for row in rows if row.family == family)
        for family in _INFLUENCE_FAMILIES
    }
    print("k5 large-gap one-dimensional barrier report")
    print()
    print(f"h_max: {h_max}")
    print(f"h_values: {_k5_balanced_mdp_h_values(h_values, h_max)}")
    print(f"max_used: {max_used}")
    print(f"active family/regime rows: {len(rows)}")
    print()

    print("1. family-level summary")
    for family in _INFLUENCE_FAMILIES:
        family_rows = [row for row in rows if row.family == family]
        print(
            f"  {family}: regimes={len(family_rows)}"
            f" all_close={family_success.get(family, True)}"
            f" max_A={max((row.barrier_constant for row in family_rows), default=0.0):.12g}"
            f" max_residual={max((row.max_residual for row in family_rows), default=0.0):.12g}"
        )
    print()

    print("2. one-dimensional regime table")
    print("family full orbit effective_gap gap_transition source psi inequality")
    for row in rows[:n]:
        transition = ", ".join(f"{label}:{weight:.6g}" for label, weight in row.gap_transition) or "none"
        print(
            f"{row.family}"
            f" {row.full_regime[0]}->{row.full_regime[1]}"
            f" {row.orbit_regime[0]}->{row.orbit_regime[1]}"
            f" {row.effective_gap}"
            f" [{transition}]"
            f" source<={row.max_source:.6g}"
            f" psi={row.psi_name}"
            f" closes={row.closes}"
            f" residual={row.max_residual:.3g}"
        )
    if len(rows) > n:
        print(f"  ... omitted {len(rows) - n} rows; increase -n to print more.")
    print()

    print("3. worst remaining cases")
    failures = [row for row in rows if not row.closes]
    if not failures:
        print("  no sampled one-dimensional barrier failures.")
    for row in sorted(failures, key=lambda item: (-item.max_residual, item.family))[:n]:
        print(
            f"  FAILURE {row.family}"
            f" full={row.full_regime[0]}->{row.full_regime[1]}"
            f" orbit={row.orbit_regime[0]}->{row.orbit_regime[1]}"
            f" h={row.worst_horizon}"
            f" r={row.worst_gap}"
            f" state={row.worst_state}"
            f" psi={row.psi_name}"
            f" residual={row.max_residual:.12g}"
        )
    print()

    print("4. theorem candidate")
    if all(family_success.values()):
        print(
            "  The sampled active regimes are covered by one-dimensional barriers. "
            "A proof can replace the row certificate by the displayed six-family transition/source inequalities."
        )
    else:
        print(
            "  Some sampled regimes are not closed by the tested one-dimensional barriers. "
            "The failure table identifies the regimes needing a richer state variable or boundary source lemma."
        )


def _large_gap_state_family_label(state: tuple[int, ...], gap_index: int) -> str:
    packet = packet_type(state)
    gaps = _gap_vector(state)
    nonzero = tuple(index for index, gap in enumerate(gaps) if gap > 0)
    return f"packet={packet}, active_gap={gap_index}, nonzero_gaps={nonzero}"


def _secondary_gap_value(state: tuple[int, ...], gap_index: int) -> int:
    gaps = _gap_vector(state)
    candidates = [gap for index, gap in enumerate(gaps) if index != gap_index and gap > 0]
    return max(candidates, default=0)


def _large_gap_two_gap_value(state: tuple[int, ...], gap_index: int, a_const: Fraction, b_const: Fraction) -> float:
    r_value = _gap_at_index(state, gap_index)
    s_value = _secondary_gap_value(state, gap_index)
    return float(a_const) / ((r_value + 1) ** 2) + float(b_const) / ((s_value + 1) ** 2)


def _large_gap_packet_bonus_value(state: tuple[int, ...], packet: tuple[int, ...], bonus: Fraction) -> float:
    return float(bonus) if packet_type(state) == packet else 0.0


def _large_gap_tied_leader_value(state: tuple[int, ...], lambda_value: Fraction) -> float:
    return float(lambda_value * packet_type(state)[0])


def _barrier_residual_for_certificate_row(
    row: K5LargeGapInfluenceConeCertificateRow,
    value_fn: Callable[[tuple[int, ...]], float],
    tolerance: float,
) -> float:
    source = row.source_scaled / ((row.gap_value + 1) ** 2)
    lhs = source
    for coefficient, successor in row.delta_terms:
        coefficient_float = float(coefficient)
        if coefficient_float <= tolerance:
            continue
        lhs += coefficient_float * value_fn(successor)
    return lhs - value_fn(row.state)


def _all_rows_close_barrier(
    rows: list[K5LargeGapInfluenceConeCertificateRow],
    value_fn: Callable[[tuple[int, ...]], float],
    tolerance: float,
) -> tuple[bool, float, K5LargeGapInfluenceConeCertificateRow]:
    worst_row = rows[0]
    max_residual = float("-inf")
    for row in rows:
        residual = _barrier_residual_for_certificate_row(row, value_fn, tolerance)
        if residual > max_residual:
            max_residual = residual
            worst_row = row
    return max_residual <= tolerance, max_residual, worst_row


def _find_two_gap_constants(
    rows: list[K5LargeGapInfluenceConeCertificateRow],
    tolerance: float,
) -> tuple[bool, tuple[tuple[str, Fraction], ...], float, K5LargeGapInfluenceConeCertificateRow]:
    constants = (Fraction(0), Fraction(1, 10), Fraction(1, 4), Fraction(1, 2), Fraction(1), Fraction(2), Fraction(5))
    best: tuple[bool, tuple[tuple[str, Fraction], ...], float, K5LargeGapInfluenceConeCertificateRow] | None = None
    for a_const in constants:
        for b_const in constants:
            closes, residual, worst = _all_rows_close_barrier(
                rows,
                lambda state, a_const=a_const, b_const=b_const, gap_index=rows[0].gap_index: _large_gap_two_gap_value(
                    state,
                    gap_index,
                    a_const,
                    b_const,
                ),
                tolerance,
            )
            candidate = (closes, (("A", a_const), ("B", b_const)), residual, worst)
            if best is None or (not best[0], sum(abs(float(value)) for _name, value in best[1]), best[2]) > (
                not closes,
                sum(abs(float(value)) for _name, value in candidate[1]),
                residual,
            ):
                best = candidate
    assert best is not None
    return best


def _find_packet_bonus(
    rows: list[K5LargeGapInfluenceConeCertificateRow],
    tolerance: float,
) -> tuple[bool, Fraction, float, K5LargeGapInfluenceConeCertificateRow]:
    packet = packet_type(rows[0].state)
    best: tuple[bool, Fraction, float, K5LargeGapInfluenceConeCertificateRow] | None = None
    for bonus in (Fraction(0), Fraction(1, 10), Fraction(1, 4), Fraction(1, 2), Fraction(1), Fraction(2), Fraction(5)):
        closes, residual, worst = _all_rows_close_barrier(
            rows,
            lambda state, packet=packet, bonus=bonus: _large_gap_packet_bonus_value(state, packet, bonus),
            tolerance,
        )
        candidate = (closes, bonus, residual, worst)
        if best is None or (not best[0], abs(float(best[1])), best[2]) > (not closes, abs(float(bonus)), residual):
            best = candidate
    assert best is not None
    return best


def _find_tied_leader_absorption(
    rows: list[K5LargeGapInfluenceConeCertificateRow],
    tolerance: float,
) -> tuple[bool, Fraction, float, K5LargeGapInfluenceConeCertificateRow]:
    best: tuple[bool, Fraction, float, K5LargeGapInfluenceConeCertificateRow] | None = None
    for lambda_value in _SIMPLE_BARRIER_LAMBDAS:
        closes, residual, worst = _all_rows_close_barrier(
            rows,
            lambda state, lambda_value=lambda_value: _large_gap_tied_leader_value(state, lambda_value),
            tolerance,
        )
        candidate = (closes, lambda_value, residual, worst)
        if best is None or (not best[0], abs(float(best[1])), best[2]) > (not closes, abs(float(lambda_value)), residual):
            best = candidate
    assert best is not None
    return best


def _large_gap_failure_analysis_from_group(
    task: tuple[
        tuple[str, tuple[int, ...], tuple[int, int], tuple[int, int], int, tuple[int, ...]],
        tuple[K5LargeGapInfluenceConeCertificateRow, ...],
        tuple[tuple[str, tuple[int, int], tuple[int, int], float], ...],
        float,
    ],
) -> K5LargeGapBarrierFailureAnalysisRow:
    (family, packet, full_regime, orbit_regime, gap_index, other_nonzero), group_tuple, one_d_residuals, tolerance = task
    group = list(group_tuple)
    two_gap_closes, two_gap_constants, two_gap_residual, two_gap_worst = _find_two_gap_constants(group, tolerance)
    packet_closes, packet_bonus, packet_residual, packet_worst = _find_packet_bonus(group, tolerance)
    tied_closes, tied_lambda, tied_residual, tied_worst = _find_tied_leader_absorption(group, tolerance)
    best_worst = max((two_gap_worst, packet_worst, tied_worst), key=lambda row: row.scaled_square)
    if two_gap_closes:
        suggested = "two-gap barrier"
        best_worst = two_gap_worst
    elif tied_closes:
        suggested = "absorb into tied-leader low-gap potential"
        best_worst = tied_worst
    elif packet_closes:
        suggested = "packet boundary-source bonus"
        best_worst = packet_worst
    else:
        suggested = "needs richer multi-block exchange state"
    one_d_residual = next(
        (
            residual
            for row_family, row_full, row_orbit, residual in one_d_residuals
            if row_family == family and row_full == full_regime and row_orbit == orbit_regime
        ),
        float("inf"),
    )
    return K5LargeGapBarrierFailureAnalysisRow(
        family=family,
        packet_type=packet,
        full_regime=full_regime,
        orbit_regime=orbit_regime,
        witness_count=len(group),
        state_family=_large_gap_state_family_label(group[0].state, gap_index),
        large_gap_index=gap_index,
        other_nonzero_gaps=other_nonzero,
        one_d_residual=one_d_residual,
        two_gap_closes=two_gap_closes,
        two_gap_constants=two_gap_constants,
        packet_bonus_closes=packet_closes,
        packet_bonus=packet_bonus,
        tied_leader_closes=tied_closes,
        tied_leader_lambda=tied_lambda,
        suggested_extension=suggested,
        worst_horizon=best_worst.horizon,
        worst_gap=best_worst.gap_value,
        worst_state=best_worst.state,
    )


def k5_large_gap_one_dimensional_failure_analysis_rows(
    h_max: int = 15,
    max_used: int = 12,
    h_values: tuple[int, ...] | None = None,
    tolerance: float = 1e-10,
    progress: bool = False,
    workers: int = 1,
) -> tuple[K5LargeGapBarrierFailureAnalysisRow, ...]:
    if progress:
        print("[large-gap failure] building one-dimensional barrier rows...", file=sys.stderr, flush=True)
    one_d_rows = k5_large_gap_one_dimensional_barrier_rows(
        h_max=h_max,
        max_used=max_used,
        h_values=h_values,
        tolerance=tolerance,
    )
    failed_keys = {
        (row.family, row.full_regime, row.orbit_regime)
        for row in one_d_rows
        if not row.closes and row.family in {"F3", "F4", "F6"}
    }
    if progress:
        print(
            f"[large-gap failure] failed F3/F4/F6 regimes: {len(failed_keys)}",
            file=sys.stderr,
            flush=True,
        )
        print("[large-gap failure] building influence cone certificate rows...", file=sys.stderr, flush=True)
    cert_rows, _fitted_b, _feasible, _message = k5_large_gap_influence_cone_certificate_rows(
        h_max=h_max,
        max_used=max_used,
        h_values=h_values,
        tolerance=tolerance,
    )
    grouped: dict[tuple[str, tuple[int, ...], tuple[int, int], tuple[int, int], int, tuple[int, ...]], list[K5LargeGapInfluenceConeCertificateRow]] = defaultdict(list)
    for row in cert_rows:
        key = (row.family, row.full_regime, row.orbit_regime)
        if key not in failed_keys:
            continue
        gaps = _gap_vector(row.state)
        other_nonzero = tuple(gap for index, gap in enumerate(gaps) if index != row.gap_index and gap > 0)
        grouped[(row.family, packet_type(row.state), row.full_regime, row.orbit_regime, row.gap_index, other_nonzero)].append(row)

    if progress:
        print(
            f"[large-gap failure] grouped certificate rows into {len(grouped)} state-family/regime groups.",
            file=sys.stderr,
            flush=True,
        )
    one_d_residuals = tuple(
        (row.family, row.full_regime, row.orbit_regime, row.max_residual)
        for row in one_d_rows
    )
    tasks = tuple((key, tuple(group), one_d_residuals, tolerance) for key, group in grouped.items())
    if workers > 1 and len(tasks) > 1:
        if progress:
            print(f"[large-gap failure] analyzing groups with {workers} worker processes...", file=sys.stderr, flush=True)
        context = get_context("spawn")
        with ProcessPoolExecutor(max_workers=workers, mp_context=context) as executor:
            output = list(executor.map(_large_gap_failure_analysis_from_group, tasks))
    else:
        output = []
        for index, task in enumerate(tasks, start=1):
            if progress:
                key = task[0]
                print(
                    f"[large-gap failure] analyzing group {index}/{len(tasks)}: {key[0]} packet={key[1]} full={key[2]} orbit={key[3]}",
                    file=sys.stderr,
                    flush=True,
                )
            output.append(_large_gap_failure_analysis_from_group(task))
    if progress:
        print("[large-gap failure] analysis complete.", file=sys.stderr, flush=True)
    return tuple(sorted(output, key=lambda row: (row.suggested_extension, row.family, row.packet_type, row.full_regime)))


def print_k5_large_gap_one_dimensional_failure_analysis_report(
    h_max: int = 15,
    max_used: int = 12,
    h_values: tuple[int, ...] | None = None,
    n: int = 80,
    tolerance: float = 1e-10,
    progress: bool = False,
    workers: int = 1,
) -> None:
    rows = k5_large_gap_one_dimensional_failure_analysis_rows(
        h_max=h_max,
        max_used=max_used,
        h_values=h_values,
        tolerance=tolerance,
        progress=progress,
        workers=workers,
    )
    print("k5 large-gap one-dimensional barrier failure analysis")
    print()
    print(f"h_max: {h_max}")
    print(f"h_values: {_k5_balanced_mdp_h_values(h_values, h_max)}")
    print(f"max_used: {max_used}")
    print(f"failed-regime groups: {len(rows)}")
    print()

    print("1. failure groups by state family")
    print("family packet full orbit gap other_gaps witnesses suggested")
    for row in rows[:n]:
        print(
            f"{row.family}"
            f" {row.packet_type}"
            f" {row.full_regime[0]}->{row.full_regime[1]}"
            f" {row.orbit_regime[0]}->{row.orbit_regime[1]}"
            f" gap={row.large_gap_index}"
            f" other={row.other_nonzero_gaps}"
            f" count={row.witness_count}"
            f" suggested={row.suggested_extension}"
        )
    if len(rows) > n:
        print(f"  ... omitted {len(rows) - n} rows; increase -n to print more.")
    print()

    print("2. extension tests")
    for row in rows[:n]:
        two_gap_text = ", ".join(f"{name}={_fraction_text(value)}" for name, value in row.two_gap_constants)
        print(
            f"  {row.family} packet={row.packet_type}"
            f" state_family={row.state_family}"
            f" one_d_residual={row.one_d_residual:.12g}"
        )
        print(
            f"    two-gap closes={row.two_gap_closes} ({two_gap_text});"
            f" packet_bonus closes={row.packet_bonus_closes} bonus={_fraction_text(row.packet_bonus)};"
            f" tied_leader closes={row.tied_leader_closes} lambda={_fraction_text(row.tied_leader_lambda)}"
        )
        print(
            f"    worst h={row.worst_horizon} r={row.worst_gap} state={row.worst_state}"
        )
    print()

    print("3. smallest human-readable extension")
    grouped: dict[str, int] = defaultdict(int)
    for row in rows:
        grouped[row.suggested_extension] += 1
    if not rows:
        print("  no F3/F4/F6 one-dimensional failures on the sampled grid.")
    for extension, count in sorted(grouped.items(), key=lambda item: (-item[1], item[0])):
        print(f"  {extension}: {count} groups")


def _large_gap_multi_gap_features(state: tuple[int, ...]) -> tuple[float, ...]:
    gaps = _gap_vector(state)
    return tuple(
        1.0 / ((gap + 1) ** 2) if gap >= 2 else 0.0
        for gap in gaps[:4]
    )


def _large_gap_multi_gap_drop(
    row: K5LargeGapInfluenceConeCertificateRow,
    b_values: tuple[float, ...],
    tolerance: float,
) -> float:
    current = sum(value * coefficient for value, coefficient in zip(_large_gap_multi_gap_features(row.state), b_values))
    successor_average = 0.0
    for coefficient, successor in row.delta_terms:
        coefficient_float = float(coefficient)
        if coefficient_float <= tolerance:
            continue
        successor_average += coefficient_float * sum(
            value * b_value
            for value, b_value in zip(_large_gap_multi_gap_features(successor), b_values)
        )
    return current - successor_average


def _fit_large_gap_multi_gap_b(
    rows: tuple[K5LargeGapInfluenceConeCertificateRow, ...],
    tolerance: float,
) -> tuple[tuple[float, ...], bool, str]:
    variable_count = 4
    a_ub: list[list[float]] = []
    b_ub: list[float] = []
    for row in rows:
        current_features = _large_gap_multi_gap_features(row.state)
        successor_features = [0.0] * variable_count
        for coefficient, successor in row.delta_terms:
            coefficient_float = float(coefficient)
            if coefficient_float <= tolerance:
                continue
            for index, value in enumerate(_large_gap_multi_gap_features(successor)):
                successor_features[index] += coefficient_float * value
        # source <= current - E[next]  <=>  E[next]-current <= -source.
        a_ub.append([successor_features[index] - current_features[index] for index in range(variable_count)])
        b_ub.append(-(row.source_scaled / ((row.gap_value + 1) ** 2)))
    objective = [1.0] * variable_count
    result = linprog(
        c=objective,
        A_ub=np.array(a_ub, dtype=float),
        b_ub=np.array(b_ub, dtype=float),
        bounds=[(0.0, None)] * variable_count,
        method="highs",
    )
    if not result.success:
        return (1.0, 1.0, 1.0, 1.0), False, result.message
    return tuple(float(value) for value in result.x), True, result.message


def k5_large_gap_multi_gap_potential_rows(
    h_max: int = 15,
    max_used: int = 12,
    h_values: tuple[int, ...] | None = None,
    tolerance: float = 1e-10,
) -> tuple[tuple[K5LargeGapMultiGapPotentialRow, ...], tuple[float, ...], bool, str]:
    cert_rows, _fitted_b, _feasible, _message = k5_large_gap_influence_cone_certificate_rows(
        h_max=h_max,
        max_used=max_used,
        h_values=h_values,
        tolerance=tolerance,
    )
    large_rows = tuple(row for row in cert_rows if row.gap_value >= 2)
    fitted_b, fitted_feasible, fitted_message = _fit_large_gap_multi_gap_b(large_rows, tolerance)
    output_rows: list[K5LargeGapMultiGapPotentialRow] = []
    unit_b = (1.0, 1.0, 1.0, 1.0)
    for row in large_rows:
        source = row.source_scaled / ((row.gap_value + 1) ** 2)
        unit_drop = _large_gap_multi_gap_drop(row, unit_b, tolerance)
        fitted_drop = _large_gap_multi_gap_drop(row, fitted_b, tolerance)
        output_rows.append(
            K5LargeGapMultiGapPotentialRow(
                family=row.family,
                packet_type=packet_type(row.state),
                full_regime=row.full_regime,
                orbit_regime=row.orbit_regime,
                gap_index=row.gap_index,
                gap_value=row.gap_value,
                source=source,
                psi_drop_unit_b=unit_drop,
                unit_slack=unit_drop - source,
                fitted_slack=fitted_drop - source,
                fitted_b=tuple((index, value) for index, value in enumerate(fitted_b)),
                state=row.state,
                vertex_class_hint=row.full_regime[0],
                support_hint=(),
            )
        )
    return (
        tuple(sorted(output_rows, key=lambda item: (item.unit_slack, item.fitted_slack, item.family, item.state))),
        fitted_b,
        fitted_feasible,
        fitted_message,
    )


def print_k5_large_gap_multi_gap_potential_report(
    h_max: int = 15,
    max_used: int = 12,
    h_values: tuple[int, ...] | None = None,
    n: int = 80,
    tolerance: float = 1e-10,
) -> None:
    rows, fitted_b, fitted_feasible, fitted_message = k5_large_gap_multi_gap_potential_rows(
        h_max=h_max,
        max_used=max_used,
        h_values=h_values,
        tolerance=tolerance,
    )
    unit_failures = [row for row in rows if row.unit_slack < -tolerance]
    fitted_failures = [row for row in rows if row.fitted_slack < -tolerance]
    print("k5 large-gap multi-gap potential report")
    print()
    print(f"h_max: {h_max}")
    print(f"h_values: {_k5_balanced_mdp_h_values(h_values, h_max)}")
    print(f"max_used: {max_used}")
    print(f"large-gap rows: {len(rows)}")
    print()

    print("1. Psi=sum_i B/(g_i+1)^2")
    print(f"  B=1 failures: {len(unit_failures)}")
    print(f"  worst B=1 slack: {min((row.unit_slack for row in rows), default=0.0):.12g}")
    print()

    print("2. fitted gap-position constants")
    print(f"  feasible: {fitted_feasible}")
    print(f"  message: {fitted_message}")
    for index, value in enumerate(fitted_b):
        print(f"  B_{index} = {value:.12g}")
    print(f"  fitted failures: {len(fitted_failures)}")
    print(f"  worst fitted slack: {min((row.fitted_slack for row in rows), default=0.0):.12g}")
    print()

    print("3. failures grouped by family/packet")
    grouped: dict[tuple[str, tuple[int, ...]], list[K5LargeGapMultiGapPotentialRow]] = defaultdict(list)
    for row in unit_failures:
        grouped[(row.family, row.packet_type)].append(row)
    if not grouped:
        print("  no B=1 failures.")
    for (family, packet), group in sorted(grouped.items(), key=lambda item: (-len(item[1]), item[0]))[:n]:
        worst = min(group, key=lambda row: row.unit_slack)
        print(
            f"  {family} packet={packet}"
            f" count={len(group)}"
            f" worst_slack={worst.unit_slack:.12g}"
            f" state={worst.state}"
            f" gap_index={worst.gap_index}"
            f" full={worst.full_regime[0]}->{worst.full_regime[1]}"
            f" orbit={worst.orbit_regime[0]}->{worst.orbit_regime[1]}"
        )
    print()

    print("4. worst rows")
    for row in rows[:n]:
        print(
            f"  {row.family}"
            f" packet={row.packet_type}"
            f" state={row.state}"
            f" gap={row.gap_index}:{row.gap_value}"
            f" source={row.source:.12g}"
            f" drop_B1={row.psi_drop_unit_b:.12g}"
            f" slack_B1={row.unit_slack:.12g}"
            f" fitted_slack={row.fitted_slack:.12g}"
        )
    if len(rows) > n:
        print(f"  ... omitted {len(rows) - n} rows; increase -n to print more.")
    print()

    print("5. theorem candidate")
    if not unit_failures:
        print(
            "  The sampled rows satisfy large-gap influence <= Psi(x)-E[Psi(X')]"
            " with Psi(x)=sum_i 1/(g_i+1)^2 over true large gaps."
        )
    elif fitted_feasible and not fitted_failures:
        print(
            "  The sampled rows satisfy the superharmonic inequality with fitted gap-position constants B_i."
        )
    else:
        print(
            "  The sampled rows are not closed by this multi-gap potential alone;"
            " the grouped failures indicate where a boundary or low-gap source term is still needed."
        )


def k5_balanced_mdp_exceptional_packet_rows(
    h_values: tuple[int, ...] | None = None,
    h_max: int = 20,
    tolerance: float = 1e-12,
) -> tuple[BalancedMDPExceptionalPacketRow, ...]:
    horizons = _k5_balanced_mdp_h_values(h_values, h_max)
    max_horizon = max(horizons, default=0)
    full_solution = _k5_balanced_mdp_full_solution(max_horizon)
    orbit_solution = _k5_balanced_mdp_orbit_solution(max_horizon)
    rows: list[BalancedMDPExceptionalPacketRow] = []
    for horizon in horizons:
        occupancy = _balanced_mdp_policy_occupancy(full_solution, horizon)
        grouped_mass: dict[tuple[int, ...], float] = defaultdict(float)
        grouped_best: dict[tuple[int, ...], tuple[float, tuple[int, ...], Fraction, int]] = {}
        for time in range(horizon):
            remaining = horizon - time
            for state, occupancy_probability in occupancy[time].items():
                if occupancy_probability <= tolerance:
                    continue
                best_vertex = full_solution.policies[remaining][state]
                if best_vertex.marginal == Fraction(1, 2):
                    continue
                packet = packet_type(state)
                grouped_mass[packet] += occupancy_probability
                state_gap = max(
                    0.0,
                    full_solution.values[remaining][state] - orbit_solution.values[remaining][state],
                )
                current = grouped_best.get(packet)
                candidate = (state_gap, state, best_vertex.marginal, _balanced_vertex_class_index(best_vertex))
                if current is None or candidate > current:
                    grouped_best[packet] = candidate
        for packet, occupancy_mass in grouped_mass.items():
            max_gap, representative_state, best_c, best_class = grouped_best[packet]
            rows.append(
                BalancedMDPExceptionalPacketRow(
                    horizon=horizon,
                    packet_type=packet,
                    occupancy_mass=occupancy_mass,
                    max_gap=max_gap,
                    representative_state=representative_state,
                    best_c=best_c,
                    best_class=best_class,
                )
            )
    return tuple(rows)


def print_k5_balanced_mdp_value_gap_report(
    h_values: tuple[int, ...] | None = None,
    h_max: int = 20,
    n: int = 20,
    tolerance: float = 1e-10,
    summary_only: bool = False,
) -> None:
    horizons = _k5_balanced_mdp_h_values(h_values, h_max)
    rows = k5_balanced_mdp_value_gap_rows(h_values=horizons)
    calibration_h_max = max(max(horizons, default=0), 2)
    full_solution = _k5_balanced_mdp_full_solution(calibration_h_max)
    half_solution = _k5_balanced_mdp_half_solution(calibration_h_max)
    orbit_solution = _k5_balanced_mdp_orbit_solution(calibration_h_max)
    usage_rows: tuple[BalancedMDPCUsageRow, ...] = ()
    exceptional_rows: tuple[BalancedMDPExceptionalPacketRow, ...] = ()
    if not summary_only:
        usage_rows = k5_balanced_mdp_policy_c_usage_rows(h_values=horizons, tolerance=tolerance)
        exceptional_rows = k5_balanced_mdp_exceptional_packet_rows(h_values=horizons, tolerance=tolerance)

    print("balanced MDP value gap")
    print()
    print(f"horizons: {horizons}")
    print(f"summary_only: {summary_only}")
    print(f"occupancy tolerance: {tolerance}")
    print(f"balanced vertices: {len(k5_balanced_action_vertices())}")
    print(f"c=1/2 vertices: {sum(1 for vertex in k5_balanced_action_vertices() if vertex.marginal == Fraction(1, 2))}")
    print(f"orbit vertices: {len(_k5_chase_orbit_vertices())}")
    print()

    print("1. flat initial-state values")
    print("h V_full V_half V_orbit V_fixed_chase V_full - V_half V_full - V_orbit V_full - V_fixed_chase best c class")
    for row in rows:
        print(
            f"{row.horizon:4d}"
            f" {row.v_full:.12f}"
            f" {row.v_half:.12f}"
            f" {row.v_orbit:.12f}"
            f" {row.v_fixed_chase:.12f}"
            f" {row.gap_full_minus_half:.12f}"
            f" {row.gap_full_minus_orbit:.12f}"
            f" {row.gap_full_minus_fixed_chase:.12f}"
            f" {_fraction_text(row.initial_best_c)}"
            f" {row.initial_best_class}"
        )
        print(f"     best support: {_format_balanced_support(row.initial_best_support)}")
        print(f"     orbit support: {_format_balanced_support(row.initial_orbit_support)}")

    print()
    print("2. h=1 flat-state calibration")
    state = (0, 0, 0, 0, 0)
    print("state V_full V_half V_orbit V_full - V_orbit best c")
    full_h1 = full_solution.values[1][state]
    half_h1 = half_solution.values[1][state]
    orbit_h1 = orbit_solution.values[1][state]
    best_h1 = full_solution.policies[1][state]
    print(
        f"{state}"
        f" {full_h1:.12f}"
        f" {half_h1:.12f}"
        f" {orbit_h1:.12f}"
        f" {full_h1 - orbit_h1:.12f}"
        f" {_fraction_text(best_h1.marginal)}"
    )

    if not summary_only:
        print()
        print("3. policy c-usage")
        print("h c occupancy states")
        for horizon in horizons:
            horizon_rows = [row for row in usage_rows if row.horizon == horizon]
            for row in sorted(horizon_rows, key=lambda item: (-item.occupancy_mass, float(item.c_value))):
                print(
                    f"{row.horizon:4d}"
                    f" {_fraction_text(row.c_value):>4s}"
                    f" {row.occupancy_mass:.12f}"
                    f" {row.state_count:4d}"
                )

        print()
        print("4. exceptional packets")
        print("h packet occupancy max_gap representative_state best c class")
        exceptional_sorted = sorted(
            exceptional_rows,
            key=lambda item: (-item.occupancy_mass, -item.max_gap, item.horizon, item.packet_type),
        )
        for row in exceptional_sorted[:n]:
            print(
                f"{row.horizon:4d}"
                f" {row.packet_type}"
                f" {row.occupancy_mass:.12f}"
                f" {row.max_gap:.12f}"
                f" {row.representative_state}"
                f" {_fraction_text(row.best_c)}"
                f" {row.best_class}"
            )
        if not exceptional_sorted:
            print("  none")

    print()
    print("5. candidate interpretation")
    print("  V_full - V_orbit measures the global balanced-MDP gap from the flat initial state.")
    if summary_only:
        print("  Summary mode skips occupancy and exceptional-packet scans; increase h_max carefully if you want a richer report.")
    else:
        print("  The policy c-usage and exceptional packets tables show whether non-1/2 marginals stay confined to small boundary regimes.")


def print_k5_balanced_mdp_gap_scaling_report(
    h_values: tuple[int, ...] | None = None,
    h_max: int = 30,
    tail_length: int = 10,
    tolerance: float = 1e-9,
) -> None:
    rows = k5_balanced_mdp_gap_scaling_rows(h_values=h_values, h_max=h_max)
    summary = k5_balanced_mdp_gap_scaling_summary(
        h_values=h_values,
        h_max=h_max,
        tail_length=tail_length,
        tolerance=tolerance,
    )

    print("balanced MDP gap scaling")
    print()
    print(f"horizons: {tuple(row.horizon for row in rows)}")
    print(f"tail_length: {tail_length}")
    print(f"tolerance: {tolerance}")
    print()

    print("1. flat-state gap scaling table")
    print("h V_full - V_orbit V_full - V_half V_half - V_orbit gap/sqrt(h) gap/log(h+1) best c class")
    for row in rows:
        print(
            f"{row.horizon:4d}"
            f" {row.gap_full_minus_orbit:.12f}"
            f" {row.gap_full_minus_half:.12f}"
            f" {row.gap_half_minus_orbit:.12f}"
            f" {row.gap_over_sqrt_h:.12f}"
            f" {row.gap_over_log_h_plus_1:.12f}"
            f" {_fraction_text(row.best_first_c)}"
            f" {row.best_first_class}"
        )

    print()
    print("2. summary statistics")
    print(f"max gap over tested horizons: {summary.max_gap:.12f}")
    print(f"argmax h: {summary.argmax_h}")
    print(
        "tail gaps: "
        + ", ".join(
            f"h={h}:gap={gap:.12f}"
            for h, gap in zip(summary.tail_horizons, summary.tail_gaps, strict=True)
        )
    )
    print(
        "tail gap/sqrt(h): "
        + ", ".join(
            f"h={h}:ratio={ratio:.12f}"
            for h, ratio in zip(summary.tail_horizons, summary.tail_gap_over_sqrt, strict=True)
        )
    )
    print(f"gap/sqrt(h) nonincreasing on tail: {summary.gap_over_sqrt_nonincreasing_on_tail}")
    print(f"gap/sqrt(h) decreases end-to-end on tail: {summary.gap_over_sqrt_end_to_end_decreases}")
    print(f"monotonicity V_full >= V_half >= V_orbit holds: {summary.monotonicity_holds}")

    print()
    print("3. interpretation")
    if summary.c_half_orbit_optimality_holds:
        print("c=1/2 orbit optimality holds on tested flat horizons.")
    else:
        print("c=1/2 orbit optimality fails on at least one tested flat horizon.")
    print("The key diagnostic is whether V_full - V_orbit stays bounded or grows slowly while gap/sqrt(h) falls.")


def print_k5_balanced_varying_c_obstruction_report(
    h_values: tuple[int, ...] = (10, 20, 50, 100),
    max_used: int = 8,
    n: int = 40,
    tolerance: float = 1e-8,
) -> None:
    rows = k5_balanced_varying_c_obstruction_rows(h_values=h_values, max_used=max_used)
    print("varying-c obstruction")
    print()
    print(f"h_values: {h_values}")
    print(f"max_used: {max_used}")
    print(f"tolerance: {tolerance}")
    print()

    print("1. max centered defects")
    print("h eps_full h_eps_full eps_c_half h_eps_c_half state packet gaps best c class support")
    for horizon in h_values:
        group = [row for row in rows if row.horizon == horizon]
        if not group:
            continue
        full = max(group, key=lambda row: (row.eps_full, row.state))
        c_half = max(group, key=lambda row: (row.eps_c_half, row.state))
        print(
            f"{horizon:4d}"
            f" {full.eps_full:.12g} {horizon * full.eps_full:.12g}"
            f" {c_half.eps_c_half:.12g} {horizon * c_half.eps_c_half:.12g}"
            f" {full.state}"
            f" {full.packet_type}"
            f" {full.packet_gaps}"
            f" best c={_fraction_text(full.best_c)}"
            f" class={full.best_class}"
            f" {_format_balanced_support(full.best_support)}"
        )

    print()
    print("2. obstruction groups by packet / best c / class")
    for horizon in h_values:
        group = [
            row
            for row in rows
            if row.horizon == horizon and row.eps_full > tolerance and row.best_c != Fraction(1, 2)
        ]
        grouped: dict[tuple[tuple[int, ...], Fraction, int], list[BalancedVaryingCObstructionRow]] = defaultdict(list)
        for row in group:
            grouped[(row.packet_type, row.best_c, row.best_class)].append(row)
        print(f"  h={horizon}")
        for (packet, best_c, best_class), items in sorted(
            grouped.items(),
            key=lambda item: (-max(row.eps_full for row in item[1]), item[0]),
        )[:n]:
            worst = max(items, key=lambda row: row.eps_full)
            print(
                f"    packet={packet}"
                f" best_c={_fraction_text(best_c)}"
                f" class={best_class}"
                f" count={len(items)}"
                f" max_eps={worst.eps_full:.12g}"
                f" state={worst.state}"
                f" boundary={_boundary_distance_label(worst.state)}"
            )

    print()
    print("3. c != 1/2 states with positive obstruction")
    positive = [
        row
        for row in rows
        if row.eps_full > tolerance and row.best_c != Fraction(1, 2)
    ]
    for row in sorted(positive, key=lambda item: (-item.eps_full, item.horizon, item.state))[:n]:
        print(
            f"h={row.horizon:4d}"
            f" eps={row.eps_full:.12g}"
            f" state={row.state}"
            f" packet={row.packet_type}"
            f" gaps={row.packet_gaps}"
            f" best c={_fraction_text(row.best_c)}"
            f" class={row.best_class}"
            f" boundary={_boundary_distance_label(row.state)}"
            f" support={_format_balanced_support(row.best_support)}"
        )

    print()
    print("4. packet (1,4) scan")
    print("h a eps_full eps_c_half best c class support")
    for horizon in h_values:
        for a in range(max_used + 1):
            state = (a, 0, 0, 0, 0)
            match = next((row for row in rows if row.horizon == horizon and row.state == state), None)
            if match is None:
                continue
            print(
                f"{horizon:4d}"
                f" {a:2d}"
                f" {match.eps_full:.12g}"
                f" {match.eps_c_half:.12g}"
                f" {_fraction_text(match.best_c)}"
                f" {match.best_class}"
                f" {_format_balanced_support(match.best_support)}"
            )

    print()
    print("5. exact 1/8 local transition at packet (1,4)")
    state = (1, 0, 0, 0, 0)
    best_support = (
        (Fraction(1, 4), (0, 0, 0, 0, 1)),
        (Fraction(1, 4), (0, 0, 0, 1, 0)),
        (Fraction(1, 4), (0, 0, 1, 0, 0)),
        (Fraction(1, 4), (1, 1, 0, 0, 0)),
    )
    orbit_support = ((Fraction(1, 2), (0, 1, 1, 1, 0)), (Fraction(1, 2), (1, 0, 0, 0, 1)))
    print(f"  state={state}")
    print(f"  c=1/4 support={_format_balanced_support(best_support)}")
    print(f"  c=1/4 transitions={_format_transition_distribution(_transition_distribution_for_support(state, best_support))}")
    print(f"  orbit support={_format_balanced_support(orbit_support)}")
    print(f"  orbit transitions={_format_transition_distribution(_transition_distribution_for_support(state, orbit_support))}")
    for horizon in h_values:
        best_q = _balanced_chase_centered_q_for_support(state, horizon, best_support)
        orbit_q = _balanced_chase_centered_q_for_support(state, horizon, orbit_support)
        print(
            f"  h={horizon}"
            f" best_q={best_q:.12f}"
            f" orbit_q={orbit_q:.12f}"
            f" diff={best_q - orbit_q:.12f}"
            f" exact 1/8={float(Fraction(1, 8)):.12f}"
        )

    print()
    print("6. tiny centered one-step optimal c-usage diagnostic")
    tiny_horizon = min(max(h_values, default=1), 6)
    tiny_max_used = min(max_used, 4)
    usage = _tiny_balanced_optimal_policy_c_usage(tiny_horizon, tiny_max_used)
    grouped_usage: dict[tuple[tuple[int, ...], Fraction], int] = defaultdict(int)
    for _, _, packet, best_c, _, _ in usage:
        grouped_usage[(packet, best_c)] += 1
    print(f"  remaining_horizon<= {tiny_horizon}, max_used<= {tiny_max_used}, non_half_choices={len(usage)}")
    for (packet, best_c), count in sorted(grouped_usage.items(), key=lambda item: (-item[1], item[0]))[:n]:
        print(f"    packet={packet} best c={_fraction_text(best_c)} count={count}")
    for remaining, state, packet, best_c, best_q, support in usage[: min(n, len(usage))]:
        print(
            f"    sample rem={remaining}"
            f" state={state}"
            f" packet={packet}"
            f" best c={_fraction_text(best_c)}"
            f" q={best_q:.12f}"
            f" support={_format_balanced_support(support)}"
        )

    print()
    print("7. candidate theorem")
    print("  If c!=1/2 advantages are supported only on finite/boundary sets with bounded expected visits,")
    print("  the direct balanced route becomes an exchangeability plus local-time proof rather than a sup-norm greedy proof.")


def _is_complement_pair_vertex(vertex: BalancedActionVertex) -> bool:
    if len(vertex.support) != 2:
        return False
    (p0, a0), (p1, a1) = vertex.support
    return p0 == p1 == Fraction(1, 2) and a1 == complement(a0)


def _k5_balanced_action_symmetry_classes() -> tuple[tuple[tuple[tuple[str, int, int], ...], tuple[BalancedActionVertex, ...]], ...]:
    grouped: dict[tuple[tuple[str, int, int], ...], list[BalancedActionVertex]] = defaultdict(list)
    for vertex in k5_balanced_action_vertices():
        grouped[vertex.canonical_key].append(vertex)
    return tuple((key, tuple(grouped[key])) for key in sorted(grouped))


def print_k5_balanced_action_enumeration_report(n: int = 80) -> None:
    vertices = k5_balanced_action_vertices()
    classes = _k5_balanced_action_symmetry_classes()
    support_sizes: dict[int, int] = defaultdict(int)
    marginal_counts: dict[Fraction, int] = defaultdict(int)
    for vertex in vertices:
        support_sizes[len(vertex.support)] += 1
        marginal_counts[vertex.marginal] += 1

    chase_vertex = _k5_chase_balanced_vertex()
    comb_vertex = _k5_comb_balanced_vertex()
    complement_pairs = [vertex for vertex in vertices if _is_complement_pair_vertex(vertex)]
    packet_shapes = ((1, 2, 2), (1, 2, 1, 1), (5,), (1, 1, 1, 1, 1))

    print("k=5 balanced action enumeration report")
    print()
    print(f"total vertices: {len(vertices)}")
    print(f"symmetry classes: {len(classes)}")
    print(
        "support size distribution: "
        + ", ".join(f"{size}:{support_sizes[size]}" for size in sorted(support_sizes))
    )
    print(
        "marginal values: "
        + ", ".join(f"{_fraction_text(value)}:{marginal_counts[value]}" for value in sorted(marginal_counts))
    )
    print()
    print("special actions")
    print(f"  Chase 10100/01011 included: {chase_vertex is not None}")
    if chase_vertex is not None:
        print(f"    class={classes.index((chase_vertex.canonical_key, tuple(v for v in dict(classes)[chase_vertex.canonical_key]))) if False else chase_vertex.canonical_key}")
    print(f"  Comb  10101/01010 included: {comb_vertex is not None}")
    print(f"  complement-pair vertices: {len(complement_pairs)}")
    print()
    print("symmetry class representatives")
    for class_index, (key, group) in enumerate(classes[:n], start=1):
        representative = min(group, key=lambda vertex: _format_balanced_support(vertex.support))
        labels = []
        if chase_vertex is not None and representative.canonical_key == chase_vertex.canonical_key:
            labels.append("contains Chase")
        if comb_vertex is not None and representative.canonical_key == comb_vertex.canonical_key:
            labels.append("contains Comb")
        if any(_is_complement_pair_vertex(vertex) for vertex in group):
            labels.append("complement-pair class")
        print(
            f"{class_index:3d}. orbit_size={len(group):3d}"
            f" support={len(representative.support)}"
            f" c={_fraction_text(representative.marginal)}"
            f" labels={'; '.join(labels) if labels else '-'}"
        )
        print(f"     rep: {_format_balanced_support(representative.support)}")
        for packet_shape in packet_shapes:
            print(
                f"     packet {packet_shape}: "
                f"{_format_packet_count_distribution(_packet_action_count_distribution(representative, packet_shape))}"
            )
    if len(classes) > n:
        print(f"... {len(classes) - n} more classes omitted by n={n}")


def _expected_potential_delta(
    state: tuple[int, ...],
    support: tuple[tuple[float, tuple[int, ...]], ...],
    potential_fn,
) -> float:
    base = potential_fn(state)
    expected = 0.0
    for probability, action in support:
        next_state = canon(tuple(state[index] + action[index] for index in range(len(state))))
        expected += probability * potential_fn(next_state)
    return expected - base


def _k5_centered_potential_specs() -> tuple[tuple[str, object], ...]:
    return (
        ("phi_inf", _phi_centered_max),
        ("phi_tau_0.5", lambda state: _phi_centered_softmax(state, 0.5)),
        ("phi_tau_1.0", lambda state: _phi_centered_softmax(state, 1.0)),
        ("phi_tau_2.0", lambda state: _phi_centered_softmax(state, 2.0)),
    )


def k5_centered_potential_comb_vs_chase_rows(
    max_used: int,
) -> tuple[K5CenteredPotentialComparisonRow, ...]:
    rows: list[K5CenteredPotentialComparisonRow] = []
    for used in range(max_used + 1):
        for state in all_states(5, used):
            canonical_state = canon(state)
            mean_score = sum(canonical_state) / 5.0
            ptype = packet_type(canonical_state)
            gaps = _packet_gaps(canonical_state)
            for potential_name, potential_fn in _k5_centered_potential_specs():
                comb_delta = _expected_potential_delta(canonical_state, _k5_comb_support(), potential_fn)
                chase_delta = _expected_potential_delta(canonical_state, _k5_chase_support(), potential_fn)
                rows.append(
                    K5CenteredPotentialComparisonRow(
                        state=canonical_state,
                        used=used,
                        potential_name=potential_name,
                        phi_value=potential_fn(canonical_state),
                        comb_delta=comb_delta,
                        chase_delta=chase_delta,
                        delta_diff=chase_delta - comb_delta,
                        packet_type=ptype,
                        packet_gaps=gaps,
                        max_gap=max(gaps, default=0),
                        top_gap=canonical_state[0] - mean_score,
                        bottom_gap=mean_score - canonical_state[-1],
                        multiple_near_leaders=sum(1 for value in canonical_state if canonical_state[0] - value <= 1) >= 2,
                        bottom_below_mean=canonical_state[-1] < mean_score,
                    )
                )
    return tuple(rows)


def _k5_softmax_tau_specs(horizon: int) -> tuple[tuple[str, float], ...]:
    fixed = (("tau_0.5", 0.5), ("tau_1.0", 1.0), ("tau_2.0", 2.0))
    sqrt_h = horizon ** 0.5 if horizon > 0 else 1.0
    scaled = (
        ("tau_0.25_sqrt_h", 0.25 * sqrt_h),
        ("tau_0.5_sqrt_h", 0.5 * sqrt_h),
        ("tau_1.0_sqrt_h", sqrt_h),
        ("tau_2.0_sqrt_h", 2.0 * sqrt_h),
    )
    return fixed + scaled


def _softmax_certificate_residual(
    state: tuple[int, ...],
    action: tuple[int, ...],
    tau: float,
    learner: tuple[float, ...],
) -> float:
    next_state = canon(tuple(state[index] + action[index] for index in range(len(state))))
    learner_gain = sum(learner[index] * action[index] for index in range(len(state)))
    return _phi_centered_softmax(next_state, tau) - learner_gain - _phi_centered_softmax(state, tau)


def k5_softmax_potential_certificate_rows(
    max_used: int,
    horizons: tuple[int, ...] = (5, 10, 20, 50),
) -> tuple[K5SoftmaxPotentialCertificateRow, ...]:
    all_gain_actions = all_actions(5)
    rows: list[K5SoftmaxPotentialCertificateRow] = []
    for horizon in horizons:
        for tau_name, tau in _k5_softmax_tau_specs(horizon):
            potential_fn = lambda state, tau=tau: _phi_centered_softmax(state, tau)
            for used in range(max_used + 1):
                for state in all_states(5, used):
                    canonical_state = canon(state)
                    learner = _softmax_centered_gradient(canonical_state, tau)
                    residuals = [
                        (_softmax_certificate_residual(canonical_state, action, tau, learner), action)
                        for action in all_gain_actions
                    ]
                    max_residual, max_action = max(residuals, key=lambda item: item[0])
                    chase_residual = sum(
                        probability * _softmax_certificate_residual(canonical_state, action, tau, learner)
                        for probability, action in _k5_chase_support()
                    )
                    comb_residual = sum(
                        probability * _softmax_certificate_residual(canonical_state, action, tau, learner)
                        for probability, action in _k5_comb_support()
                    )
                    chase_delta = _expected_potential_delta(canonical_state, _k5_chase_support(), potential_fn)
                    comb_delta = _expected_potential_delta(canonical_state, _k5_comb_support(), potential_fn)
                    rows.append(
                        K5SoftmaxPotentialCertificateRow(
                            state=canonical_state,
                            used=used,
                            horizon=horizon,
                            tau_name=tau_name,
                            tau=tau,
                            phi_value=_phi_centered_softmax(canonical_state, tau),
                            learner=learner,
                            max_residual=max_residual,
                            max_centered_residual=max_residual - chase_residual,
                            max_action=max_action,
                            chase_average_residual=chase_residual,
                            comb_average_residual=comb_residual,
                            chase_delta=chase_delta,
                            comb_delta=comb_delta,
                            delta_diff=chase_delta - comb_delta,
                            packet_type=packet_type(canonical_state),
                            packet_gaps=_packet_gaps(canonical_state),
                        )
                    )
    return tuple(rows)


def _balanced_pair_from_action_text(action_text: str) -> tuple[tuple[float, tuple[int, ...]], ...]:
    action = tuple(int(bit) for bit in action_text)
    return _policy_from_weighted_actions(((0.5, action), (0.5, complement(action))))


def _potential_greedy_interval_grammar(k: int) -> tuple[PotentialGreedyGrammarCandidate, ...]:
    if k == 5:
        return (
            PotentialGreedyGrammarCandidate("comb_10101", _balanced_pair_from_action_text("10101")),
            PotentialGreedyGrammarCandidate("chase_10100", _balanced_pair_from_action_text("10100")),
            PotentialGreedyGrammarCandidate("one_run_10010", _balanced_pair_from_action_text("10010")),
            PotentialGreedyGrammarCandidate("one_run_10001", _balanced_pair_from_action_text("10001")),
            PotentialGreedyGrammarCandidate("one_run_10110", _balanced_pair_from_action_text("10110")),
            PotentialGreedyGrammarCandidate("one_run_11000", _balanced_pair_from_action_text("11000")),
        )
    if k == 6:
        return (
            PotentialGreedyGrammarCandidate("interval_0_0", _balanced_policy_from_one_run_interval(6, (0, 0))),
            PotentialGreedyGrammarCandidate("interval_0_2", _balanced_policy_from_one_run_interval(6, (0, 2))),
            PotentialGreedyGrammarCandidate("interval_0_3", _balanced_policy_from_one_run_interval(6, (0, 3))),
            PotentialGreedyGrammarCandidate("interval_0_4", _balanced_policy_from_one_run_interval(6, (0, 4))),
            PotentialGreedyGrammarCandidate("interval_1_1", _balanced_policy_from_one_run_interval(6, (1, 1))),
            PotentialGreedyGrammarCandidate("interval_1_4", _balanced_policy_from_one_run_interval(6, (1, 4))),
            PotentialGreedyGrammarCandidate(
                "top_full_tail",
                _mixed_one_run_interval_policy(
                    6,
                    ((1.0 / 3.0, (0, 0)), (1.0 / 3.0, (0, 4)), (1.0 / 3.0, (1, 4))),
                ),
            ),
            PotentialGreedyGrammarCandidate(
                "tail_heavy",
                _mixed_one_run_interval_policy(6, ((0.25, (0, 0)), (0.25, (0, 4)), (0.5, (1, 4)))),
            ),
        )
    return ()


def _potential_greedy_choice(
    state: tuple[int, ...],
    remaining_horizon: int,
    c: float,
) -> PotentialGreedyGrammarCandidate:
    canonical_state = canon(state)
    grammar = _potential_greedy_interval_grammar(len(canonical_state))
    if not grammar:
        raise ValueError(f"no potential-greedy grammar for k={len(canonical_state)}")
    tau_next = c * (max(remaining_horizon - 1, 1) ** 0.5)

    def score(candidate: PotentialGreedyGrammarCandidate) -> float:
        expected = 0.0
        for probability, action in candidate.support:
            next_state = canon(tuple(canonical_state[index] + action[index] for index in range(len(canonical_state))))
            expected += probability * _phi_centered_softmax(next_state, tau_next)
        return expected

    return max(grammar, key=lambda candidate: (score(candidate), -len(candidate.support), candidate.name))


def potential_greedy_interval_policy(k: int, c: float):
    if k not in (5, 6):
        raise ValueError("potential-greedy interval policy is currently implemented for k=5 and k=6")

    def policy(
        state: tuple[int, ...],
        remaining_horizon: int,
    ) -> tuple[tuple[float, tuple[int, ...]], ...]:
        if len(state) != k:
            raise ValueError(f"potential-greedy policy k={k} received state of length {len(state)}")
        return _potential_greedy_choice(state, remaining_horizon, c).support

    return policy


def _potential_greedy_policy_from_c(c: float):
    def policy(
        state: tuple[int, ...],
        remaining_horizon: int,
    ) -> tuple[tuple[float, tuple[int, ...]], ...]:
        return _potential_greedy_choice(state, remaining_horizon, c).support

    return policy


def _chase5_policy(
    state: tuple[int, ...],
    remaining_horizon: int,
) -> tuple[tuple[float, tuple[int, ...]], ...]:
    del state, remaining_horizon
    return (
        (0.5, (1, 0, 1, 0, 0)),
        (0.5, (0, 1, 0, 1, 1)),
    )


def _interval_from_action(
    action: tuple[int, ...],
) -> tuple[int, int] | None:
    return _one_run_interval_from_edge_signature(_edge_signature(action))


def _format_interval_distribution(
    interval_totals: dict[tuple[int, int] | None, float],
) -> str:
    total = sum(interval_totals.values())
    if total <= 0.0:
        return "-"
    return ", ".join(
        f"{_format_interval(interval)}:{weight / total:.3f}"
        for interval, weight in sorted(interval_totals.items(), key=lambda item: (-item[1], str(item[0])))
    )


def _packet_barycenter_status(packet_value: float, mean_score: float, tolerance: float = 1e-9) -> str:
    if packet_value > mean_score + tolerance:
        return "above_mean"
    if packet_value < mean_score - tolerance:
        return "below_mean"
    return "crosses_mean"


def _support_interval_distribution(
    support: tuple[tuple[float, tuple[int, ...], tuple[int, ...]], ...],
) -> tuple[tuple[tuple[int, int] | None, float], ...]:
    totals: dict[tuple[int, int] | None, float] = defaultdict(float)
    for weight, action, _ in support:
        totals[_interval_from_action(action)] += weight
    return tuple(sorted(totals.items(), key=lambda item: (-item[1], str(item[0]))))


def _barycenter_action_row_from_dual_row(
    library_name: str,
    row: LibraryLPDualInspectRow,
) -> BarycenterActionRow:
    groups = _packet_index_groups(row.state)
    mean_score = sum(row.state) / len(row.state) if row.state else 0.0
    summaries: list[BarycenterPacketSummary] = []
    for packet_index, group in enumerate(groups):
        packet_value = row.state[group[0]]
        exposure = sum(row.expected_action[index] for index in group) / len(group)
        split_rate = 0.0
        for weight, action, _ in row.support:
            bits = {action[index] for index in group}
            if len(bits) > 1:
                split_rate += weight
        summaries.append(
            BarycenterPacketSummary(
                status=_packet_barycenter_status(packet_value, mean_score),
                packet_index=packet_index,
                packet_size=len(group),
                exposure=exposure,
                split_rate=split_rate,
            )
        )
    top_exposure = row.expected_action[0] if row.expected_action else 0.0
    bottom_index = len(row.state) - 1
    bottom_exposure = row.expected_action[bottom_index] if row.expected_action else 0.0
    p_top1_bottom0 = 0.0
    p_top0_bottom1 = 0.0
    p_top_equals_bottom = 0.0
    p_top_bottom = 0.0
    for weight, action, _ in row.support:
        top = action[0] if action else 0
        bottom = action[bottom_index] if action else 0
        if top == 1 and bottom == 0:
            p_top1_bottom0 += weight
        if top == 0 and bottom == 1:
            p_top0_bottom1 += weight
        if top == bottom:
            p_top_equals_bottom += weight
        p_top_bottom += weight * top * bottom
    return BarycenterActionRow(
        library_name=library_name,
        time=row.time,
        remaining_horizon=row.remaining_horizon,
        state=row.state,
        packet_type=row.packet_type,
        packet_gaps=row.packet_gaps,
        occupancy_probability=row.occupancy_probability,
        mean_score=mean_score,
        packet_summaries=tuple(summaries),
        top_exposure=top_exposure,
        bottom_exposure=bottom_exposure,
        p_top1_bottom0=p_top1_bottom0,
        p_top0_bottom1=p_top0_bottom1,
        p_top_equals_bottom=p_top_equals_bottom,
        top_bottom_covariance=p_top_bottom - top_exposure * bottom_exposure,
        interval_distribution=_support_interval_distribution(row.support),
    )


def k6_barycenter_action_rows(
    T: int,
    support_tolerance: float = 1e-8,
) -> tuple[BarycenterActionRow, ...]:
    rows: list[BarycenterActionRow] = []
    for library_name in ("top_prefix_all", "one_run"):
        _, dual_rows = library_lp_dual_inspect_rows(6, T, library_name, support_tolerance=support_tolerance)
        rows.extend(_barycenter_action_row_from_dual_row(library_name, row) for row in dual_rows)
    return tuple(rows)


def _subsequence_packet_type(values: tuple[int, ...]) -> tuple[int, ...]:
    if not values:
        return ()
    sizes: list[int] = []
    current = values[0]
    count = 1
    for value in values[1:]:
        if value == current:
            count += 1
        else:
            sizes.append(count)
            current = value
            count = 1
    sizes.append(count)
    return tuple(sizes)


def _alive_span(alive_positions: tuple[int, ...]) -> tuple[int, int] | None:
    if not alive_positions:
        return None
    return (min(alive_positions), max(alive_positions))


def _alive_is_prefix(alive_positions: tuple[int, ...]) -> bool:
    return alive_positions == tuple(range(len(alive_positions)))


def _classify_one_run_alive_relation(
    interval: tuple[int, int] | None,
    alive_span: tuple[int, int] | None,
) -> tuple[str, tuple[int, int] | None]:
    if interval is None:
        return "constant_or_no_run", None
    start, end = interval
    if alive_span is None:
        return "outside_alive", None
    alive_start, alive_end = alive_span
    relative = (start - alive_start, end - alive_start)
    if start == 0:
        return "prefix_truncated_comb_on_full_k", relative
    if start == alive_start and end == alive_end - 1:
        return "alive_full_comb", relative
    if start == alive_start and end <= alive_end - 1:
        return "alive_prefix_truncated_comb", relative
    if alive_start < start <= end < alive_end:
        return "alive_internal_repair", relative
    if start <= alive_end <= end:
        return "crosses_alive_dead_boundary", relative
    if end < alive_start or start > alive_end - 1:
        return "outside_alive", relative
    return "shifted_not_alive_explained", relative


def _classify_k6_one_run_interval_relation(
    interval: tuple[int, int] | None,
    state: tuple[int, ...],
) -> str:
    if interval is None:
        return "constant_or_no_run"
    start, end = interval
    edge_count = len(state) - 1
    boundaries = set(_packet_boundary_edges(_packet_index_groups(state)))
    crosses_boundary = any(start <= boundary <= end for boundary in boundaries)
    if start == 0 and end == edge_count - 1:
        return "full_comb_like"
    if start == 0:
        return "prefix_truncated"
    if end == edge_count - 1:
        return "tail_cleanup"
    if start == end:
        if start in boundaries:
            return "crosses_packet_boundary"
        if (start - 1) in boundaries:
            return "left_shoulder_repair"
        if (start + 1) in boundaries:
            return "right_shoulder_repair"
        return "short_internal_repair"
    if crosses_boundary:
        return "crosses_packet_boundary"
    if end - start <= 1:
        return "short_internal_repair"
    return "other"


def _one_run_interval_from_edge_signature(edge_signature: tuple[int, ...]) -> tuple[int, int] | None:
    intervals = tuple(_edge_run_intervals(edge_signature))
    return intervals[0] if len(intervals) == 1 else None


def _interval_distribution_for_interval_support(
    support: tuple[K6OneRunIntervalActionRow, ...],
) -> tuple[tuple[tuple[int, int] | None, float], ...]:
    totals: dict[tuple[int, int] | None, float] = defaultdict(float)
    for item in support:
        totals[item.interval] += item.weight
    return tuple(sorted(totals.items(), key=lambda pair: (-pair[1], pair[0] is None, pair[0] or (-1, -1))))


def _interval_distribution_for_alive_row(
    row: K6OneRunAlivePatternRow,
) -> tuple[tuple[tuple[int, int] | None, str], ...]:
    weights: dict[tuple[int, int] | None, float] = defaultdict(float)
    for item in row.support:
        weights[item.interval] += item.weight
    return tuple(
        (interval, _format_fractionish(weight))
        for interval, weight in sorted(weights.items(), key=lambda pair: (pair[0] is None, pair[0] or (-1, -1)))
    )


def k6_one_run_alive_pattern_rows(
    T: int,
    support_tolerance: float = 1e-8,
) -> tuple[K6OneRunAlivePatternRow, ...]:
    _, dual_rows = library_lp_dual_inspect_rows(6, T, "one_run", support_tolerance=support_tolerance)
    rows: list[K6OneRunAlivePatternRow] = []
    for row in dual_rows:
        alive = _alive_positions(row.state, row.remaining_horizon)
        span = _alive_span(alive)
        alive_values = tuple(row.state[index] for index in alive)
        support_rows: list[K6OneRunAliveActionRow] = []
        for weight, action, edge_signature in row.support:
            intervals = tuple(_edge_run_intervals(edge_signature))
            interval = intervals[0] if len(intervals) == 1 else None
            relation_class, relative_interval = _classify_one_run_alive_relation(interval, span)
            next_state = canon(tuple(row.state[index] + action[index] for index in range(len(row.state))))
            support_rows.append(
                K6OneRunAliveActionRow(
                    weight=weight,
                    action=action,
                    edge_signature=edge_signature,
                    interval=interval,
                    interval_relative_to_alive=relative_interval,
                    relation_class=relation_class,
                    successor_packet_type=packet_type(next_state),
                )
            )
        rows.append(
            K6OneRunAlivePatternRow(
                time=row.time,
                remaining_horizon=row.remaining_horizon,
                state=row.state,
                packet_type=row.packet_type,
                packet_gaps=row.packet_gaps,
                adjacent_gaps=row.adjacent_gaps,
                occupancy_probability=row.occupancy_probability,
                learner_distribution=row.learner_distribution,
                alive_positions=alive,
                alive_count=len(alive),
                alive_span=span,
                alive_is_prefix=_alive_is_prefix(alive),
                alive_packet_type=_subsequence_packet_type(alive_values),
                support=tuple(sorted(support_rows, key=lambda item: (-item.weight, _format_action(item.action)))),
            )
        )
    return tuple(rows)


def _group_alive_rows(rows: tuple[K6OneRunAlivePatternRow, ...], key_fn):
    grouped: dict[object, list[K6OneRunAlivePatternRow]] = defaultdict(list)
    for row in rows:
        grouped[key_fn(row)].append(row)
    return tuple(
        sorted(
            grouped.items(),
            key=lambda item: (
                -sum(row.occupancy_probability for row in item[1]),
                -len(item[1]),
                str(item[0]),
            ),
        )
    )


def _alive_support_relation_totals(
    rows: tuple[K6OneRunAlivePatternRow, ...],
) -> tuple[tuple[str, float, float], ...]:
    dual_totals: dict[str, float] = defaultdict(float)
    occupancy_totals: dict[str, float] = defaultdict(float)
    for row in rows:
        for support in row.support:
            dual_totals[support.relation_class] += support.weight
            occupancy_totals[support.relation_class] += row.occupancy_probability * support.weight
    return tuple(
        (relation, dual_totals[relation], occupancy_totals[relation])
        for relation in sorted(dual_totals, key=lambda key: (-occupancy_totals[key], key))
    )


def _format_interval(interval: tuple[int, int] | None) -> str:
    return "-" if interval is None else f"{interval[0]}:{interval[1]}"


def _print_alive_row(row: K6OneRunAlivePatternRow, support_n: int = 12) -> None:
    print(
        f"  t={row.time} rem={row.remaining_horizon}"
        f" state={row.state}"
        f" packet={row.packet_type} gaps={row.packet_gaps}"
        f" occ={row.occupancy_probability:.6f}"
    )
    print(
        f"    alive={row.alive_positions}"
        f" alive_count={row.alive_count}"
        f" alive_span={row.alive_span}"
        f" alive_is_prefix={row.alive_is_prefix}"
        f" alive_packet_type={row.alive_packet_type}"
    )
    print(f"    learner p={_format_float_tuple(row.learner_distribution)}")
    print("    support:")
    for support in row.support[:support_n]:
        print(
            f"      w={_format_fractionish(support.weight):>8s}"
            f" action={_format_action(support.action)}"
            f" edge={_format_edge_signature(support.edge_signature)}"
            f" interval={_format_interval(support.interval)}"
            f" rel={_format_interval(support.interval_relative_to_alive)}"
            f" relation={support.relation_class}"
            f" successor={support.successor_packet_type}"
        )
    if len(row.support) > support_n:
        print("      ...")


def print_k6_one_run_alive_pattern_report(
    T: int,
    support_tolerance: float = 1e-8,
    n: int = 80,
) -> None:
    rows = k6_one_run_alive_pattern_rows(T, support_tolerance=support_tolerance)
    zero = (0, 0, 0, 0, 0, 0)
    optimal = optimal_values(6, T)[T][zero]
    library_values: dict[str, float] = {}
    for library_name in ("top_prefix_all", "one_run", "two_run", "local_edges"):
        actions = _strategy_class_library_actions(6, T, library_name)
        values = _library_lp_value_layers(6, T, actions)
        library_values[library_name] = values[T][zero]

    print(f"k=6 one-run alive-pattern report, T={T}")
    print()
    print(f"support tolerance: {support_tolerance:.3g}")
    print(f"rows: {len(rows)}")
    print()
    print("Value summary:")
    print(f"  V_star: {optimal:.6f}")
    for library_name in ("top_prefix_all", "one_run", "two_run", "local_edges"):
        value = library_values[library_name]
        gap = optimal - value
        print(
            f"  {library_name:14s}"
            f" V={value:.6f}"
            f" gap={gap:.6f}"
            f" gap/sqrt(T)={gap / (T ** 0.5 if T > 0 else 1.0):.6f}"
        )
    print()

    print("Overall support mass by relation class:")
    for relation, dual_weight, occupancy_weight in _alive_support_relation_totals(rows):
        print(
            f"  {relation:32s}"
            f" dual_weight={dual_weight:.6f}"
            f" occupancy_weight={occupancy_weight:.6f}"
        )
    print()

    print("Support mass by alive_count:")
    for alive_count, group in _group_alive_rows(rows, lambda row: row.alive_count):
        print(
            f"  alive_count={alive_count}"
            f" rows={len(group)}"
            f" occupancy={sum(row.occupancy_probability for row in group):.6f}"
        )
        relation_totals = _alive_support_relation_totals(tuple(group))
        print("    top relation classes:")
        for relation, _, occupancy_weight in relation_totals[:8]:
            print(f"      {relation}: {occupancy_weight:.6f}")
        interval_totals: dict[tuple[int, int] | None, float] = defaultdict(float)
        regime_totals: dict[tuple[tuple[int, ...], tuple[int, ...]], float] = defaultdict(float)
        for row in group:
            regime_totals[(row.packet_type, row.packet_gaps)] += row.occupancy_probability
            for support in row.support:
                interval_totals[support.interval] += row.occupancy_probability * support.weight
        print("    top edge intervals:")
        for interval, weight in sorted(interval_totals.items(), key=lambda item: (-item[1], str(item[0])))[:8]:
            print(f"      {_format_interval(interval)}: {weight:.6f}")
        print("    top packet regimes:")
        for (ptype, gaps), weight in sorted(regime_totals.items(), key=lambda item: (-item[1], item[0]))[:5]:
            print(f"      packet={ptype} gaps={gaps}: {weight:.6f}")
    print()

    print("Top dual rows by occupancy:")
    for row in sorted(rows, key=lambda item: (-item.occupancy_probability, item.time, item.state))[:n]:
        _print_alive_row(row)
    print()

    print("Compression check:")
    mapping_a = {
        (row.remaining_horizon, row.packet_type, row.packet_gaps, _interval_distribution_for_alive_row(row))
        for row in rows
    }
    mapping_b = {
        (
            row.remaining_horizon,
            row.alive_count,
            row.alive_span,
            row.packet_type,
            _interval_distribution_for_alive_row(row),
        )
        for row in rows
    }
    mapping_c: dict[tuple[int, str, tuple[int, int] | None], float] = defaultdict(float)
    for row in rows:
        for support in row.support:
            mapping_c[(row.alive_count, support.relation_class, support.interval_relative_to_alive)] += (
                row.occupancy_probability * support.weight
            )
    print(f"  distinct (rem, packet_type, gaps) -> interval distributions: {len(mapping_a)}")
    print(f"  distinct (rem, alive_count, alive_span, packet_type) -> interval distributions: {len(mapping_b)}")
    print(f"  distinct (alive_count, relation_class, interval_relative_to_alive): {len(mapping_c)}")
    print("  top alive/relation/relative interval masses:")
    for (alive_count, relation, relative_interval), weight in sorted(mapping_c.items(), key=lambda item: (-item[1], str(item[0])))[:n]:
        print(
            f"    alive_count={alive_count}"
            f" relation={relation}"
            f" rel_interval={_format_interval(relative_interval)}"
            f" mass={weight:.6f}"
        )
    print()

    print("Candidate rule hints:")
    for alive_count, group in _group_alive_rows(rows, lambda row: row.alive_count):
        prefix_occupancy = sum(row.occupancy_probability for row in group if row.alive_is_prefix)
        total_occupancy = sum(row.occupancy_probability for row in group)
        interval_totals: dict[tuple[int, int] | None, float] = defaultdict(float)
        boundary_gap_totals: dict[int, float] = defaultdict(float)
        cleanup_totals: dict[int, float] = defaultdict(float)
        for row in group:
            if row.alive_span is not None and row.alive_span[1] < len(row.state) - 1:
                boundary_gap_totals[row.state[row.alive_span[1]] - row.state[row.alive_span[1] + 1]] += row.occupancy_probability
            if row.remaining_horizon in {1, 2}:
                cleanup_totals[row.remaining_horizon] += row.occupancy_probability
            for support in row.support:
                interval_totals[support.interval] += row.occupancy_probability * support.weight
        print(
            f"  alive_count={alive_count}"
            f" alive_prefix_share={prefix_occupancy / total_occupancy if total_occupancy else 0.0:.3f}"
            f" rows={len(group)}"
            f" occupancy={total_occupancy:.6f}"
        )
        print("    dominant intervals:")
        for interval, weight in sorted(interval_totals.items(), key=lambda item: (-item[1], str(item[0])))[:6]:
            print(f"      {_format_interval(interval)}: {weight:.6f}")
        if boundary_gap_totals:
            print(f"    alive/dead boundary gaps={tuple(sorted(boundary_gap_totals.items(), key=lambda item: (-item[1], item[0]))[:5])}")
        if cleanup_totals:
            print(f"    cleanup horizons={tuple(sorted(cleanup_totals.items()))}")


def _k6_alive_candidate_policy_specs() -> dict[str, tuple[str, str]]:
    return {
        "k6_alive_trunc_comb_policy": ("trunc6_chase5_comb_tail", "weak"),
        "k6_alive_trunc_comb_twin3_policy": ("trunc6_chase5_twin3_tail", "weak"),
        "k6_alive_full_comb_control_policy": ("fullcomb6_chase5_comb_tail", "weak"),
        "k6_alive_trunc_comb_strict_policy": ("trunc6_chase5_comb_tail", "strict"),
        "k6_alive_trunc_comb_twin3_strict_policy": ("trunc6_chase5_twin3_tail", "strict"),
        "k6_alive_full_comb_control_strict_policy": ("fullcomb6_chase5_comb_tail", "strict"),
    }


def _k6_alive_candidate_histograms(
    T: int,
    variant: str,
    death_mode: str,
) -> tuple[tuple[tuple[int, float], ...], tuple[tuple[str, float], ...]]:
    def policy_fn(state: tuple[int, ...], remaining_horizon: int):
        return _k6_alive_candidate_policy(state, remaining_horizon, variant, death_mode=death_mode)

    occupancy = _time_policy_occupancy(6, T, policy_fn)
    alive_counts: dict[int, float] = defaultdict(float)
    pattern_usage: dict[str, float] = defaultdict(float)
    for time in range(T):
        remaining_horizon = T - time
        for state, probability in occupancy[time].items():
            alive_count, _, pattern_label = _k6_alive_policy_metadata(
                state,
                remaining_horizon,
                variant,
                death_mode=death_mode,
            )
            alive_counts[alive_count] += probability
            pattern_usage[f"m={alive_count}:{pattern_label}"] += probability

    return (
        tuple(sorted(alive_counts.items(), key=lambda item: (-item[1], item[0]))),
        tuple(sorted(pattern_usage.items(), key=lambda item: (-item[1], item[0]))),
    )


def k6_alive_candidate_benchmark_rows(T: int) -> tuple[K6AliveCandidateBenchmarkRow, ...]:
    if T <= 0:
        raise ValueError("T must be positive")
    zero = (0, 0, 0, 0, 0, 0)
    optimal = optimal_values(6, T)[T][zero]
    one_run_value = _library_lp_value_layers(6, T, _strategy_class_library_actions(6, T, "one_run"))[T][zero]

    rows: list[K6AliveCandidateBenchmarkRow] = []
    for name, (variant, death_mode) in _k6_alive_candidate_policy_specs().items():
        policy_fn = _resolve_time_dependent_policy(6, name)
        if policy_fn is None:
            raise ValueError(f"unknown k=6 alive candidate policy: {name}")
        values = evaluate_time_dependent_policy(6, T, policy_fn)
        value = values[T][zero]
        gap_to_optimal = optimal - value
        gap_to_one_run = one_run_value - value
        alive_histogram, pattern_histogram = _k6_alive_candidate_histograms(T, variant, death_mode)
        rows.append(
            K6AliveCandidateBenchmarkRow(
                T=T,
                name=name,
                value=value,
                optimal_value=optimal,
                gap_to_optimal=gap_to_optimal,
                normalized_gap_to_optimal=gap_to_optimal / (T ** 0.5),
                one_run_value=one_run_value,
                gap_to_one_run=gap_to_one_run,
                normalized_gap_to_one_run=gap_to_one_run / (T ** 0.5),
                alive_count_histogram=alive_histogram,
                pattern_usage_histogram=pattern_histogram,
            )
        )
    return tuple(rows)


def print_k6_alive_candidate_benchmark(T_values: tuple[int, ...]) -> None:
    print("k=6 alive-prefix candidate benchmark")
    print()
    print(f"T values: {T_values}")
    print()
    for T in T_values:
        zero = (0, 0, 0, 0, 0, 0)
        optimal = optimal_values(6, T)[T][zero]
        reference_values: dict[str, float] = {}
        for library_name in ("top_prefix_all", "one_run", "two_run", "local_edges"):
            actions = _strategy_class_library_actions(6, T, library_name)
            reference_values[library_name] = _library_lp_value_layers(6, T, actions)[T][zero]

        print(f"k=6 T={T}")
        print("Reference values:")
        print(f"  V_star: {optimal:.6f}")
        for library_name in ("top_prefix_all", "one_run", "two_run", "local_edges"):
            value = reference_values[library_name]
            gap = optimal - value
            print(
                f"  {library_name:14s}"
                f" V={value:.6f}"
                f" gap={gap:.6f}"
                f" gap/sqrt(T)={gap / (T ** 0.5):.6f}"
            )
        print()
        print(
            "policy                                      V_policy"
            " gap_to_V_star gap/sqrt(T) gap_to_one_run gap_to_one_run/sqrt(T)"
        )
        for row in sorted(k6_alive_candidate_benchmark_rows(T), key=lambda item: (item.normalized_gap_to_optimal, item.name)):
            print(
                f"{row.name:42s}"
                f" {row.value:10.6f}"
                f" {row.gap_to_optimal:13.6f}"
                f" {row.normalized_gap_to_optimal:11.6f}"
                f" {row.gap_to_one_run:14.6f}"
                f" {row.normalized_gap_to_one_run:22.6f}"
            )
            rendered_alive = ", ".join(f"{alive}:{weight:.6f}" for alive, weight in row.alive_count_histogram)
            rendered_patterns = ", ".join(
                f"{pattern}:{weight:.6f}" for pattern, weight in row.pattern_usage_histogram[:8]
            )
            print(f"  alive_count occupancy: {rendered_alive}")
            print(f"  pattern usage: {rendered_patterns}")
        print()


def k6_one_run_interval_rule_rows(
    T: int,
    support_tolerance: float = 1e-8,
) -> tuple[K6OneRunIntervalRuleRow, ...]:
    _, dual_rows = library_lp_dual_inspect_rows(6, T, "one_run", support_tolerance=support_tolerance)
    rows: list[K6OneRunIntervalRuleRow] = []
    for row in dual_rows:
        support_rows: list[K6OneRunIntervalActionRow] = []
        for weight, action, edge_signature in row.support:
            interval = _one_run_interval_from_edge_signature(edge_signature)
            next_state = canon(tuple(row.state[index] + action[index] for index in range(6)))
            support_rows.append(
                K6OneRunIntervalActionRow(
                    weight=weight,
                    action=action,
                    edge_signature=edge_signature,
                    interval=interval,
                    relation_class=_classify_k6_one_run_interval_relation(interval, row.state),
                    successor_packet_type=packet_type(next_state),
                )
            )
        rows.append(
            K6OneRunIntervalRuleRow(
                time=row.time,
                remaining_horizon=row.remaining_horizon,
                state=row.state,
                packet_type=row.packet_type,
                packet_gaps=row.packet_gaps,
                adjacent_gaps=row.adjacent_gaps,
                occupancy_probability=row.occupancy_probability,
                value=row.value,
                learner_distribution=row.learner_distribution,
                alive_count=_alive_prefix_length(row.state, row.remaining_horizon),
                support=tuple(sorted(support_rows, key=lambda item: (-item.weight, _format_action(item.action)))),
            )
        )
    return tuple(rows)


def _candidate_policy_patterns(policy: tuple[tuple[float, tuple[int, ...]], ...]) -> tuple[str, ...]:
    return tuple(
        f"{_format_action(action)}:{_format_fractionish(probability)}"
        for probability, action in sorted(policy, key=lambda item: _format_action(item[1]))
    )


def k6_one_run_candidate_failure_rows(
    T: int,
    policy_names: tuple[str, ...] = (
        "k6_alive_trunc_comb_policy",
        "k6_alive_full_comb_control_policy",
    ),
    support_tolerance: float = 1e-8,
) -> tuple[K6OneRunCandidateFailureRow, ...]:
    one_run_actions = _strategy_class_library_actions(6, T, "one_run")
    one_run_values = _library_lp_value_layers(6, T, one_run_actions)
    interval_rows_by_key = {
        (row.time, row.state): row
        for row in k6_one_run_interval_rule_rows(T, support_tolerance=support_tolerance)
    }
    rows: list[K6OneRunCandidateFailureRow] = []
    for policy_name in policy_names:
        policy_fn = _resolve_time_dependent_policy(6, policy_name)
        if policy_fn is None:
            raise ValueError(f"unknown candidate policy: {policy_name}")
        occupancy = _time_policy_occupancy(6, T, policy_fn)
        for time in range(T):
            remaining_horizon = T - time
            continuation = one_run_values[remaining_horizon - 1]
            for state, probability in occupancy[time].items():
                policy = policy_fn(state, remaining_horizon)
                candidate_step = _time_policy_step_value(6, state, policy, continuation)
                one_run_value = one_run_values[remaining_horizon][state]
                action_loss = one_run_value - candidate_step
                interval_row = interval_rows_by_key.get((time, state))
                if interval_row is None:
                    # The candidate can drift outside the one-run LP occupancy basin; inspect
                    # its local one-run dual anyway without assigning LP occupancy.
                    q_by_action = {
                        action: _next_state_value(state, action, continuation)
                        for action in one_run_actions
                    }
                    dual = solve_adversary_dual(q_by_action, 6)
                    if not dual.success:
                        raise RuntimeError(f"dual LP failed at state {state}: {dual.message}")
                    support = tuple(
                        K6OneRunIntervalActionRow(
                            weight=weight,
                            action=action,
                            edge_signature=_edge_signature(action),
                            interval=_one_run_interval_from_edge_signature(_edge_signature(action)),
                            relation_class=_classify_k6_one_run_interval_relation(
                                _one_run_interval_from_edge_signature(_edge_signature(action)),
                                state,
                            ),
                            successor_packet_type=packet_type(canon(tuple(state[index] + action[index] for index in range(6)))),
                        )
                        for action, weight in dual.weights_by_action
                        if weight >= support_tolerance
                    )
                else:
                    support = interval_row.support
                interval_distribution = _interval_distribution_for_interval_support(support)
                dominant_interval = interval_distribution[0][0] if interval_distribution else None
                dominant_relation = next(
                    (item.relation_class for item in support if item.interval == dominant_interval),
                    "-",
                )
                rows.append(
                    K6OneRunCandidateFailureRow(
                        policy_name=policy_name,
                        time=time,
                        remaining_horizon=remaining_horizon,
                        state=state,
                        packet_type=packet_type(state),
                        packet_gaps=_packet_gaps(state),
                        adjacent_gaps=_gap_vector(state),
                        occupancy_probability=probability,
                        one_run_value=one_run_value,
                        candidate_step_value_on_one_run_continuation=candidate_step,
                        action_loss=action_loss,
                        weighted_action_loss=probability * action_loss,
                        candidate_actions=tuple(policy),
                        candidate_patterns=_candidate_policy_patterns(tuple(policy)),
                        lp_interval_distribution=interval_distribution,
                        lp_dominant_interval=dominant_interval,
                        lp_dominant_relation=dominant_relation,
                    )
                )
    return tuple(rows)


def _k6_one_run_candidate_failure_rows_for_policy(
    T: int,
    policy_name: str,
    policy_fn,
    one_run_actions: tuple[tuple[int, ...], ...],
    one_run_values: tuple[dict[tuple[int, ...], float], ...],
    interval_rows_by_key: dict[tuple[int, tuple[int, ...]], K6OneRunIntervalRuleRow],
    support_tolerance: float = 1e-8,
) -> tuple[K6OneRunCandidateFailureRow, ...]:
    rows: list[K6OneRunCandidateFailureRow] = []
    occupancy = _time_policy_occupancy(6, T, policy_fn)
    for time in range(T):
        remaining_horizon = T - time
        continuation = one_run_values[remaining_horizon - 1]
        for state, probability in occupancy[time].items():
            policy = policy_fn(state, remaining_horizon)
            candidate_step = _time_policy_step_value(6, state, policy, continuation)
            one_run_value = one_run_values[remaining_horizon][state]
            action_loss = one_run_value - candidate_step
            interval_row = interval_rows_by_key.get((time, state))
            if interval_row is None:
                q_by_action = {
                    action: _next_state_value(state, action, continuation)
                    for action in one_run_actions
                }
                dual = solve_adversary_dual(q_by_action, 6)
                if not dual.success:
                    raise RuntimeError(f"dual LP failed at state {state}: {dual.message}")
                support = tuple(
                    K6OneRunIntervalActionRow(
                        weight=weight,
                        action=action,
                        edge_signature=_edge_signature(action),
                        interval=_one_run_interval_from_edge_signature(_edge_signature(action)),
                        relation_class=_classify_k6_one_run_interval_relation(
                            _one_run_interval_from_edge_signature(_edge_signature(action)),
                            state,
                        ),
                        successor_packet_type=packet_type(canon(tuple(state[index] + action[index] for index in range(6)))),
                    )
                    for action, weight in dual.weights_by_action
                    if weight >= support_tolerance
                )
            else:
                support = interval_row.support
            interval_distribution = _interval_distribution_for_interval_support(support)
            dominant_interval = interval_distribution[0][0] if interval_distribution else None
            dominant_relation = next(
                (item.relation_class for item in support if item.interval == dominant_interval),
                "-",
            )
            rows.append(
                K6OneRunCandidateFailureRow(
                    policy_name=policy_name,
                    time=time,
                    remaining_horizon=remaining_horizon,
                    state=state,
                    packet_type=packet_type(state),
                    packet_gaps=_packet_gaps(state),
                    adjacent_gaps=_gap_vector(state),
                    occupancy_probability=probability,
                    one_run_value=one_run_value,
                    candidate_step_value_on_one_run_continuation=candidate_step,
                    action_loss=action_loss,
                    weighted_action_loss=probability * action_loss,
                    candidate_actions=tuple(policy),
                    candidate_patterns=_candidate_policy_patterns(tuple(policy)),
                    lp_interval_distribution=interval_distribution,
                    lp_dominant_interval=dominant_interval,
                    lp_dominant_relation=dominant_relation,
                )
            )
    return tuple(rows)


def _k6_patch_name_from_key(
    remaining_horizon: int,
    ptype: tuple[int, ...],
    gaps: tuple[int, ...],
    interval: tuple[int, int],
) -> str:
    packet_part = "".join(str(item) for item in ptype)
    gap_part = "".join(str(item) for item in gaps) or "flat"
    return f"g_rem{remaining_horizon}_{packet_part}_g{gap_part}_i{interval[0]}{interval[1]}"


def _k6_greedy_patch_candidates_from_failures(
    failures: tuple[K6OneRunCandidateFailureRow, ...],
    existing_patches: tuple[K6OneRunPatch, ...],
    candidate_n: int,
) -> tuple[K6OneRunPatch, ...]:
    existing_regimes = {
        (patch.remaining_horizon, patch.packet_type, patch.packet_gaps)
        for patch in existing_patches
    }
    weighted_losses: dict[tuple[int, tuple[int, ...], tuple[int, ...], tuple[int, int]], float] = defaultdict(float)
    for failure in failures:
        interval = failure.lp_dominant_interval
        if interval is None or failure.weighted_action_loss <= 1e-12:
            continue
        regime = (failure.remaining_horizon, failure.packet_type, failure.packet_gaps)
        if regime in existing_regimes:
            continue
        weighted_losses[regime + (interval,)] += failure.weighted_action_loss
    patches: list[K6OneRunPatch] = []
    for (remaining_horizon, ptype, gaps, interval), _ in sorted(
        weighted_losses.items(),
        key=lambda item: (-item[1], item[0]),
    )[:candidate_n]:
        patches.append(
            K6OneRunPatch(
                name=_k6_patch_name_from_key(remaining_horizon, ptype, gaps, interval),
                remaining_horizon=remaining_horizon,
                packet_type=ptype,
                packet_gaps=gaps,
                interval=interval,
            )
        )
    return tuple(patches)


def _matching_k6_mixed_patch(
    state: tuple[int, ...],
    remaining_horizon: int,
    patches: tuple[MixedIntervalPatch, ...],
) -> MixedIntervalPatch | None:
    canonical_state = canon(state)
    ptype = packet_type(canonical_state)
    gaps = _packet_gaps(canonical_state)
    for patch in patches:
        if (
            patch.remaining_horizon == remaining_horizon
            and patch.packet_type == ptype
            and patch.packet_gaps == gaps
        ):
            return patch
    return None


def make_k6_one_run_mixed_patch_policy(
    base_policy_name: str,
    deterministic_patches: tuple[K6OneRunPatch, ...],
    mixed_patches: tuple[MixedIntervalPatch, ...],
):
    base_policy = make_k6_one_run_patch_policy_from_patches(base_policy_name, deterministic_patches)

    def policy(
        state: tuple[int, ...],
        remaining_horizon: int,
    ) -> tuple[tuple[float, tuple[int, ...]], ...]:
        canonical_state = canon(state)
        if len(canonical_state) == 6:
            patch = _matching_k6_mixed_patch(canonical_state, remaining_horizon, mixed_patches)
            if patch is not None:
                return _mixed_one_run_interval_policy(6, patch.weighted_intervals)
        return base_policy(canonical_state, remaining_horizon)

    return policy


def _k6_mixed_patch_name_from_key(
    remaining_horizon: int,
    ptype: tuple[int, ...],
    gaps: tuple[int, ...],
) -> str:
    packet_part = "".join(str(item) for item in ptype)
    gap_part = "".join(str(item) for item in gaps) or "flat"
    return f"m_rem{remaining_horizon}_{packet_part}_g{gap_part}"


def _k6_mixed_patch_candidates_from_failures(
    T: int,
    failures: tuple[K6OneRunCandidateFailureRow, ...],
    existing_mixed_patches: tuple[MixedIntervalPatch, ...],
    candidate_n: int,
    distributions_by_regime: dict[
        tuple[int, tuple[int, ...], tuple[int, ...]],
        tuple[tuple[float, tuple[int, int]], ...],
    ] | None = None,
    support_tolerance: float = 1e-8,
) -> tuple[MixedIntervalPatch, ...]:
    existing_regimes = {
        (patch.remaining_horizon, patch.packet_type, patch.packet_gaps)
        for patch in existing_mixed_patches
    }
    weighted_losses: dict[tuple[int, tuple[int, ...], tuple[int, ...]], float] = defaultdict(float)
    for failure in failures:
        if failure.weighted_action_loss <= 1e-12:
            continue
        regime = (failure.remaining_horizon, failure.packet_type, failure.packet_gaps)
        if regime in existing_regimes:
            continue
        weighted_losses[regime] += failure.weighted_action_loss
    patches: list[MixedIntervalPatch] = []
    for (remaining_horizon, ptype, gaps), _ in sorted(
        weighted_losses.items(),
        key=lambda item: (-item[1], item[0]),
    )[:candidate_n]:
        if distributions_by_regime is None:
            weighted_intervals = _one_run_interval_distribution_for_regime(
                6,
                T,
                remaining_horizon,
                ptype,
                gaps,
                support_tolerance=support_tolerance,
            )
        else:
            weighted_intervals = distributions_by_regime.get((remaining_horizon, ptype, gaps), ())
        if not weighted_intervals:
            continue
        patches.append(
            MixedIntervalPatch(
                name=_k6_mixed_patch_name_from_key(remaining_horizon, ptype, gaps),
                remaining_horizon=remaining_horizon,
                packet_type=ptype,
                packet_gaps=gaps,
                weighted_intervals=weighted_intervals,
            )
        )
    return tuple(patches)


def _k6_failure_summary(
    failures: tuple[K6OneRunCandidateFailureRow, ...],
    n: int = 10,
) -> tuple[tuple[str, float], ...]:
    summary: dict[str, float] = defaultdict(float)
    for failure in failures:
        key = (
            f"rem={failure.remaining_horizon}"
            f" packet={failure.packet_type}"
            f" gaps={failure.packet_gaps}"
            f" lp={_format_interval(failure.lp_dominant_interval)}"
        )
        summary[key] += failure.weighted_action_loss
    return tuple(sorted(summary.items(), key=lambda item: (-item[1], item[0]))[:n])


def k6_one_run_greedy_patch_search_steps(
    T: int,
    max_patches: int = 20,
    candidate_n: int = 50,
    support_tolerance: float = 1e-8,
) -> tuple[K6GreedyPatchSearchStep, ...]:
    zero = (0, 0, 0, 0, 0, 0)
    one_run_actions = _strategy_class_library_actions(6, T, "one_run")
    one_run_values = _library_lp_value_layers(6, T, one_run_actions)
    one_run_value = one_run_values[T][zero]
    top_prefix_value = _library_lp_value_layers(6, T, _strategy_class_library_actions(6, T, "top_prefix_all"))[T][zero]
    interval_rows_by_key = {
        (row.time, row.state): row
        for row in k6_one_run_interval_rule_rows(T, support_tolerance=support_tolerance)
    }

    patches = tuple(_k6_one_run_patch_list()[:5])
    steps: list[K6GreedyPatchSearchStep] = []
    current_policy = make_k6_one_run_patch_policy_from_patches("k6_alive_full_comb_control_policy", patches)
    current_value = evaluate_time_dependent_policy(6, T, current_policy)[T][zero]

    for step in range(max_patches + 1):
        failures = _k6_one_run_candidate_failure_rows_for_policy(
            T,
            "k6_greedy_current",
            current_policy,
            one_run_actions,
            one_run_values,
            interval_rows_by_key,
            support_tolerance=support_tolerance,
        )
        if step == 0:
            steps.append(
                K6GreedyPatchSearchStep(
                    step=step,
                    selected_patch=None,
                    improvement=0.0,
                    value=current_value,
                    one_run_value=one_run_value,
                    normalized_gap_to_one_run=(one_run_value - current_value) / (T ** 0.5),
                    top_prefix_value=top_prefix_value,
                    gap_to_top_prefix=current_value - top_prefix_value,
                    rejected_candidates=(),
                    top_failure_summaries=_k6_failure_summary(failures),
                )
            )
            if max_patches == 0:
                break
            continue
        candidates = _k6_greedy_patch_candidates_from_failures(failures, patches, candidate_n)
        evaluations: list[tuple[K6OneRunPatch, float]] = []
        best_patch: K6OneRunPatch | None = None
        best_value = current_value
        for candidate in candidates:
            candidate_policy = make_k6_one_run_patch_policy_from_patches(
                "k6_alive_full_comb_control_policy",
                patches + (candidate,),
            )
            value = evaluate_time_dependent_policy(6, T, candidate_policy)[T][zero]
            improvement = value - current_value
            evaluations.append((candidate, improvement))
            if improvement > best_value - current_value + 1e-12:
                best_patch = candidate
                best_value = value
        rejected = tuple(sorted(evaluations, key=lambda item: (-item[1], item[0].name))[:10])
        if best_patch is not None and best_value > current_value + 1e-12:
            selected_patch: K6OneRunPatch | None = best_patch
            improvement = best_value - current_value
            next_value = best_value
        else:
            selected_patch = None
            improvement = 0.0
            next_value = current_value
        next_failures = failures
        if selected_patch is None:
            steps.append(
                K6GreedyPatchSearchStep(
                    step=step,
                    selected_patch=None,
                    improvement=0.0,
                    value=current_value,
                    one_run_value=one_run_value,
                    normalized_gap_to_one_run=(one_run_value - current_value) / (T ** 0.5),
                    top_prefix_value=top_prefix_value,
                    gap_to_top_prefix=current_value - top_prefix_value,
                    rejected_candidates=rejected,
                    top_failure_summaries=_k6_failure_summary(next_failures),
                )
            )
            break
        patches = patches + (selected_patch,)
        current_value = next_value
        current_policy = make_k6_one_run_patch_policy_from_patches("k6_alive_full_comb_control_policy", patches)
        next_failures = _k6_one_run_candidate_failure_rows_for_policy(
            T,
            "k6_greedy_current",
            current_policy,
            one_run_actions,
            one_run_values,
            interval_rows_by_key,
            support_tolerance=support_tolerance,
        )
        steps.append(
            K6GreedyPatchSearchStep(
                step=step,
                selected_patch=selected_patch,
                improvement=improvement,
                value=next_value,
                one_run_value=one_run_value,
                normalized_gap_to_one_run=(one_run_value - next_value) / (T ** 0.5),
                top_prefix_value=top_prefix_value,
                gap_to_top_prefix=next_value - top_prefix_value,
                rejected_candidates=rejected,
                top_failure_summaries=_k6_failure_summary(next_failures),
            )
        )
    return tuple(steps)


