def _binomial_probability(n: int, k: int) -> float:
    if k < 0 or k > n:
        return 0.0
    return comb(n, k) / (2.0 ** n)


def _top3_ballot_candidates(n: int, a: int, exact_value: float) -> tuple[float, float, float, str, float]:
    central_index = (n - a) // 2
    central = _binomial_probability(n, central_index) if (n - a) % 2 == 0 else 0.0
    adjacent = central - _binomial_probability(n, central_index - 1)
    ballot = ((a + 1) / (n + 1)) * central if n >= 0 else 0.0
    candidates = {
        "central_binomial": central,
        "signed_central": ((-1) ** (n - a)) * central,
        "adjacent_difference": adjacent,
        "signed_adjacent_difference": ((-1) ** (n - a)) * adjacent,
        "ballot": ballot,
        "signed_ballot": ((-1) ** (n - a)) * ballot,
    }
    best_name, best_value = min(candidates.items(), key=lambda item: abs(exact_value - item[1]))
    return central, adjacent, ballot, best_name, abs(exact_value - best_value)


def k5_top3_ballot_candidate_rows(
    a_values: tuple[int, ...] = (1, 2, 3, 4, 5, 7),
    n_values: tuple[int, ...] = (0, 1, 2, 3, 4, 5, 10, 20),
) -> tuple[K5Top3BallotCandidateRow, ...]:
    rows: list[K5Top3BallotCandidateRow] = []
    for a in a_values:
        for n_value in n_values:
            for name, exact in (
                ("A", _top3_a_term(n_value, a)),
                ("k", _top3_kernel_term(n_value, a)),
            ):
                central, adjacent, ballot, best_name, best_error = _top3_ballot_candidates(n_value, a, exact)
                rows.append(
                    K5Top3BallotCandidateRow(
                        name=name,
                        n=n_value,
                        a=a,
                        exact_value=exact,
                        central_binomial=central,
                        adjacent_difference=adjacent,
                        ballot_value=ballot,
                        best_candidate=best_name,
                        best_abs_error=best_error,
                    )
                )
    return tuple(rows)


