@lru_cache(maxsize=None)
def _top3_r0_probability_fraction(t: int, r: int, s: int) -> Fraction:
    if t == 0:
        return Fraction(1) if r == 0 else Fraction(0)
    plus_r, plus_s, _ = _top3_plus_transition(r, s)
    minus_r, minus_s, _ = _top3_minus_transition(r, s)
    return Fraction(1, 2) * _top3_r0_probability_fraction(t - 1, plus_r, plus_s) + Fraction(1, 2) * _top3_r0_probability_fraction(t - 1, minus_r, minus_s)


def _top3_a_term_fraction(t: int, a: int) -> Fraction:
    return _top3_r0_probability_fraction(t, a, 1) - _top3_r0_probability_fraction(t, a + 1, 0)


def _top3_b_term_fraction(t: int, a: int) -> Fraction:
    return _top3_r0_probability_fraction(t, a - 1, 1) - _top3_r0_probability_fraction(t, a, 0)


def _top3_c_term_fraction(t: int, a: int) -> Fraction:
    return _top3_r0_probability_fraction(t, a, 0) - _top3_r0_probability_fraction(t, a + 1, 0)


def _top3_k_term_fraction(t: int, a: int) -> Fraction:
    return Fraction(1, 2) * _top3_b_term_fraction(t, a) + Fraction(1, 2) * _top3_c_term_fraction(t, a) - Fraction(3, 2) * _top3_a_term_fraction(t, a)


def _fraction_sequence_for_endpoint(name: str, a: int, length: int) -> tuple[Fraction, ...]:
    if length < 0:
        raise ValueError(f"length must be nonnegative, got {length}")
    if name == "A":
        return tuple(_top3_a_term_fraction(t, a) for t in range(length))
    if name == "k":
        return tuple(_top3_k_term_fraction(t, a) for t in range(length))
    raise ValueError(f"unknown endpoint sequence: {name}")


def _solve_fraction_linear_system(
    matrix: list[list[Fraction]],
    rhs: list[Fraction],
) -> tuple[Fraction, ...] | None:
    size = len(rhs)
    augmented = [row[:] + [rhs_value] for row, rhs_value in zip(matrix, rhs, strict=True)]
    for col in range(size):
        pivot = next((row for row in range(col, size) if augmented[row][col] != 0), None)
        if pivot is None:
            return None
        if pivot != col:
            augmented[col], augmented[pivot] = augmented[pivot], augmented[col]
        pivot_value = augmented[col][col]
        augmented[col] = [value / pivot_value for value in augmented[col]]
        for row in range(size):
            if row == col:
                continue
            factor = augmented[row][col]
            if factor == 0:
                continue
            augmented[row] = [
                value - factor * pivot_entry
                for value, pivot_entry in zip(augmented[row], augmented[col], strict=True)
            ]
    return tuple(augmented[row][-1] for row in range(size))


def _guess_constant_recurrence(
    sequence: tuple[Fraction, ...],
    max_order: int = 12,
    fit_terms: int | None = None,
) -> tuple[tuple[Fraction, ...], int] | None:
    usable = sequence if fit_terms is None else sequence[:fit_terms]
    for order in range(1, min(max_order, (len(usable) - 1) // 2) + 1):
        matrix = []
        rhs = []
        for n_index in range(order, 2 * order):
            matrix.append([usable[n_index - lag] for lag in range(1, order + 1)])
            rhs.append(usable[n_index])
        coefficients = _solve_fraction_linear_system(matrix, rhs)
        if coefficients is None:
            continue
        fits = True
        for n_index in range(order, len(usable)):
            predicted = sum(coefficients[lag - 1] * usable[n_index - lag] for lag in range(1, order + 1))
            if predicted != usable[n_index]:
                fits = False
                break
        if fits:
            return coefficients, order
    return None


def _recurrence_generating_function_parts(
    sequence: tuple[Fraction, ...],
    coefficients: tuple[Fraction, ...],
) -> tuple[tuple[Fraction, ...], tuple[Fraction, ...]]:
    # Denominator Q(z)=1-c1 z-...-cd z^d.
    denominator = (Fraction(1),) + tuple(-coeff for coeff in coefficients)
    numerator: list[Fraction] = []
    for n_index in range(len(coefficients)):
        correction = sum(
            coefficients[lag - 1] * sequence[n_index - lag]
            for lag in range(1, n_index + 1)
        )
        numerator.append(sequence[n_index] - correction)
    return tuple(numerator), denominator


def _format_fraction(value: Fraction) -> str:
    if value.denominator == 1:
        return str(value.numerator)
    return f"{value.numerator}/{value.denominator}"


def _format_polynomial(coefficients: tuple[Fraction, ...], variable: str = "z") -> str:
    pieces: list[str] = []
    for power, coeff in enumerate(coefficients):
        if coeff == 0:
            continue
        coeff_abs = abs(coeff)
        if power == 0:
            monomial = _format_fraction(coeff_abs)
        elif power == 1:
            monomial = variable if coeff_abs == 1 else f"{_format_fraction(coeff_abs)}{variable}"
        else:
            monomial = f"{variable}^{power}" if coeff_abs == 1 else f"{_format_fraction(coeff_abs)}{variable}^{power}"
        if not pieces:
            pieces.append(monomial if coeff > 0 else f"-{monomial}")
        else:
            pieces.append(f" {'+' if coeff > 0 else '-'} {monomial}")
    return "".join(pieces) if pieces else "0"


def k5_top3_discrepancy_generating_recurrence_rows(
    a_values: tuple[int, ...] = (1, 2, 3, 4),
    sequence_names: tuple[str, ...] = ("A", "k"),
    fit_terms: int = 60,
    validate_terms: int = 200,
    max_order: int = 12,
) -> tuple[K5Top3GuessedRecurrenceRow, ...]:
    _ensure_top3_recursion_limit(validate_terms)
    rows: list[K5Top3GuessedRecurrenceRow] = []
    for name in sequence_names:
        for a in a_values:
            sequence = _fraction_sequence_for_endpoint(name, a, validate_terms + 1)
            guessed = _guess_constant_recurrence(sequence, max_order=max_order, fit_terms=fit_terms)
            if guessed is None:
                rows.append(
                    K5Top3GuessedRecurrenceRow(
                        name=name,
                        a=a,
                        order=None,
                        coefficients=(),
                        denominator=(),
                        numerator=(),
                        fit_terms=fit_terms,
                        validate_terms=validate_terms,
                        max_validate_residual=None,
                    )
                )
                continue
            coefficients, order = guessed
            max_residual = Fraction(0)
            for n_index in range(order, validate_terms + 1):
                predicted = sum(coefficients[lag - 1] * sequence[n_index - lag] for lag in range(1, order + 1))
                max_residual = max(max_residual, abs(sequence[n_index] - predicted))
            numerator, denominator = _recurrence_generating_function_parts(sequence, coefficients)
            rows.append(
                K5Top3GuessedRecurrenceRow(
                    name=name,
                    a=a,
                    order=order,
                    coefficients=coefficients,
                    denominator=denominator,
                    numerator=numerator,
                    fit_terms=fit_terms,
                    validate_terms=validate_terms,
                    max_validate_residual=max_residual,
                )
            )
    return tuple(rows)


def print_k5_top3_discrepancy_generating_function_report(
    a_values: tuple[int, ...] = (1, 2, 3, 4),
    n_values: tuple[int, ...] = (0, 1, 2, 3, 4, 5, 10, 20),
    fit_terms: int = 60,
    validate_terms: int = 200,
    max_order: int = 12,
    n: int = 40,
) -> None:
    print("discrepancy generating function report")
    print()
    print("1. Finite discrepancy transition system")
    print("A/B discrepancy labels: cross=(1,-1), same=(0,1), reflected=(-1,0)")
    print("C discrepancy labels:   same=(1,0), cross=(0,-1), reflected=(-1,1)")
    print("The base coordinate is retained; boundary output is the signed indicator of which chain has R=0.")
    print()

    print("2. Sample exact values")
    print("name a n value")
    sample_count = 0
    for a in a_values:
        for n_value in n_values:
            for name, value in (
                ("A", _top3_a_term_fraction(n_value, a)),
                ("k", _top3_k_term_fraction(n_value, a)),
            ):
                if sample_count >= n:
                    break
                print(f"{name:1s} {a:3d} {n_value:3d} {_format_fraction(value)}")
                sample_count += 1
            if sample_count >= n:
                break
        if sample_count >= n:
            break

    print()
    print("3. guessed recurrence")
    print("name a order coefficients max_validate_residual generating_function")
    rows = k5_top3_discrepancy_generating_recurrence_rows(
        a_values=a_values,
        fit_terms=fit_terms,
        validate_terms=validate_terms,
        max_order=max_order,
    )
    for row in rows:
        if row.order is None:
            print(f"{row.name:1s} {row.a:3d} none - - no recurrence found up to order {max_order}")
            continue
        coeff_text = ",".join(_format_fraction(coeff) for coeff in row.coefficients)
        residual_text = "-" if row.max_validate_residual is None else _format_fraction(row.max_validate_residual)
        numerator_text = _format_polynomial(row.numerator)
        denominator_text = _format_polynomial(row.denominator)
        print(
            f"{row.name:1s}"
            f" {row.a:3d}"
            f" {row.order:3d}"
            f" [{coeff_text}]"
            f" {residual_text}"
            f" ({numerator_text})/({denominator_text})"
        )

    print()
    print("4. Recurrences in a / two-dimensional recurrence search")
    print("The top3 recurrence gives an exact two-dimensional system without guessing:")
    print(r"\[")
    print(r"p_{t+1}(r,s)=\frac12p_t(P(r,s))+\frac12p_t(N(r,s)).")
    print(r"\]")
    print("Substituting the adjacent-start definitions yields the A/B/C/k recurrences printed in the endpoint-barrier report.")
    print("The constant-coefficient one-dimensional recurrences above are fixed-a shadows of this finite discrepancy system.")

    print()
    print("5. Binomial/Catalan/ballot search")
    print("name n a exact central_binom adjacent_diff ballot best_candidate best_abs_error")
    for row in k5_top3_ballot_candidate_rows(a_values=a_values, n_values=n_values)[:n]:
        print(
            f"{row.name:1s}"
            f" {row.n:3d}"
            f" {row.a:3d}"
            f" {row.exact_value:+.12f}"
            f" {row.central_binomial:.12f}"
            f" {row.adjacent_difference:.12f}"
            f" {row.ballot_value:.12f}"
            f" {row.best_candidate:26s}"
            f" {row.best_abs_error:.12f}"
        )
    print("Naive single-term ballot templates are diagnostic only; the finite discrepancy recurrence is the exact object.")

    print()
    print("6. endpoint coefficient bound")
    print("If the generating functions above have coefficients satisfying")
    print(r"\[")
    print(r"|[z^n]A_a(z)|\le (n+1)^{-1},\qquad |[z^n]k_a(z)|\le \frac32(n+1)^{-1},")
    print(r"\]")
    print("then the endpoint barrier follows for fixed a. Uniformity in a remains the theorem-level task.")
    print("The guessed recurrences give exact rational generating functions for each fixed sampled a when residual=0.")

    print()
    print("7. Proof-ready theorem template")
    print("For each fixed a, A_a(z) and k_a(z) are rational functions obtained from the finite discrepancy chain.")
    print("A uniform coefficient bound over a implies the endpoint barrier and therefore the K_n(a)=O((n+1)^-1) estimate.")


def _top3_signed_endpoint_value(name: str, n: int, a: int) -> float:
    if name == "A":
        return ((-1) ** (n - a)) * _top3_a_term(n, a)
    if name == "k":
        return ((-1) ** (n - a + 1)) * _top3_kernel_term(n, a)
    if name == "B":
        return ((-1) ** (n - a + 1)) * _top3_b_term(n, a)
    if name == "C":
        return ((-1) ** (n - a)) * _top3_c_term(n, a)
    if name == "D":
        return ((-1) ** (n - a + 1)) * _top3_d_term(n, a)
    raise ValueError(f"unknown signed endpoint family: {name}")


def _top3_barrier_denominator(barrier: str, n: int, a: int) -> float:
    if barrier == "n":
        return float(n + 1)
    if barrier == "n+a":
        return float(n + 1 + a)
    if barrier == "sqrt-cutoff":
        scale = (n + 1) ** 0.5
        factor = min(1.0, a / scale) if scale > 0 else 1.0
        return float(n + 1) / max(factor, 1e-300)
    if barrier == "affine-a":
        # This is reported as a ratio against basis (1+a/(n+1))/(n+1).
        return float(n + 1) / (1.0 + a / (n + 1))
    raise ValueError(f"unknown barrier: {barrier}")


def k5_top3_discrepancy_barrier_certificate_rows(
    max_n: int = 2000,
    dense_a_limit: int = 300,
    families: tuple[str, ...] = ("A", "k"),
    barriers: tuple[str, ...] = ("n", "n+a", "sqrt-cutoff", "affine-a"),
) -> tuple[K5Top3BarrierCertificateRow, ...]:
    if max_n < 0:
        raise ValueError(f"max_n must be nonnegative, got {max_n}")
    if dense_a_limit <= 0:
        raise ValueError(f"dense_a_limit must be positive, got {dense_a_limit}")
    _ensure_top3_recursion_limit(max_n)
    rows: list[K5Top3BarrierCertificateRow] = []
    for name in families:
        for barrier in barriers:
            max_ratio = -float("inf")
            worst_n = 0
            worst_a = 1
            worst_value = 0.0
            for n_value in range(max_n + 1):
                a_limit = min(n_value + 2, dense_a_limit)
                for a in range(1, a_limit + 1):
                    value = _top3_signed_endpoint_value(name, n_value, a)
                    denominator = _top3_barrier_denominator(barrier, n_value, a)
                    ratio = value * denominator
                    if ratio > max_ratio:
                        max_ratio = ratio
                        worst_n = n_value
                        worst_a = a
                        worst_value = value
            constant = max(max_ratio, 0.0)
            violations = 0
            worst_slack = float("inf")
            for n_value in range(max_n + 1):
                a_limit = min(n_value + 2, dense_a_limit)
                for a in range(1, a_limit + 1):
                    value = _top3_signed_endpoint_value(name, n_value, a)
                    bound = constant / _top3_barrier_denominator(barrier, n_value, a)
                    slack = bound - value
                    worst_slack = min(worst_slack, slack)
                    if slack < -1e-12:
                        violations += 1
            rows.append(
                K5Top3BarrierCertificateRow(
                    name=name,
                    barrier=barrier,
                    constant=constant,
                    max_ratio=max_ratio,
                    worst_n=worst_n,
                    worst_a=worst_a,
                    worst_value=worst_value,
                    worst_slack=worst_slack,
                    violations=violations,
                )
            )
    return tuple(rows)


def _top3_signed_recurrence_residuals(
    max_n: int,
    a_values: tuple[int, ...],
) -> tuple[tuple[str, float], ...]:
    residuals: dict[str, float] = {
        "Aplus_{n+1}=0.5(Dplus_n+Cplus_n(a+1)-Aplus_n(a+1))": 0.0,
        "kplus_sign_definition": 0.0,
    }
    for n_value in range(max_n):
        for a in a_values:
            lhs = _top3_signed_endpoint_value("A", n_value + 1, a)
            rhs = 0.5 * (
                _top3_signed_endpoint_value("D", n_value, a)
                + _top3_signed_endpoint_value("C", n_value, a + 1)
                - _top3_signed_endpoint_value("A", n_value, a + 1)
            )
            key = "Aplus_{n+1}=0.5(Dplus_n+Cplus_n(a+1)-Aplus_n(a+1))"
            residuals[key] = max(residuals[key], abs(lhs - rhs))
            kplus = _top3_signed_endpoint_value("k", n_value, a)
            direct = ((-1) ** (n_value - a + 1)) * _top3_kernel_term(n_value, a)
            residuals["kplus_sign_definition"] = max(
                residuals["kplus_sign_definition"],
                abs(kplus - direct),
            )
    return tuple(residuals.items())


def print_k5_top3_discrepancy_barrier_certificate_report(
    max_n: int = 2000,
    dense_a_limit: int = 300,
    recurrence_max_n: int = 80,
    recurrence_a_values: tuple[int, ...] = (1, 2, 3, 4, 5, 7, 9, 11),
    n: int = 40,
) -> None:
    print("discrepancy barrier certificate")
    print()
    print("1. signed recurrence")
    print(r"\[A^+_n(a)=(-1)^{n-a}A_n(a),\qquad k^+_n(a)=(-1)^{n-a+1}k_n(a).\]")
    print(r"\[B^+_n(a)=(-1)^{n-a+1}B_n(a),\quad C^+_n(a)=(-1)^{n-a}C_n(a),\quad D^+_n(a)=(-1)^{n-a+1}D_n(a).\]")
    print(r"\[")
    print(r"A^+_{n+1}(a)=\frac12\left(D^+_n(a)+C^+_n(a+1)-A^+_n(a+1)\right).")
    print(r"\]")
    print("recurrence residual checks:")
    for name, residual in _top3_signed_recurrence_residuals(recurrence_max_n, recurrence_a_values):
        print(f"  {name}: {residual:.3e}")

    print()
    print("2. signed nonnegativity scan")
    print("family min_signed max_signed first_negative")
    for family in ("A", "k", "B", "C", "D"):
        min_signed = float("inf")
        max_signed = -float("inf")
        first_negative: tuple[int, int, float] | None = None
        for n_value in range(min(max_n, recurrence_max_n) + 1):
            for a in range(1, min(n_value + 2, dense_a_limit, max(recurrence_a_values, default=1)) + 1):
                value = _top3_signed_endpoint_value(family, n_value, a)
                min_signed = min(min_signed, value)
                max_signed = max(max_signed, value)
                if first_negative is None and value < -1e-15:
                    first_negative = (n_value, a, value)
        print(f"  {family:1s} {min_signed:.12f} {max_signed:.12f} {first_negative}")

    print()
    print("3. super-solution barrier scan")
    print(f"grid: n <= {max_n}, 1 <= a <= min(n+2,{dense_a_limit})")
    print("family barrier constant worst_n worst_a worst_value worst_slack violations")
    rows = k5_top3_discrepancy_barrier_certificate_rows(
        max_n=max_n,
        dense_a_limit=dense_a_limit,
    )
    for row in rows:
        print(
            f"{row.name:1s}"
            f" {row.barrier:12s}"
            f" {row.constant:.12f}"
            f" {row.worst_n:5d}"
            f" {row.worst_a:5d}"
            f" {row.worst_value:.12f}"
            f" {row.worst_slack:.3e}"
            f" {row.violations:5d}"
        )

    print()
    print("4. LP-fit interpretation")
    print("For a barrier U(n,a)=c/basis(n,a), the minimal feasible c on the grid is max signed_value*basis.")
    print("The table above reports exactly that one-constant certificate for each family and basis.")
    print("The target endpoint constants correspond to A/n with c=1 and k/n with c=3/2.")

    print()
    print("5. worst slack")
    for family in ("A", "k"):
        family_rows = [row for row in rows if row.name == family]
        best = min(family_rows, key=lambda item: item.constant)
        print(
            f"  best {family}: barrier={best.barrier}"
            f" constant={best.constant:.12f}"
            f" worst=({best.worst_n},{best.worst_a})"
            f" slack={best.worst_slack:.3e}"
        )

    print()
    print("6. theorem-ready certificate")
    print("Does simple c/(n+1) close?")
    simple = {(row.name, row.barrier): row for row in rows}
    for family, target in (("A", 1.0), ("k", 1.5)):
        row = simple[(family, "n")]
        print(f"  {family}: observed c={row.constant:.12f}, target={target:.12f}, closes={row.constant <= target + 1e-12}")
    print("If the signed recurrences and parity nonnegativity are proved, the remaining endpoint-barrier lemma is:")
    print(r"\[")
    print(r"A^+_n(a)\le\frac1{n+1},\qquad k^+_n(a)\le\frac{3}{2(n+1)}.")
    print(r"\]")
    print("The scanned data suggests no a-dependent correction is needed for A or k; C/D may still be proof auxiliaries.")


def _top3_signed_aux_value(name: str, n: int, a: int) -> float:
    if name in {"A", "B", "C", "D", "k"}:
        return _top3_signed_endpoint_value(name, n, a)
    if name == "F":
        return ((-1) ** (n - a)) * _top3_f_term(n, a)
    raise ValueError(f"unknown signed auxiliary family: {name}")


def _top3_signed_recurrence_terms() -> dict[str, tuple[str, tuple[tuple[float, str, int], ...]]]:
    return {
        "A": (
            "A+_{n+1}(a)=0.5(D+_n(a)+C+_n(a+1)-A+_n(a+1))",
            ((0.5, "D", 0), (0.5, "C", 1), (-0.5, "A", 1)),
        ),
        "B": (
            "B+_{n+1}(a)=0.5(D+_n(a-1)+C+_n(a)-A+_n(a))",
            ((0.5, "D", -1), (0.5, "C", 0), (-0.5, "A", 0)),
        ),
        "C": (
            "C+_{n+1}(a)=0.5(B+_n(a)-C+_n(a)+C+_n(a+1)-A+_n(a+1))",
            ((0.5, "B", 0), (-0.5, "C", 0), (0.5, "C", 1), (-0.5, "A", 1)),
        ),
        "D": (
            "D+_{n+1}(a)=0.5(F+_n(a)+A+_n(a))",
            ((0.5, "F", 0), (0.5, "A", 0)),
        ),
    }


def _top3_aux_value_scan_constants(
    max_n: int,
    dense_a_limit: int,
    families: tuple[str, ...] = ("A", "B", "C", "D", "F", "k"),
) -> dict[str, tuple[float, float, tuple[int, int], tuple[int, int] | None]]:
    constants: dict[str, tuple[float, float, tuple[int, int], tuple[int, int] | None]] = {}
    for family in families:
        max_scaled = 0.0
        min_signed = float("inf")
        argmax = (0, 1)
        first_negative: tuple[int, int] | None = None
        for n_value in range(max_n + 1):
            a_limit = min(n_value + 2, dense_a_limit)
            for a in range(1, a_limit + 1):
                if family == "F" and a <= 1:
                    continue
                try:
                    value = _top3_signed_aux_value(family, n_value, a)
                except ValueError:
                    continue
                min_signed = min(min_signed, value)
                if first_negative is None and value < -1e-15:
                    first_negative = (n_value, a)
                scaled = (n_value + 1) * max(value, 0.0)
                if scaled > max_scaled:
                    max_scaled = scaled
                    argmax = (n_value, a)
        constants[family] = (max_scaled, min_signed, argmax, first_negative)
    return constants


def k5_top3_endpoint_induction_certificate_rows(
    max_n: int = 1000,
    dense_a_limit: int = 300,
    barrier: str = "n",
) -> tuple[K5Top3InductionStepRow, ...]:
    constants = _top3_aux_value_scan_constants(max_n=max_n, dense_a_limit=dense_a_limit)
    recurrence_terms = _top3_signed_recurrence_terms()
    rows: list[K5Top3InductionStepRow] = []
    for target, (recurrence_text, terms) in recurrence_terms.items():
        target_constant = constants[target][0]
        rhs_constant = sum(max(coeff, 0.0) * constants[source][0] for coeff, source, _ in terms)
        nonnegative_obstructions = [
            source
            for coeff, source, _ in terms
            if coeff < 0.0 and constants[source][3] is not None
        ]
        worst_induction_slack = float("inf")
        exact_worst_slack = float("inf")
        for n_value in range(max_n):
            a_limit = min(n_value + 2, dense_a_limit)
            for a in range(1, a_limit + 1):
                target_bound = target_constant / _top3_barrier_denominator(barrier, n_value + 1, a)
                rhs_bound = 0.0
                exact_rhs = 0.0
                valid_point = True
                for coeff, source, shift in terms:
                    source_a = a + shift
                    if source_a <= 0 or (source == "F" and source_a <= 1):
                        valid_point = False
                        break
                    if coeff > 0.0:
                        rhs_bound += coeff * constants[source][0] / _top3_barrier_denominator(barrier, n_value, source_a)
                    exact_rhs += coeff * _top3_signed_aux_value(source, n_value, source_a)
                if not valid_point:
                    continue
                exact_value = _top3_signed_aux_value(target, n_value + 1, a)
                worst_induction_slack = min(worst_induction_slack, target_bound - rhs_bound)
                exact_worst_slack = min(exact_worst_slack, target_bound - exact_value, target_bound - exact_rhs)
        obstruction = "none"
        if nonnegative_obstructions:
            obstruction = "negative signed source(s): " + ",".join(sorted(set(nonnegative_obstructions)))
        elif worst_induction_slack < -1e-12:
            obstruction = "box constants do not make RHS fit target"
        rows.append(
            K5Top3InductionStepRow(
                target=target,
                recurrence=recurrence_text,
                barrier=barrier,
                constant=target_constant,
                rhs_constant=rhs_constant,
                worst_induction_slack=worst_induction_slack,
                exact_worst_slack=exact_worst_slack,
                closes=worst_induction_slack >= -1e-12 and not nonnegative_obstructions,
                obstruction=obstruction,
            )
        )
    return tuple(rows)


def print_k5_top3_endpoint_induction_certificate_report(
    max_n: int = 1000,
    dense_a_limit: int = 300,
    barriers: tuple[str, ...] = ("n", "n+a", "affine-a"),
    n: int = 40,
) -> None:
    print("endpoint induction certificate")
    print()
    print("1. Value-scan constants versus induction constants")
    constants = _top3_aux_value_scan_constants(max_n=max_n, dense_a_limit=dense_a_limit)
    print(f"scan grid: n <= {max_n}, 1 <= a <= min(n+2,{dense_a_limit})")
    print("family c_value min_signed argmax first_negative")
    for family, (constant, min_signed, argmax, first_negative) in constants.items():
        print(f"{family:1s} {constant:.12f} {min_signed:.12f} {argmax} {first_negative}")

    print()
    print("2. true induction inequality")
    print("For each signed recurrence, the box test asks whether")
    print("  target_barrier(n+1,a) >= recurrence_RHS_barrier(n,a)")
    print("using barrier bounds, not exact values.")
    for barrier in barriers:
        print()
        print(f"barrier={barrier}")
        print("target constant rhs_constant worst induction slack exact_worst_slack closes obstruction")
        for row in k5_top3_endpoint_induction_certificate_rows(
            max_n=max_n,
            dense_a_limit=dense_a_limit,
            barrier=barrier,
        ):
            print(
                f"{row.target:1s}"
                f" {row.constant:.12f}"
                f" {row.rhs_constant:.12f}"
                f" {row.worst_induction_slack:.12f}"
                f" {row.exact_worst_slack:.12f}"
                f" {row.closes}"
                f" {row.obstruction}"
            )

    print()
    print("3. finite discrepancy-state recurrence")
    for target, (recurrence_text, _) in _top3_signed_recurrence_terms().items():
        print(f"  {target}: {recurrence_text}")
    print("The recurrence for D leaks to F. A closed induction certificate must either bound F or replace {A,B,C,D} by finer discrepancy-state endpoint functions.")

    print()
    print("4. smallest likely finite family")
    print("The value scan shows A and k have the desired constants, but a true box induction over A/B/C/D/F does not automatically close.")
    print("The blocking sources are the signed auxiliary functions that are not nonnegative, notably C in the current sign convention.")
    print("A theorem-ready certificate should refine C into its discrepancy labels, so negative components are not hidden inside a single scalar Cplus.")

    print()
    print("5. endpoint consequence")
    print("If a refined finite-state barrier proves:")
    print(r"\[")
    print(r"0\le A^+_n(a)\le\frac1{n+1},\qquad 0\le k^+_n(a)\le\frac{3}{2(n+1)},")
    print(r"\]")
    print("then the endpoint bounds and the K_n(a)=O((n+1)^-1) estimate follow by the parity telescope.")


def _top3_aggregate_start_pair(aggregate: str, a: int) -> tuple[tuple[int, int], tuple[int, int]]:
    if aggregate == "A":
        return ((a, 1), (a + 1, 0))
    if aggregate == "B":
        return ((a - 1, 1), (a, 0))
    if aggregate == "C":
        return ((a, 0), (a + 1, 0))
    raise ValueError(f"unknown top3 aggregate family: {aggregate}")


def _top3_refined_label_map(aggregate: str) -> dict[tuple[int, int], str]:
    if aggregate in {"A", "B"}:
        return {
            (1, -1): "cross",
            (0, 1): "same",
            (-1, 0): "reflected",
        }
    if aggregate == "C":
        return {
            (1, 0): "same",
            (0, -1): "cross",
            (-1, 1): "reflected",
        }
    raise ValueError(f"unknown top3 aggregate family: {aggregate}")


def _top3_refined_label_keys() -> tuple[tuple[str, str], ...]:
    return (
        ("A", "cross"),
        ("A", "same"),
        ("A", "reflected"),
        ("B", "cross"),
        ("B", "same"),
        ("B", "reflected"),
        ("C", "same"),
        ("C", "cross"),
        ("C", "reflected"),
    )


@lru_cache(maxsize=None)
def _top3_refined_label_endpoint_value_from_pair(
    aggregate: str,
    label: str,
    n: int,
    x_r: int,
    x_s: int,
    y_r: int,
    y_s: int,
) -> float:
    if n == 0:
        pair_state = ((x_r, x_s), (y_r, y_s))
        discrepancy = _top3_endpoint_coupling_discrepancy(pair_state)
        terminal_label = _top3_refined_label_map(aggregate).get(discrepancy)
        if terminal_label != label:
            return 0.0
        return float(_top3_endpoint_coupling_boundary_difference(pair_state))
    plus_pair = _top3_coupled_plus_state(((x_r, x_s), (y_r, y_s)))
    minus_pair = _top3_coupled_minus_state(((x_r, x_s), (y_r, y_s)))
    return 0.5 * _top3_refined_label_endpoint_value_from_pair(
        aggregate,
        label,
        n - 1,
        plus_pair[0][0],
        plus_pair[0][1],
        plus_pair[1][0],
        plus_pair[1][1],
    ) + 0.5 * _top3_refined_label_endpoint_value_from_pair(
        aggregate,
        label,
        n - 1,
        minus_pair[0][0],
        minus_pair[0][1],
        minus_pair[1][0],
        minus_pair[1][1],
    )


def _top3_refined_label_endpoint_value(aggregate: str, label: str, n: int, a: int) -> float:
    pair_state = _top3_aggregate_start_pair(aggregate, a)
    return _top3_refined_label_endpoint_value_from_pair(
        aggregate,
        label,
        n,
        pair_state[0][0],
        pair_state[0][1],
        pair_state[1][0],
        pair_state[1][1],
    )


def _top3_refined_label_aggregate_value(aggregate: str, n: int, a: int) -> float:
    return sum(
        _top3_refined_label_endpoint_value(aggregate, label, n, a)
        for label in _top3_refined_label_map(aggregate).values()
    )


def _top3_refined_aggregate_direct_value(aggregate: str, n: int, a: int) -> float:
    if aggregate == "A":
        return _top3_a_term(n, a)
    if aggregate == "B":
        return _top3_b_term(n, a)
    if aggregate == "C":
        return _top3_c_term(n, a)
    if aggregate == "k":
        return _top3_kernel_term(n, a)
    raise ValueError(f"unknown aggregate value: {aggregate}")


def _top3_refined_signed_value(
    aggregate: str,
    label: str,
    parity_shift: int,
    n: int,
    a: int,
) -> float:
    return ((-1) ** (n - a + parity_shift)) * _top3_refined_label_endpoint_value(
        aggregate,
        label,
        n,
        a,
    )


def _top3_refined_best_parity_shift(
    aggregate: str,
    label: str,
    max_n: int,
    dense_a_limit: int,
) -> int:
    best_shift = 0
    best_min = -float("inf")
    best_max_scaled = float("inf")
    for shift in (0, 1):
        min_signed = float("inf")
        max_scaled = 0.0
        for n_value in range(max_n + 1):
            for a in range(1, min(n_value + 2, dense_a_limit) + 1):
                value = _top3_refined_signed_value(aggregate, label, shift, n_value, a)
                min_signed = min(min_signed, value)
                max_scaled = max(max_scaled, (n_value + 1) * max(value, 0.0))
        if min_signed > best_min + 1e-15 or (
            abs(min_signed - best_min) <= 1e-15 and max_scaled < best_max_scaled
        ):
            best_shift = shift
            best_min = min_signed
            best_max_scaled = max_scaled
    return best_shift


def k5_top3_refined_discrepancy_label_scan_rows(
    max_n: int = 600,
    dense_a_limit: int = 160,
) -> tuple[K5Top3RefinedLabelScanRow, ...]:
    if max_n < 0:
        raise ValueError(f"max_n must be nonnegative, got {max_n}")
    if dense_a_limit <= 0:
        raise ValueError(f"dense_a_limit must be positive, got {dense_a_limit}")
    _ensure_top3_recursion_limit(max_n)

    rows: list[K5Top3RefinedLabelScanRow] = []
    for aggregate, label in _top3_refined_label_keys():
        parity_shift = _top3_refined_best_parity_shift(aggregate, label, max_n, dense_a_limit)
        min_signed = float("inf")
        max_scaled = 0.0
        argmax_n = 0
        argmax_a = 1
        first_negative: tuple[int, int] | None = None
        for n_value in range(max_n + 1):
            for a in range(1, min(n_value + 2, dense_a_limit) + 1):
                signed = _top3_refined_signed_value(aggregate, label, parity_shift, n_value, a)
                min_signed = min(min_signed, signed)
                if first_negative is None and signed < -1e-15:
                    first_negative = (n_value, a)
                scaled = (n_value + 1) * max(signed, 0.0)
                if scaled > max_scaled:
                    max_scaled = scaled
                    argmax_n = n_value
                    argmax_a = a
        rows.append(
            K5Top3RefinedLabelScanRow(
                key=f"{aggregate}:{label}",
                aggregate=aggregate,
                label=label,
                parity_shift=parity_shift,
                min_signed=min_signed,
                max_scaled=max_scaled,
                argmax_n=argmax_n,
                argmax_a=argmax_a,
                first_negative=first_negative,
            )
        )
    return tuple(rows)


def _top3_refined_reconstruction_residuals(
    max_n: int,
    dense_a_limit: int,
) -> tuple[tuple[str, float], ...]:
    residuals = {"A": 0.0, "B": 0.0, "C": 0.0, "k": 0.0}
    for n_value in range(max_n + 1):
        for a in range(1, min(n_value + 2, dense_a_limit) + 1):
            a_sum = _top3_refined_label_aggregate_value("A", n_value, a)
            b_sum = _top3_refined_label_aggregate_value("B", n_value, a)
            c_sum = _top3_refined_label_aggregate_value("C", n_value, a)
            k_sum = 0.5 * b_sum + 0.5 * c_sum - 1.5 * a_sum
            residuals["A"] = max(residuals["A"], abs(a_sum - _top3_a_term(n_value, a)))
            residuals["B"] = max(residuals["B"], abs(b_sum - _top3_b_term(n_value, a)))
            residuals["C"] = max(residuals["C"], abs(c_sum - _top3_c_term(n_value, a)))
            residuals["k"] = max(residuals["k"], abs(k_sum - _top3_kernel_term(n_value, a)))
    return tuple(residuals.items())


def _top3_refined_one_step_residuals(
    max_n: int,
    dense_a_limit: int,
) -> tuple[tuple[str, float], ...]:
    residuals: dict[str, float] = {}
    for aggregate, label in _top3_refined_label_keys():
        key = f"{aggregate}:{label}"
        max_residual = 0.0
        for n_value in range(max_n):
            for a in range(1, min(n_value + 2, dense_a_limit) + 1):
                pair_state = _top3_aggregate_start_pair(aggregate, a)
                plus_pair = _top3_coupled_plus_state(pair_state)
                minus_pair = _top3_coupled_minus_state(pair_state)
                lhs = _top3_refined_label_endpoint_value(aggregate, label, n_value + 1, a)
                rhs = 0.5 * _top3_refined_label_endpoint_value_from_pair(
                    aggregate,
                    label,
                    n_value,
                    plus_pair[0][0],
                    plus_pair[0][1],
                    plus_pair[1][0],
                    plus_pair[1][1],
                ) + 0.5 * _top3_refined_label_endpoint_value_from_pair(
                    aggregate,
                    label,
                    n_value,
                    minus_pair[0][0],
                    minus_pair[0][1],
                    minus_pair[1][0],
                    minus_pair[1][1],
                )
                max_residual = max(max_residual, abs(lhs - rhs))
        residuals[key] = max_residual
    return tuple(sorted(residuals.items()))


def k5_top3_refined_discrepancy_induction_rows(
    max_n: int = 600,
    dense_a_limit: int = 160,
    barrier: str = "n",
) -> tuple[K5Top3RefinedInductionRow, ...]:
    scan_rows = {
        row.key: row
        for row in k5_top3_refined_discrepancy_label_scan_rows(
            max_n=max_n,
            dense_a_limit=dense_a_limit,
        )
    }
    rows: list[K5Top3RefinedInductionRow] = []
    for aggregate, label in _top3_refined_label_keys():
        key = f"{aggregate}:{label}"
        scan = scan_rows[key]
        worst_exact_slack = float("inf")
        worst_induction_slack = float("inf")
        for n_value in range(max_n):
            for a in range(1, min(n_value + 2, dense_a_limit) + 1):
                target_bound = scan.max_scaled / _top3_barrier_denominator(barrier, n_value + 1, a)
                exact_value = _top3_refined_signed_value(
                    aggregate,
                    label,
                    scan.parity_shift,
                    n_value + 1,
                    a,
                )
                pair_state = _top3_aggregate_start_pair(aggregate, a)
                plus_pair = _top3_coupled_plus_state(pair_state)
                minus_pair = _top3_coupled_minus_state(pair_state)
                # This is the exact signed one-step RHS. It distinguishes an exact
                # value scan from a theorem-level box induction, because the child
                # pairs are not yet reduced to a finite closed barrier family.
                exact_rhs = ((-1) ** (n_value + 1 - a + scan.parity_shift)) * (
                    0.5
                    * _top3_refined_label_endpoint_value_from_pair(
                        aggregate,
                        label,
                        n_value,
                        plus_pair[0][0],
                        plus_pair[0][1],
                        plus_pair[1][0],
                        plus_pair[1][1],
                    )
                    + 0.5
                    * _top3_refined_label_endpoint_value_from_pair(
                        aggregate,
                        label,
                        n_value,
                        minus_pair[0][0],
                        minus_pair[0][1],
                        minus_pair[1][0],
                        minus_pair[1][1],
                    )
                )
                worst_exact_slack = min(worst_exact_slack, target_bound - exact_value, target_bound - exact_rhs)
                worst_induction_slack = min(worst_induction_slack, target_bound - abs(exact_rhs))
        obstruction = "none"
        closes = scan.first_negative is None and worst_induction_slack >= -1e-12
        if scan.first_negative is not None:
            obstruction = f"label is not sign-definite at {scan.first_negative}"
        elif worst_induction_slack < -1e-12:
            obstruction = "absolute child RHS exceeds label box"
        rows.append(
            K5Top3RefinedInductionRow(
                key=key,
                barrier=barrier,
                constant=scan.max_scaled,
                worst_induction_slack=worst_induction_slack,
                exact_worst_slack=worst_exact_slack,
                closes=closes,
                obstruction=obstruction,
            )
        )
    return tuple(rows)


def print_k5_top3_refined_discrepancy_barrier_report(
    max_n: int = 600,
    dense_a_limit: int = 160,
    barriers: tuple[str, ...] = ("n", "n+a"),
    recurrence_max_n: int = 80,
    n: int = 40,
) -> None:
    print("refined discrepancy barrier")
    print()
    print(f"dense grid: n <= {max_n}, 1 <= a <= min(n+2,{dense_a_limit})")
    print()

    print("1. reconstructs aggregate")
    print("aggregate max_abs_residual")
    for aggregate, residual in _top3_refined_reconstruction_residuals(
        max_n=min(max_n, recurrence_max_n),
        dense_a_limit=dense_a_limit,
    ):
        print(f"{aggregate:1s} {residual:.3e}")
    print("The label sums reconstruct A/B/C, and 0.5B+0.5C-1.5A reconstructs k.")

    print()
    print("2. label-level sign scan")
    print("key parity_shift min_signed max_(n+1)positive argmax first_negative")
    scan_rows = k5_top3_refined_discrepancy_label_scan_rows(
        max_n=max_n,
        dense_a_limit=dense_a_limit,
    )
    for row in scan_rows:
        print(
            f"{row.key:11s}"
            f" {row.parity_shift:2d}"
            f" {row.min_signed:.12f}"
            f" {row.max_scaled:.12f}"
            f" ({row.argmax_n},{row.argmax_a})"
            f" {row.first_negative}"
        )

    print()
    print("3. label-level recurrence")
    print(r"\[")
    print(r"U^{\sigma}_{n+1}(P)=\frac12U^{\sigma}_n(P^+)+\frac12U^{\sigma}_n(P^-),")
    print(r"\]")
    print("where P is the coupled pair state and sigma is a terminal discrepancy label.")
    print("key max_abs_residual")
    for key, residual in _top3_refined_one_step_residuals(
        max_n=min(max_n, recurrence_max_n),
        dense_a_limit=dense_a_limit,
    ):
        print(f"{key:11s} {residual:.3e}")

    print()
    print("4. induction slack")
    print("barrier key constant worst_induction_slack exact_worst_slack closes obstruction")
    for barrier in barriers:
        rows = k5_top3_refined_discrepancy_induction_rows(
            max_n=max_n,
            dense_a_limit=dense_a_limit,
            barrier=barrier,
        )
        for row in rows:
            print(
                f"{barrier:8s}"
                f" {row.key:11s}"
                f" {row.constant:.12f}"
                f" {row.worst_induction_slack:.12f}"
                f" {row.exact_worst_slack:.12f}"
                f" {row.closes}"
                f" {row.obstruction}"
            )

    print()
    print("5. aggregate Cplus obstruction")
    c_min = min(
        _top3_signed_endpoint_value("C", n_value, a)
        for n_value in range(min(max_n, recurrence_max_n) + 1)
        for a in range(1, min(n_value + 2, dense_a_limit) + 1)
    )
    print(f"aggregate Cplus minimum on the recurrence grid: {c_min:.12f}")
    print("Refining by terminal discrepancy label exposes which pieces carry this negative mass.")

    print()
    print("6. endpoint consequences")
    a_constant = max((row.max_scaled for row in scan_rows if row.aggregate == "A"), default=0.0)
    b_constant = max((row.max_scaled for row in scan_rows if row.aggregate == "B"), default=0.0)
    c_constant = max((row.max_scaled for row in scan_rows if row.aggregate == "C"), default=0.0)
    print(f"sum-of-label constants: A <= {a_constant:.6f}/(n+1), B <= {b_constant:.6f}/(n+1), C <= {c_constant:.6f}/(n+1)")
    print("For kplus = 0.5 B + 0.5 C - 1.5 A, this naive label-box consequence is generally too loose.")
    print("A proof of kplus <= 3/(2(n+1)) still needs either signed cancellation between labels or a sharper coupled-output basis.")

    print()
    print("7. theorem-ready recurrence and barrier inequalities")
    print("For each terminal label sigma, prove a sign convention and a barrier")
    print(r"\[")
    print(r"0\le U^\sigma_n(a)\le \frac{c_\sigma}{n+1}.")
    print(r"\]")
    print("Then prove the aggregate endpoint inequalities by summing the signed label decomposition, retaining cancellations rather than applying a triangle inequality.")


Top3ConeComponent = tuple[float, str, str, int]


def _top3_cone_form_specs() -> dict[str, tuple[Top3ConeComponent, ...]]:
    specs: dict[str, tuple[Top3ConeComponent, ...]] = {}

    def pieces(aggregate: str, coeff: float, shift: int) -> tuple[Top3ConeComponent, ...]:
        return tuple((coeff, aggregate, label, shift) for label in _top3_refined_label_map(aggregate).values())

    specs["Aplus"] = pieces("A", 1.0, 0)
    specs["Bplus"] = pieces("B", 1.0, 1)
    specs["Cplus"] = pieces("C", 1.0, 0)
    specs["kplus"] = pieces("B", 0.5, 1) + pieces("C", 0.5, 1) + pieces("A", -1.5, 1)
    specs["Aplus+kplus"] = specs["Aplus"] + specs["kplus"]
    for numerator, denominator in ((1, 2), (1, 1), (3, 2)):
        c = numerator / denominator
        specs[f"kplus-{numerator}/{denominator}Aplus"] = specs["kplus"] + pieces("A", -c, 0)
    specs["Bplus+Cplus"] = specs["Bplus"] + specs["Cplus"]
    specs["Cplus-Aplus"] = specs["Cplus"] + pieces("A", -1.0, 0)

    # Include label-level probes with the parity shifts chosen by the previous
    # refined scan. These often fail sign-definiteness, which is useful data.
    for aggregate, label in _top3_refined_label_keys():
        shift = 0
        if aggregate == "B":
            shift = 1
        specs[f"{aggregate}:{label}"] = ((1.0, aggregate, label, shift),)
    return specs


def _top3_cone_form_value(
    components: tuple[Top3ConeComponent, ...],
    n: int,
    a: int,
) -> float:
    value = 0.0
    for coeff, aggregate, label, shift in components:
        value += coeff * ((-1) ** (n - a + shift)) * _top3_refined_label_endpoint_value(
            aggregate,
            label,
            n,
            a,
        )
    return value


def k5_top3_endpoint_cone_form_scan_rows(
    max_n: int = 600,
    dense_a_limit: int = 160,
) -> tuple[K5Top3ConeFormScanRow, ...]:
    if max_n < 0:
        raise ValueError(f"max_n must be nonnegative, got {max_n}")
    if dense_a_limit <= 0:
        raise ValueError(f"dense_a_limit must be positive, got {dense_a_limit}")
    _ensure_top3_recursion_limit(max_n)
    specs = _top3_cone_form_specs()
    rows: list[K5Top3ConeFormScanRow] = []
    for name, components in specs.items():
        min_value = float("inf")
        max_scaled = 0.0
        argmax_n = 0
        argmax_a = 1
        first_negative: tuple[int, int] | None = None
        for n_value in range(max_n + 1):
            for a in range(1, min(n_value + 2, dense_a_limit) + 1):
                value = _top3_cone_form_value(components, n_value, a)
                min_value = min(min_value, value)
                if first_negative is None and value < -1e-15:
                    first_negative = (n_value, a)
                scaled = (n_value + 1) * max(value, 0.0)
                if scaled > max_scaled:
                    max_scaled = scaled
                    argmax_n = n_value
                    argmax_a = a
        rows.append(
            K5Top3ConeFormScanRow(
                name=name,
                min_value=min_value,
                max_scaled=max_scaled,
                argmax_n=argmax_n,
                argmax_a=argmax_a,
                first_negative=first_negative,
            )
        )
    return tuple(rows)


def _top3_cone_reconstruction_residuals(max_n: int, dense_a_limit: int) -> tuple[tuple[str, float], ...]:
    specs = _top3_cone_form_specs()
    residuals = {"Aplus": 0.0, "kplus": 0.0}
    for n_value in range(max_n + 1):
        for a in range(1, min(n_value + 2, dense_a_limit) + 1):
            residuals["Aplus"] = max(
                residuals["Aplus"],
                abs(specs["Aplus"] and _top3_cone_form_value(specs["Aplus"], n_value, a) - _top3_signed_endpoint_value("A", n_value, a)),
            )
            residuals["kplus"] = max(
                residuals["kplus"],
                abs(specs["kplus"] and _top3_cone_form_value(specs["kplus"], n_value, a) - _top3_signed_endpoint_value("k", n_value, a)),
            )
    return tuple(residuals.items())


def k5_top3_endpoint_cone_closure_rows(
    max_n: int = 600,
    dense_a_limit: int = 160,
    closure_max_n: int = 80,
    shifts: tuple[int, ...] = (-1, 0, 1),
) -> tuple[K5Top3ConeClosureRow, ...]:
    scan_rows = {
        row.name: row
        for row in k5_top3_endpoint_cone_form_scan_rows(
            max_n=max_n,
            dense_a_limit=dense_a_limit,
        )
    }
    specs = _top3_cone_form_specs()
    nonnegative_names = tuple(
        row.name for row in scan_rows.values() if row.first_negative is None and row.max_scaled > 1e-15
    )
    columns: list[tuple[str, int]] = []
    for name in nonnegative_names:
        for shift in shifts:
            columns.append((name, shift))
    column_labels = tuple(f"{name}[a{shift:+d}]" for name, shift in columns)
    if not columns:
        return ()

    sample_points: list[tuple[int, int]] = []
    for n_value in range(max(0, closure_max_n)):
        for a in range(1, min(n_value + 2, dense_a_limit) + 1):
            sample_points.append((n_value, a))
    rows: list[K5Top3ConeClosureRow] = []
    for target_name in ("Aplus", "kplus", "Aplus+kplus"):
        if target_name not in specs:
            continue
        matrix: list[list[float]] = []
        target: list[float] = []
        for n_value, a in sample_points:
            target.append(_top3_cone_form_value(specs[target_name], n_value + 1, a))
            matrix_row: list[float] = []
            for column_name, shift in columns:
                source_a = a + shift
                if source_a <= 0:
                    matrix_row.append(0.0)
                else:
                    matrix_row.append(_top3_cone_form_value(specs[column_name], n_value, source_a))
            matrix.append(matrix_row)
        if not matrix:
            continue
        x_matrix = np.asarray(matrix, dtype=float)
        y_vector = np.asarray(target, dtype=float)
        variable_count = x_matrix.shape[1] + 1
        objective = np.zeros(variable_count)
        objective[-1] = 1.0
        a_ub = []
        b_ub = []
        # Minimize an L-infinity residual: |Xw-y| <= t, w >= 0.
        for row_values, y_value in zip(x_matrix, y_vector, strict=True):
            a_ub.append([*row_values, -1.0])
            b_ub.append(float(y_value))
            a_ub.append([*(-row_values), -1.0])
            b_ub.append(float(-y_value))
        bounds = [(0.0, None)] * variable_count
        result = linprog(
            objective,
            A_ub=np.asarray(a_ub, dtype=float),
            b_ub=np.asarray(b_ub, dtype=float),
            bounds=bounds,
            method="highs",
        )
        if not result.success:
            weights = np.zeros(x_matrix.shape[1], dtype=float)
            max_abs_residual = float("inf")
        else:
            weights = np.asarray(result.x[:-1], dtype=float)
            max_abs_residual = float(result.x[-1])
        target_constant = scan_rows[target_name].max_scaled
        rhs_constant = 0.0
        for weight, (column_name, _) in zip(weights, columns, strict=True):
            rhs_constant += float(weight) * scan_rows[column_name].max_scaled
        worst_slack = target_constant - rhs_constant
        top_weights = tuple(
            sorted(
                ((column_labels[index], float(weight)) for index, weight in enumerate(weights) if weight > 1e-9),
                key=lambda item: -item[1],
            )[:8]
        )
        rows.append(
            K5Top3ConeClosureRow(
                target=target_name,
                columns=column_labels,
                max_abs_residual=max_abs_residual,
                target_constant=target_constant,
                rhs_constant=rhs_constant,
                closes=max_abs_residual <= 1e-10 and worst_slack >= -1e-12,
                worst_slack=worst_slack,
                top_weights=top_weights,
            )
        )
    return tuple(rows)


def print_k5_top3_endpoint_cone_certificate_report(
    max_n: int = 600,
    dense_a_limit: int = 160,
    closure_max_n: int = 80,
    n: int = 40,
) -> None:
    print("endpoint cone certificate")
    print()
    print(f"value grid: n <= {max_n}, 1 <= a <= min(n+2,{dense_a_limit})")
    print(f"cone closure fit grid: n <= {closure_max_n}")

    print()
    print("1. label basis reconstruction")
    print("name max_abs_residual")
    for name, residual in _top3_cone_reconstruction_residuals(
        max_n=min(max_n, closure_max_n),
        dense_a_limit=dense_a_limit,
    ):
        print(f"{name:6s} {residual:.3e}")
    print("This reconstructs Aplus and kplus from the terminal-label basis.")

    print()
    print("2. candidate linear forms")
    print("name min_value max_(n+1)positive argmax first_negative")
    scan_rows = k5_top3_endpoint_cone_form_scan_rows(max_n=max_n, dense_a_limit=dense_a_limit)
    for row in scan_rows:
        print(
            f"{row.name:18s}"
            f" {row.min_value:.12f}"
            f" {row.max_scaled:.12f}"
            f" ({row.argmax_n},{row.argmax_a})"
            f" {row.first_negative}"
        )

    print()
    print("3. reproduces previous failures")
    aggregate_rows = k5_top3_endpoint_induction_certificate_rows(
        max_n=min(max_n, closure_max_n),
        dense_a_limit=dense_a_limit,
        barrier="n",
    )
    print("aggregate target closes obstruction")
    for row in aggregate_rows:
        print(f"{row.target:1s} {row.closes} {row.obstruction}")
    label_rows = k5_top3_refined_discrepancy_induction_rows(
        max_n=min(max_n, closure_max_n),
        dense_a_limit=dense_a_limit,
        barrier="n",
    )
    print("label-box nonclosing rows:")
    for row in label_rows:
        if not row.closes:
            print(f"  {row.key:11s} {row.obstruction}")

    print()
    print("4. cone closure")
    print("target max_abs_image_residual target_constant rhs_constant worst_slack closes top_weights")
    closure_rows = k5_top3_endpoint_cone_closure_rows(
        max_n=max_n,
        dense_a_limit=dense_a_limit,
        closure_max_n=closure_max_n,
    )
    for row in closure_rows:
        weights_text = ", ".join(f"{name}:{weight:.6f}" for name, weight in row.top_weights)
        print(
            f"{row.target:18s}"
            f" {row.max_abs_residual:.12f}"
            f" {row.target_constant:.12f}"
            f" {row.rhs_constant:.12f}"
            f" {row.worst_slack:.12f}"
            f" {row.closes}"
            f" {weights_text}"
        )
    print("The cone closure is a sampled nonnegative image fit. A zero residual plus nonnegative slack would be a true inductive super-solution candidate.")

    print()
    print("5. inductive super-solution")
    print("The target endpoint theorem asks for constants:")
    print(r"\[")
    print(r"A^+_n(a)\le\frac1{n+1},\qquad k^+_n(a)\le\frac{3}{2(n+1)}.")
    print(r"\]")
    form_rows = {row.name: row for row in scan_rows}
    for name, target in (("Aplus", 1.0), ("kplus", 1.5)):
        row = form_rows[name]
        print(f"  {name}: observed constant={row.max_scaled:.12f}, target={target:.12f}, value-scan closes={row.max_scaled <= target + 1e-12}")

    print()
    print("6. leftover linear forms")
    nonclosing = [row for row in closure_rows if not row.closes]
    if not nonclosing:
        print("No leftover forms on the sampled cone fit.")
    for row in nonclosing:
        print(
            f"  {row.target}: residual={row.max_abs_residual:.6e},"
            f" slack={row.worst_slack:.6e}; suggested new forms are recurrence-image components not represented by the current shifted candidate basis."
        )


ConeValueFunction = Callable[[int, int], float]


def _top3_base_cone_value_functions() -> dict[str, ConeValueFunction]:
    specs = _top3_cone_form_specs()
    return {
        name: (lambda n, a, components=components: _top3_cone_form_value(components, n, a))
        for name, components in specs.items()
    }


def _top3_expanded_cone_value_functions() -> dict[str, ConeValueFunction]:
    funcs = dict(_top3_base_cone_value_functions())
    funcs["image_kplus"] = lambda n, a: funcs["kplus"](n + 1, a)
    funcs["image_kminus_3half_A"] = lambda n, a: funcs["kplus-3/2Aplus"](n + 1, a)
    funcs["image_Aplus+kplus"] = lambda n, a: funcs["Aplus+kplus"](n + 1, a)
    funcs["kplus_forward_diff"] = lambda n, a: funcs["kplus"](n, a) - funcs["kplus"](n, a + 1)
    funcs["Aplus_forward_diff"] = lambda n, a: funcs["Aplus"](n, a) - funcs["Aplus"](n, a + 1)
    funcs["kplus_backward_diff"] = lambda n, a: funcs["kplus"](n, a) - (funcs["kplus"](n, a - 1) if a > 1 else 0.0)
    funcs["Aplus_backward_diff"] = lambda n, a: funcs["Aplus"](n, a) - (funcs["Aplus"](n, a - 1) if a > 1 else 0.0)
    funcs["Bplus_minus_Aplus"] = lambda n, a: funcs["Bplus"](n, a) - funcs["Aplus"](n, a)
    funcs["kplus_plus_Bplus"] = lambda n, a: funcs["kplus"](n, a) + funcs["Bplus"](n, a)
    return funcs


def _top3_scan_cone_function_constant(
    fn: ConeValueFunction,
    max_n: int,
    dense_a_limit: int,
) -> tuple[float, float, tuple[int, int], tuple[int, int] | None]:
    max_scaled = 0.0
    min_value = float("inf")
    argmax = (0, 1)
    first_negative: tuple[int, int] | None = None
    for n_value in range(max_n + 1):
        for a in range(1, min(n_value + 2, dense_a_limit) + 1):
            value = fn(n_value, a)
            min_value = min(min_value, value)
            if first_negative is None and value < -1e-15:
                first_negative = (n_value, a)
            scaled = (n_value + 1) * max(value, 0.0)
            if scaled > max_scaled:
                max_scaled = scaled
                argmax = (n_value, a)
    return max_scaled, min_value, argmax, first_negative


def _top3_cone_fit_image(
    target_name: str,
    funcs: dict[str, ConeValueFunction],
    source_names: tuple[str, ...],
    closure_max_n: int,
    dense_a_limit: int,
    shifts: tuple[int, ...],
) -> tuple[np.ndarray, tuple[str, ...], float, tuple[K5Top3ConeResidualRow, ...]]:
    columns: list[tuple[str, int]] = []
    for name in source_names:
        for shift in shifts:
            columns.append((name, shift))
    column_labels = tuple(f"{name}[a{shift:+d}]" for name, shift in columns)
    matrix: list[list[float]] = []
    target: list[float] = []
    points: list[tuple[int, int]] = []
    for n_value in range(max(0, closure_max_n)):
        for a in range(1, min(n_value + 2, dense_a_limit) + 1):
            points.append((n_value, a))
            target.append(funcs[target_name](n_value + 1, a))
            row_values: list[float] = []
            for source_name, shift in columns:
                source_a = a + shift
                row_values.append(0.0 if source_a <= 0 else funcs[source_name](n_value, source_a))
            matrix.append(row_values)
    if not matrix:
        return np.zeros(0), column_labels, float("inf"), ()

    x_matrix = np.asarray(matrix, dtype=float)
    y_vector = np.asarray(target, dtype=float)
    variable_count = x_matrix.shape[1] + 1
    objective = np.zeros(variable_count)
    objective[-1] = 1.0
    a_ub = []
    b_ub = []
    for row_values, y_value in zip(x_matrix, y_vector, strict=True):
        a_ub.append([*row_values, -1.0])
        b_ub.append(float(y_value))
        a_ub.append([*(-row_values), -1.0])
        b_ub.append(float(-y_value))
    result = linprog(
        objective,
        A_ub=np.asarray(a_ub, dtype=float),
        b_ub=np.asarray(b_ub, dtype=float),
        bounds=[(0.0, None)] * variable_count,
        method="highs",
    )
    if not result.success:
        weights = np.zeros(x_matrix.shape[1], dtype=float)
        max_abs_residual = float("inf")
    else:
        weights = np.asarray(result.x[:-1], dtype=float)
        max_abs_residual = float(result.x[-1])
    fitted = x_matrix @ weights
    residual_rows = tuple(
        sorted(
            (
                K5Top3ConeResidualRow(
                    target=target_name,
                    n=n_value,
                    a=a,
                    residual=float(y_value - fitted_value),
                    image_value=float(y_value),
                    fitted_value=float(fitted_value),
                )
                for (n_value, a), y_value, fitted_value in zip(points, y_vector, fitted, strict=True)
            ),
            key=lambda row: abs(row.residual),
            reverse=True,
        )
    )
    return weights, column_labels, max_abs_residual, residual_rows


def k5_top3_endpoint_cone_expansion_rows(
    max_n: int = 300,
    dense_a_limit: int = 100,
    closure_max_n: int = 80,
    shifts: tuple[int, ...] = (-2, -1, 0, 1, 2),
    weak_a_constant: float = 1.1,
    weak_k_constant: float = 1.7,
) -> tuple[tuple[K5Top3ConeExpansionFitRow, ...], tuple[K5Top3ConeResidualRow, ...]]:
    funcs = _top3_expanded_cone_value_functions()
    base_funcs = _top3_base_cone_value_functions()
    base_source_names = tuple(
        row.name
        for row in k5_top3_endpoint_cone_form_scan_rows(max_n=max_n, dense_a_limit=dense_a_limit)
        if row.first_negative is None and row.max_scaled > 1e-15
    )
    expanded_constants = {
        name: _top3_scan_cone_function_constant(fn, max_n=max_n, dense_a_limit=dense_a_limit)[0]
        for name, fn in funcs.items()
    }
    base_weights, base_columns, _, base_residuals = _top3_cone_fit_image(
        "kplus",
        funcs=base_funcs,
        source_names=base_source_names,
        closure_max_n=closure_max_n,
        dense_a_limit=dense_a_limit,
        shifts=(-1, 0, 1),
    )
    base_residual_names: list[str] = []
    for index, weight in enumerate(base_weights):
        if weight > 1e-9:
            base_residual_names.append(base_columns[index])
    residual_form_names = (
        "image_kplus",
        "image_kminus_3half_A",
        "image_Aplus+kplus",
        "kplus_forward_diff",
        "Aplus_forward_diff",
        "kplus_backward_diff",
        "Aplus_backward_diff",
        "Bplus_minus_Aplus",
        "kplus_plus_Bplus",
    )
    expanded_source_names = tuple(
        name
        for name, fn in funcs.items()
        if _top3_scan_cone_function_constant(fn, max_n=max_n, dense_a_limit=dense_a_limit)[3] is None
        and expanded_constants[name] > 1e-15
    )
    # Force recurrence-image forms into the attempted basis even when they are
    # not sign-definite, so the report can show why they help or fail.
    expanded_source_names = tuple(dict.fromkeys((*expanded_source_names, *residual_form_names)))
    rows: list[K5Top3ConeExpansionFitRow] = []
    for basis_name, source_names in (
        ("base", base_source_names),
        ("expanded", expanded_source_names),
    ):
        for target_name, exact_constant, weak_constant in (
            ("Aplus", 1.0, weak_a_constant),
            ("kplus", 1.5, weak_k_constant),
            ("Aplus+kplus", 2.5, weak_a_constant + weak_k_constant),
        ):
            weights, columns, max_abs_residual, _ = _top3_cone_fit_image(
                target_name,
                funcs=funcs,
                source_names=source_names,
                closure_max_n=closure_max_n,
                dense_a_limit=dense_a_limit,
                shifts=shifts,
            )
            rhs_constant = 0.0
            for weight, column_label in zip(weights, columns, strict=True):
                source_name = column_label.split("[", 1)[0]
                rhs_constant += float(weight) * expanded_constants.get(source_name, 0.0)
            target_constant = expanded_constants[target_name]
            top_weights = tuple(
                sorted(
                    ((columns[index], float(weight)) for index, weight in enumerate(weights) if weight > 1e-9),
                    key=lambda item: -item[1],
                )[:10]
            )
            rows.append(
                K5Top3ConeExpansionFitRow(
                    target=target_name,
                    basis_name=basis_name,
                    max_abs_residual=max_abs_residual,
                    target_constant=target_constant,
                    rhs_constant=rhs_constant,
                    exact_slack=exact_constant - rhs_constant,
                    weak_slack=weak_constant - rhs_constant,
                    closes_exact=max_abs_residual <= 1e-8 and exact_constant - rhs_constant >= -1e-12,
                    closes_weak=max_abs_residual <= 1e-8 and weak_constant - rhs_constant >= -1e-12,
                    top_weights=top_weights,
                )
            )
    return tuple(rows), base_residuals[:20]


def print_k5_top3_endpoint_cone_expansion_report(
    max_n: int = 300,
    dense_a_limit: int = 100,
    closure_max_n: int = 80,
    weak_a_constant: float = 1.1,
    weak_k_constant: float = 1.7,
    n: int = 40,
) -> None:
    print("endpoint cone expansion")
    print()
    print(f"value grid: n <= {max_n}, 1 <= a <= min(n+2,{dense_a_limit})")
    print(f"closure grid: n <= {closure_max_n}, shifts a-2..a+2")

    print()
    print("1. previous cone baseline")
    for row in k5_top3_endpoint_cone_closure_rows(
        max_n=max_n,
        dense_a_limit=dense_a_limit,
        closure_max_n=closure_max_n,
    ):
        print(
            f"{row.target:18s}"
            f" residual={row.max_abs_residual:.3e}"
            f" target_c={row.target_constant:.6f}"
            f" rhs_c={row.rhs_constant:.6f}"
            f" slack={row.worst_slack:.6f}"
            f" closes={row.closes}"
        )

    rows, residual_rows = k5_top3_endpoint_cone_expansion_rows(
        max_n=max_n,
        dense_a_limit=dense_a_limit,
        closure_max_n=closure_max_n,
        weak_a_constant=weak_a_constant,
        weak_k_constant=weak_k_constant,
    )

    print()
    print("2. residual-driven forms")
    print("Top residuals for the current kplus image fit:")
    print("target n a residual image fitted")
    for row in residual_rows[:n]:
        print(
            f"{row.target:6s}"
            f" {row.n:3d}"
            f" {row.a:3d}"
            f" {row.residual:+.12f}"
            f" {row.image_value:+.12f}"
            f" {row.fitted_value:+.12f}"
        )
    print("Added forms: exact image(kplus), image(kplus-3/2Aplus), image(Aplus+kplus), shifted first differences, and residual-adjacent combinations.")

    print()
    print("3. true induction closure")
    print("basis target image_residual target_value_c rhs_c exact_slack weak_slack closes_exact closes_weak top_weights")
    for row in rows:
        weights_text = ", ".join(f"{name}:{weight:.6f}" for name, weight in row.top_weights)
        print(
            f"{row.basis_name:8s}"
            f" {row.target:18s}"
            f" {row.max_abs_residual:.12f}"
            f" {row.target_constant:.12f}"
            f" {row.rhs_constant:.12f}"
            f" {row.exact_slack:.12f}"
            f" {row.weak_slack:.12f}"
            f" {row.closes_exact}"
            f" {row.closes_weak}"
            f" {weights_text}"
        )

    print()
    print("4. weaker constants")
    print(f"weak A constant: {weak_a_constant:.6f}")
    print(f"weak k constant: {weak_k_constant:.6f}")
    for row in rows:
        if row.target in {"Aplus", "kplus"} and row.basis_name == "expanded":
            print(
                f"  {row.target}: exact_closes={row.closes_exact}"
                f" weak_closes={row.closes_weak}"
                f" weak_slack={row.weak_slack:.12f}"
            )

    print()
    print("5. interpretation")
    print("The success criterion is true induction closure: image_residual <= 1e-8 and nonnegative constant slack.")
    print("If only recurrence-image forms close the cone, the next proof step is to derive barriers for those image forms rather than treating them as black-box auxiliaries.")


def _top3_kplus_companion_functions() -> dict[str, ConeValueFunction]:
    base = _top3_base_cone_value_functions()
    return {
        "A": base["Aplus"],
        "K": base["kplus"],
        "Q1": lambda n, a: base["kplus"](n, a) - base["Aplus"](n, a),
        "Q3": lambda n, a: base["kplus"](n, a) - 1.5 * base["Aplus"](n, a),
        "Qhalf": lambda n, a: base["kplus"](n, a) - 0.5 * base["Aplus"](n, a),
        "S": lambda n, a: base["Aplus"](n, a) + base["kplus"](n, a),
        "B": base["Bplus"],
        "B-A": lambda n, a: base["Bplus"](n, a) - base["Aplus"](n, a),
        "B-Q1": lambda n, a: base["Bplus"](n, a) - (base["kplus"](n, a) - base["Aplus"](n, a)),
    }


def k5_top3_kplus_companion_scan_rows(
    max_n: int = 200,
    dense_a_limit: int = 80,
) -> tuple[K5Top3CompanionScanRow, ...]:
    funcs = _top3_kplus_companion_functions()
    rows: list[K5Top3CompanionScanRow] = []
    for name, fn in funcs.items():
        max_scaled = 0.0
        min_value = float("inf")
        argmax_n = 0
        argmax_a = 1
        first_negative: tuple[int, int] | None = None
        for n_value in range(max_n + 1):
            for a in range(1, min(n_value + 2, dense_a_limit) + 1):
                value = fn(n_value, a)
                min_value = min(min_value, value)
                if first_negative is None and value < -1e-15:
                    first_negative = (n_value, a)
                scaled = (n_value + 1) * max(value, 0.0)
                if scaled > max_scaled:
                    max_scaled = scaled
                    argmax_n = n_value
                    argmax_a = a
        rows.append(
            K5Top3CompanionScanRow(
                name=name,
                min_value=min_value,
                max_scaled=max_scaled,
                argmax_n=argmax_n,
                argmax_a=argmax_a,
                first_negative=first_negative,
            )
        )
    return tuple(rows)


def _top3_fit_companion_image(
    target_name: str,
    funcs: dict[str, ConeValueFunction],
    source_names: tuple[str, ...],
    closure_max_n: int,
    dense_a_limit: int,
    shifts: tuple[int, ...] = (-2, -1, 0, 1, 2),
) -> tuple[np.ndarray, tuple[str, ...], float]:
    columns: list[tuple[str, int]] = [(name, shift) for name in source_names for shift in shifts]
    labels = tuple(f"{name}[a{shift:+d}]" for name, shift in columns)
    matrix: list[list[float]] = []
    target: list[float] = []
    for n_value in range(max(0, closure_max_n)):
        for a in range(1, min(n_value + 2, dense_a_limit) + 1):
            target.append(funcs[target_name](n_value + 1, a))
            row: list[float] = []
            for source_name, shift in columns:
                source_a = a + shift
                row.append(0.0 if source_a <= 0 else funcs[source_name](n_value, source_a))
            matrix.append(row)
    if not matrix:
        return np.zeros(0), labels, float("inf")
    x_matrix = np.asarray(matrix, dtype=float)
    y_vector = np.asarray(target, dtype=float)
    variable_count = x_matrix.shape[1] + 1
    objective = np.zeros(variable_count)
    objective[-1] = 1.0
    a_ub = []
    b_ub = []
    for row_values, y_value in zip(x_matrix, y_vector, strict=True):
        a_ub.append([*row_values, -1.0])
        b_ub.append(float(y_value))
        a_ub.append([*(-row_values), -1.0])
        b_ub.append(float(-y_value))
    result = linprog(
        objective,
        A_ub=np.asarray(a_ub, dtype=float),
        b_ub=np.asarray(b_ub, dtype=float),
        bounds=[(0.0, None)] * variable_count,
        method="highs",
    )
    if not result.success:
        return np.zeros(x_matrix.shape[1], dtype=float), labels, float("inf")
    return np.asarray(result.x[:-1], dtype=float), labels, float(result.x[-1])


def k5_top3_kplus_companion_closure_rows(
    max_n: int = 200,
    dense_a_limit: int = 80,
    closure_max_n: int = 60,
) -> tuple[K5Top3CompanionClosureRow, ...]:
    funcs = _top3_kplus_companion_functions()
    scan_rows = {row.name: row for row in k5_top3_kplus_companion_scan_rows(max_n=max_n, dense_a_limit=dense_a_limit)}
    source_names = tuple(
        row.name for row in scan_rows.values() if row.first_negative is None and row.max_scaled > 1e-15
    )
    rows: list[K5Top3CompanionClosureRow] = []
    target_constants = {
        "A": 1.0,
        "K": 1.5,
        "Q1": 0.75,
        "Q3": 0.5,
        "Qhalf": scan_rows["Qhalf"].max_scaled,
        "S": 2.5,
        "B": 1.0,
    }
    for target_name in ("A", "K", "Q1", "Q3", "Qhalf", "S", "B"):
        weights, labels, max_abs_residual = _top3_fit_companion_image(
            target_name,
            funcs=funcs,
            source_names=source_names,
            closure_max_n=closure_max_n,
            dense_a_limit=dense_a_limit,
        )
        rhs_constant = 0.0
        for weight, label in zip(weights, labels, strict=True):
            source_name = label.split("[", 1)[0]
            rhs_constant += float(weight) * scan_rows[source_name].max_scaled
        target_constant = target_constants[target_name]
        top_weights = tuple(
            sorted(
                ((labels[index], float(weight)) for index, weight in enumerate(weights) if weight > 1e-9),
                key=lambda item: -item[1],
            )[:10]
        )
        rows.append(
            K5Top3CompanionClosureRow(
                target=target_name,
                target_constant=target_constant,
                rhs_constant=rhs_constant,
                max_abs_residual=max_abs_residual,
                worst_slack=target_constant - rhs_constant,
                closes=max_abs_residual <= 1e-8 and target_constant - rhs_constant >= -1e-12,
                top_weights=top_weights,
            )
        )
    return tuple(rows)


def print_k5_top3_kplus_companion_barrier_report(
    max_n: int = 200,
    dense_a_limit: int = 80,
    closure_max_n: int = 60,
    n: int = 40,
) -> None:
    print("kplus companion barrier")
    print()
    print(f"value grid: n <= {max_n}, 1 <= a <= min(n+2,{dense_a_limit})")
    print(f"closure grid: n <= {closure_max_n}, shifts a-2..a+2")

    print()
    print("1. companion definitions")
    print("A = Aplus")
    print("K = kplus")
    print("Q1 = kplus - Aplus")
    print("Q3 = kplus - 3/2 Aplus")
    print("Qhalf = kplus - 1/2 Aplus")
    print("S = Aplus + kplus")

    print()
    print("2. dense value scan")
    print("form min_value max_(n+1)positive argmax first_negative")
    scan_rows = k5_top3_kplus_companion_scan_rows(max_n=max_n, dense_a_limit=dense_a_limit)
    scan_by_name = {row.name: row for row in scan_rows}
    for row in scan_rows:
        print(
            f"{row.name:6s}"
            f" {row.min_value:.12f}"
            f" {row.max_scaled:.12f}"
            f" ({row.argmax_n},{row.argmax_a})"
            f" {row.first_negative}"
        )

    print()
    print("3. true induction closure")
    print("target target_c rhs_c residual worst_slack closes top_weights")
    closure_rows = k5_top3_kplus_companion_closure_rows(
        max_n=max_n,
        dense_a_limit=dense_a_limit,
        closure_max_n=closure_max_n,
    )
    closure_by_name = {row.target: row for row in closure_rows}
    for row in closure_rows:
        weights_text = ", ".join(f"{name}:{weight:.6f}" for name, weight in row.top_weights)
        print(
            f"{row.target:6s}"
            f" {row.target_constant:.12f}"
            f" {row.rhs_constant:.12f}"
            f" {row.max_abs_residual:.12f}"
            f" {row.worst_slack:.12f}"
            f" {row.closes}"
            f" {weights_text}"
        )

    print()
    print("4. K follows")
    a_closes = closure_by_name.get("A") is not None and closure_by_name["A"].closes
    q1_closes = closure_by_name.get("Q1") is not None and closure_by_name["Q1"].closes
    q3_closes = closure_by_name.get("Q3") is not None and closure_by_name["Q3"].closes
    print(f"A closes: {a_closes}")
    print(f"Q1 closes: {q1_closes}")
    print(f"Q3 closes: {q3_closes}")
    print(
        "K via Q1 + A:"
        f" constant={scan_by_name['Q1'].max_scaled + scan_by_name['A'].max_scaled:.12f}"
        f" target=1.500000000000"
        f" follows={a_closes and q1_closes and scan_by_name['Q1'].max_scaled + scan_by_name['A'].max_scaled <= 1.5 + 1e-12}"
    )
    print(
        "K via Q3 + 1.5A:"
        f" constant={scan_by_name['Q3'].max_scaled + 1.5 * scan_by_name['A'].max_scaled:.12f}"
        f" target=1.500000000000"
        f" follows={a_closes and q3_closes and scan_by_name['Q3'].max_scaled + 1.5 * scan_by_name['A'].max_scaled <= 1.5 + 1e-12}"
    )

    print()
    print("5. proof-helper interpretation")
    print("If A and either Q1 or Q3 close inductively, K can be bounded by the displayed decompositions.")
    print("The report distinguishes this true induction closure from the dense value-scan constants above.")


_TOP3_POLYTOPE_VARIABLES = ("A", "K", "Q3", "Q1", "Qhalf", "B", "S")


def _top3_polytope_point(n_value: int, a: int) -> tuple[float, ...]:
    funcs = _top3_kplus_companion_functions()
    return tuple((n_value + 1) * funcs[name](n_value, a) for name in _TOP3_POLYTOPE_VARIABLES)


def _top3_polytope_raw_values(n_value: int, a: int) -> tuple[float, ...]:
    funcs = _top3_kplus_companion_functions()
    return tuple(funcs[name](n_value, a) for name in _TOP3_POLYTOPE_VARIABLES)


def _top3_polytope_base_halfspaces() -> tuple[tuple[str, tuple[float, ...], float], ...]:
    index = {name: i for i, name in enumerate(_TOP3_POLYTOPE_VARIABLES)}

    def coeff(**kwargs: float) -> tuple[float, ...]:
        values = [0.0] * len(_TOP3_POLYTOPE_VARIABLES)
        for name, value in kwargs.items():
            values[index[name]] = value
        return tuple(values)

    return (
        ("A<=1", coeff(A=1.0), 1.0),
        ("K<=1.5", coeff(K=1.0), 1.5),
        ("Q3<=0.5", coeff(Q3=1.0), 0.5),
        ("B<=1", coeff(B=1.0), 1.0),
        ("Q1<=0.75", coeff(Q1=1.0), 0.75),
        ("Qhalf<=1.125", coeff(Qhalf=1.0), 1.125),
        ("S<=2.5", coeff(S=1.0), 2.5),
        ("K-A<=0.75", coeff(K=1.0, A=-1.0), 0.75),
        ("K-0.5A<=1.125", coeff(K=1.0, A=-0.5), 1.125),
        ("Q3+1.5A<=1.5", coeff(Q3=1.0, A=1.5), 1.5),
    )


def _top3_polytope_halfspaces_from_scan(
    max_n: int,
    dense_a_limit: int,
    add_hull_facets: bool = True,
) -> tuple[K5Top3PolytopeHalfspaceRow, ...]:
    base = list(_top3_polytope_base_halfspaces())
    if add_hull_facets:
        for slope in (0.25, 0.5, 0.75, 1.0):
            coeffs = [0.0] * len(_TOP3_POLYTOPE_VARIABLES)
            coeffs[_TOP3_POLYTOPE_VARIABLES.index("K")] = 1.0
            coeffs[_TOP3_POLYTOPE_VARIABLES.index("A")] = slope
            base.append((f"K+{slope:g}A<=data", tuple(coeffs), 0.0))
            coeffs2 = [0.0] * len(_TOP3_POLYTOPE_VARIABLES)
            coeffs2[_TOP3_POLYTOPE_VARIABLES.index("Q3")] = 1.0
            coeffs2[_TOP3_POLYTOPE_VARIABLES.index("A")] = slope
            base.append((f"Q3+{slope:g}A<=data", tuple(coeffs2), 0.0))

    rows: list[K5Top3PolytopeHalfspaceRow] = []
    for name, coefficients, nominal_constant in base:
        max_value = -float("inf")
        argmax_n = 0
        argmax_a = 1
        for n_value in range(max_n + 1):
            for a in range(1, min(n_value + 2, dense_a_limit) + 1):
                point = _top3_polytope_point(n_value, a)
                value = sum(c * x for c, x in zip(coefficients, point, strict=True))
                if value > max_value:
                    max_value = value
                    argmax_n = n_value
                    argmax_a = a
        constant = max(nominal_constant, max_value) if name.endswith("<=data") else nominal_constant
        rows.append(
            K5Top3PolytopeHalfspaceRow(
                name=name,
                coefficients=coefficients,
                constant=constant,
                max_value=max_value,
                argmax_n=argmax_n,
                argmax_a=argmax_a,
            )
        )
    return tuple(rows)


def _top3_polytope_bin_rows(max_n: int, dense_a_limit: int, bins: int = 10) -> tuple[tuple[float, float, float, float], ...]:
    buckets: list[list[tuple[float, float, float]]] = [[] for _ in range(bins)]
    for n_value in range(max_n + 1):
        for a in range(1, min(n_value + 2, dense_a_limit) + 1):
            point = dict(zip(_TOP3_POLYTOPE_VARIABLES, _top3_polytope_point(n_value, a), strict=True))
            index = min(bins - 1, max(0, int(point["A"] * bins)))
            buckets[index].append((point["A"], point["K"], point["Q3"]))
    rows = []
    for index, bucket in enumerate(buckets):
        lo = index / bins
        hi = (index + 1) / bins
        if not bucket:
            rows.append((lo, hi, 0.0, 0.0))
            continue
        rows.append((lo, hi, max(item[1] for item in bucket), max(item[2] for item in bucket)))
    return tuple(rows)


def k5_top3_endpoint_polytope_closure_rows(
    max_n: int = 300,
    dense_a_limit: int = 100,
    closure_max_n: int = 60,
) -> tuple[K5Top3PolytopeClosureRow, ...]:
    halfspaces = _top3_polytope_halfspaces_from_scan(max_n=max_n, dense_a_limit=dense_a_limit)
    funcs = _top3_kplus_companion_functions()
    variables = _TOP3_POLYTOPE_VARIABLES
    rows: list[K5Top3PolytopeClosureRow] = []
    # Fit each target halfspace image at n+1 as a nonnegative combination of
    # normalized halfspace functions at n: H_j((n+1)x_n)/(n+1).
    for target in halfspaces:
        matrix: list[list[float]] = []
        target_values: list[float] = []
        for n_value in range(max(0, closure_max_n)):
            for a in range(1, min(n_value + 2, dense_a_limit) + 1):
                next_raw = dict(zip(variables, _top3_polytope_raw_values(n_value + 1, a), strict=True))
                target_values.append(sum(c * next_raw[name] for c, name in zip(target.coefficients, variables, strict=True)))
                source_point = _top3_polytope_point(n_value, a)
                row = []
                for source in halfspaces:
                    row.append(sum(c * x for c, x in zip(source.coefficients, source_point, strict=True)) / (n_value + 1))
                matrix.append(row)
        if not matrix:
            continue
        x_matrix = np.asarray(matrix, dtype=float)
        y_vector = np.asarray(target_values, dtype=float)
        variable_count = x_matrix.shape[1] + 1
        objective = np.zeros(variable_count)
        objective[-1] = 1.0
        a_ub = []
        b_ub = []
        for row_values, y_value in zip(x_matrix, y_vector, strict=True):
            a_ub.append([*row_values, -1.0])
            b_ub.append(float(y_value))
            a_ub.append([*(-row_values), -1.0])
            b_ub.append(float(-y_value))
        result = linprog(
            objective,
            A_ub=np.asarray(a_ub, dtype=float),
            b_ub=np.asarray(b_ub, dtype=float),
            bounds=[(0.0, None)] * variable_count,
            method="highs",
        )
        if not result.success:
            weights = np.zeros(len(halfspaces), dtype=float)
            max_abs_residual = float("inf")
        else:
            weights = np.asarray(result.x[:-1], dtype=float)
            max_abs_residual = float(result.x[-1])
        rhs_constant = sum(float(weight) * source.constant for weight, source in zip(weights, halfspaces, strict=True))
        top_weights = tuple(
            sorted(
                ((halfspaces[index].name, float(weight)) for index, weight in enumerate(weights) if weight > 1e-9),
                key=lambda item: -item[1],
            )[:10]
        )
        rows.append(
            K5Top3PolytopeClosureRow(
                target=target.name,
                max_abs_residual=max_abs_residual,
                rhs_constant=rhs_constant,
                constant=target.constant,
                worst_slack=target.constant - rhs_constant,
                closes=max_abs_residual <= 1e-8 and target.constant - rhs_constant >= -1e-12,
                top_weights=top_weights,
            )
        )
    return tuple(rows)


def print_k5_top3_endpoint_polytope_barrier_report(
    max_n: int = 300,
    dense_a_limit: int = 100,
    closure_max_n: int = 60,
    n: int = 40,
) -> None:
    print("endpoint polytope barrier")
    print()
    print(f"value grid: n <= {max_n}, 1 <= a <= min(n+2,{dense_a_limit})")
    print(f"closure grid: n <= {closure_max_n}")

    print()
    print("1. companion constants")
    scan_rows = {row.name: row for row in k5_top3_kplus_companion_scan_rows(max_n=max_n, dense_a_limit=dense_a_limit)}
    for name in ("A", "K", "Q3", "Q1", "Qhalf", "B", "S"):
        row = scan_rows[name]
        print(f"{name:6s} {row.max_scaled:.12f} argmax=({row.argmax_n},{row.argmax_a}) first_negative={row.first_negative}")

    print()
    print("2. normalized convex hull")
    print("A_bin_lo A_bin_hi max_xK max_xQ3")
    for lo, hi, max_k, max_q3 in _top3_polytope_bin_rows(max_n=max_n, dense_a_limit=dense_a_limit):
        print(f"{lo:.2f} {hi:.2f} {max_k:.12f} {max_q3:.12f}")
    print("top normalized points by x_K:")
    points: list[tuple[float, int, int, tuple[float, ...]]] = []
    for n_value in range(max_n + 1):
        for a in range(1, min(n_value + 2, dense_a_limit) + 1):
            point = _top3_polytope_point(n_value, a)
            points.append((point[_TOP3_POLYTOPE_VARIABLES.index("K")], n_value, a, point))
    for _, n_value, a, point in sorted(points, reverse=True)[:n]:
        values = " ".join(f"{name}={value:.6f}" for name, value in zip(_TOP3_POLYTOPE_VARIABLES, point, strict=True))
        print(f"  n={n_value:4d} a={a:3d} {values}")

    print()
    print("3. candidate halfspaces")
    print("name constant max_value argmax valid_on_data coefficients")
    halfspaces = _top3_polytope_halfspaces_from_scan(max_n=max_n, dense_a_limit=dense_a_limit)
    for row in halfspaces:
        coeff_text = ",".join(f"{name}:{coeff:.3g}" for name, coeff in zip(_TOP3_POLYTOPE_VARIABLES, row.coefficients, strict=True) if abs(coeff) > 1e-12)
        print(
            f"{row.name:22s}"
            f" {row.constant:.12f}"
            f" {row.max_value:.12f}"
            f" ({row.argmax_n},{row.argmax_a})"
            f" {row.max_value <= row.constant + 1e-12}"
            f" {coeff_text}"
        )

    print()
    print("4. halfspace induction closure")
    print("target residual rhs_constant constant worst_slack closes top_weights")
    closure_rows = k5_top3_endpoint_polytope_closure_rows(
        max_n=max_n,
        dense_a_limit=dense_a_limit,
        closure_max_n=closure_max_n,
    )
    for row in closure_rows:
        weights_text = ", ".join(f"{name}:{weight:.6f}" for name, weight in row.top_weights)
        print(
            f"{row.target:22s}"
            f" {row.max_abs_residual:.12f}"
            f" {row.rhs_constant:.12f}"
            f" {row.constant:.12f}"
            f" {row.worst_slack:.12f}"
            f" {row.closes}"
            f" {weights_text}"
        )

    print()
    print("5. K halfspace status")
    k_rows = [row for row in closure_rows if row.target == "K<=1.5"]
    if k_rows:
        row = k_rows[0]
        print(f"K <= 1.5 inductively preserved: {row.closes}")
        print(f"worst induction slack: {row.worst_slack:.12f}")
    else:
        print("K <= 1.5 halfspace was not generated.")
    failures = [row for row in closure_rows if not row.closes]
    if failures:
        worst = min(failures, key=lambda item: item.worst_slack)
        print(f"worst failing halfspace: {worst.target} slack={worst.worst_slack:.12f} residual={worst.max_abs_residual:.3e}")
    else:
        print("All sampled halfspaces close on the induction fit.")

    print()
    print("6. coordinate-box versus polytope closure")
    companion_rows = {row.target: row for row in k5_top3_kplus_companion_closure_rows(max_n=max_n, dense_a_limit=dense_a_limit, closure_max_n=closure_max_n)}
    print(f"coordinate K closes: {companion_rows['K'].closes}")
    print("polytope K closes:", bool(k_rows and k_rows[0].closes))


def _parse_top3_pairs(text: str) -> tuple[tuple[int, int], ...]:
    pairs: list[tuple[int, int]] = []
    for piece in text.split(";"):
        stripped = piece.strip()
        if not stripped:
            continue
        values = tuple(int(part.strip()) for part in stripped.split(",") if part.strip())
        if len(values) != 2:
            raise ValueError(f"top3 pair must have two integers, got {piece!r}")
        pairs.append((values[0], values[1]))
    return tuple(pairs)


def _parse_top3_kernel_pair_cases(text: str | None) -> tuple[tuple[int, int], ...]:
    if text is None:
        return ()
    cases: list[tuple[int, int]] = []
    for piece in text.split(";"):
        stripped = piece.strip()
        if not stripped:
            continue
        parts = [part.strip() for part in stripped.split(":")]
        if len(parts) != 2:
            raise ValueError(f"kernel pairing case must be n:a, got {piece!r}")
        cases.append((int(parts[0]), int(parts[1])))
    return tuple(cases)


def print_k5_worst_family_scaling_report(
    h_values: tuple[int, ...] = (50, 100, 200, 500),
    families: tuple[str, ...] = ("packet_122", "packet_1211", "packet_221", "packet_212"),
    grid: tuple[float, ...] = (0.0, 0.25, 0.5, 0.75, 1.0, 1.25, 1.5, 2.0, 2.5, 3.0),
    potential_name: str = "Q_chase",
    jobs: int = 1,
    progress_file: str | None = None,
    start_method: str = "spawn",
    memory_safe_above: int = 150,
    progress_every: int = 25,
    n: int = 40,
) -> None:
    if progress_file:
        with open(progress_file, "w", encoding="utf-8") as handle:
            handle.write("")
    rows = k5_worst_family_scaling_rows(
        h_values=h_values,
        families=families,
        grid=grid,
        potential_name=potential_name,
        jobs=jobs,
        progress_file=progress_file,
        start_method=start_method,
        memory_safe_above=memory_safe_above,
        progress_every=progress_every,
    )
    print("k=5 worst-family scaling report")
    print()
    print(f"h_values: {h_values}")
    print(f"families: {families}")
    print(f"grid: {grid}")
    print(f"potential: {potential_name}")
    print(f"jobs: {jobs}")
    print(f"start_method: {start_method}")
    print(f"memory_safe_above: {memory_safe_above}")
    print(f"progress_every: {progress_every}")
    print(f"progress_file: {progress_file}")
    print()

    print("A. Worst by h and family")
    for horizon in h_values:
        for family in families:
            group = [row for row in rows if row.horizon == horizon and row.family == family]
            if not group:
                continue
            worst = max(group, key=lambda row: row.scaled_alpha)
            print(
                f"  h={horizon:4d}"
                f" family={family:12s}"
                f" C={worst.scaled_alpha:.6f}"
                f" alpha={worst.alpha:.6f}"
                f" state={worst.state}"
                f" s=({worst.s1:.2f},{worst.s2:.2f},{worst.s3:.2f})"
                f" weights={_format_packet_weights(worst.weights)}"
                f" active={','.join(_format_count_vector(vector) for vector in worst.active_count_vectors)}"
            )

    print()
    print("B. Scaling convergence table")
    top_scaled_points = sorted(
        {(row.family, row.s1, row.s2, row.s3) for row in rows},
        key=lambda key: -max(
            row.scaled_alpha
            for row in rows
            if (row.family, row.s1, row.s2, row.s3) == key
        ),
    )[:n]
    for family, s1, s2, s3 in top_scaled_points:
        pieces = []
        for horizon in h_values:
            matches = [
                row
                for row in rows
                if row.horizon == horizon and row.family == family and row.s1 == s1 and row.s2 == s2 and row.s3 == s3
            ]
            if matches:
                pieces.append(f"h={horizon}:C={matches[0].scaled_alpha:.6f}")
        print(f"  family={family} s=({s1:.2f},{s2:.2f},{s3:.2f}) " + "; ".join(pieces))

    print()
    print("C. Heatmap-like grid table for packet_122")
    for horizon in h_values:
        print(f"  h={horizon}")
        header = "s1\\s2 " + " ".join(f"{s2:>7.2f}" for s2 in grid)
        print("    " + header)
        for s1 in grid:
            values = []
            for s2 in grid:
                match = next(
                    (
                        row
                        for row in rows
                        if row.horizon == horizon and row.family == "packet_122" and row.s1 == s1 and row.s2 == s2
                    ),
                    None,
                )
                values.append(f"{match.scaled_alpha:7.3f}" if match is not None else "   -   ")
            print(f"    {s1:5.2f} " + " ".join(values))

    print()
    print("D. Active-set stability")
    grouped: dict[tuple[str, tuple[tuple[int, ...], ...]], list[K5WorstFamilyScalingRow]] = defaultdict(list)
    for row in rows:
        grouped[(row.family, row.active_count_vectors)].append(row)
    for (family, active_set), group in sorted(grouped.items(), key=lambda item: (-max(row.scaled_alpha for row in item[1]), item[0]))[:n]:
        worst = max(group, key=lambda row: row.scaled_alpha)
        print(
            f"  family={family:12s}"
            f" active={','.join(_format_count_vector(vector) for vector in active_set)}"
            f" count={len(group)}"
            f" max_C={worst.scaled_alpha:.6f}"
            f" worst_h={worst.horizon}"
            f" state={worst.state}"
        )

    print()
    print("E. Candidate limiting worst point")
    for family in families:
        group = [row for row in rows if row.family == family]
        if not group:
            continue
        worst = max(group, key=lambda row: row.scaled_alpha)
        print(
            f"  family={family:12s}"
            f" best_s=({worst.s1:.2f},{worst.s2:.2f},{worst.s3:.2f})"
            f" C={worst.scaled_alpha:.6f}"
            f" h={worst.horizon}"
            f" state={worst.state}"
        )

    print()
    print("F. Proof hint equations")
    worst = max(rows, key=lambda row: row.scaled_alpha)
    print(
        f"  worst family={worst.family} h={worst.horizon} state={worst.state}"
        f" C={worst.scaled_alpha:.6f} alpha={worst.alpha:.6f}"
    )
    simplex = " + ".join(f"{size}*w{index + 1}" for index, size in enumerate(packet_type(worst.state)))
    print(f"    simplex: {simplex} = 1")
    for count_vector, residual, q_value in worst.active_constraints:
        terms = " + ".join(f"{count}*w{index + 1}" for index, count in enumerate(count_vector) if count)
        if not terms:
            terms = "0"
        print(
            f"    q({_format_count_vector(count_vector)}) - ({terms}) = alpha"
            f" ; q={q_value:.6f} residual={residual:.6f}"
        )


def _k6_fixed_pattern_names() -> tuple[str, ...]:
    return (
        "fixed_101010_comb",
        "fixed_101011_truncated",
        "fixed_101000_prefix3",
        "fixed_100000_singleton",
        "top_prefix_all",
    )


def print_k6_adaptive_interval_anatomy_report(
    T: int,
    long_T_values: tuple[int, ...],
    support_tolerance: float = 1e-8,
    n: int = 40,
) -> None:
    zero = (0, 0, 0, 0, 0, 0)
    fixed_names = _k6_fixed_pattern_names()
    print("k=6 adaptive interval anatomy report")
    print()
    print(f"T: {T}")
    print(f"long T values: {long_T_values}")
    print()

    print("Fixed pattern comparison")
    print(
        "T policy                           V_policy V_policy/sqrt(T)"
        " gap_to_top_prefix gap_to_top_prefix/sqrt(T)"
    )
    for horizon in (T,) + tuple(long_T_values):
        top_prefix = evaluate_time_dependent_policy_reachable_root(
            6,
            horizon,
            _resolve_time_dependent_policy(6, "top_prefix_all"),
        ).value
        for name in fixed_names:
            policy_fn = _resolve_time_dependent_policy(6, name)
            if policy_fn is None:
                raise ValueError(f"unknown policy: {name}")
            value = top_prefix if name == "top_prefix_all" else evaluate_time_dependent_policy_reachable_root(
                6,
                horizon,
                policy_fn,
            ).value
            gap = top_prefix - value
            sqrt_horizon = horizon ** 0.5
            print(
                f"{horizon:3d} {name:31s}"
                f" {value:10.6f}"
                f" {value / sqrt_horizon:16.6f}"
                f" {gap:17.6f}"
                f" {gap / sqrt_horizon:26.6f}"
            )
    print()

    print("Reference restricted LP values at T")
    for library_name in ("top_prefix_all", "one_run", "two_run", "local_edges"):
        value = _library_lp_value_layers(6, T, _strategy_class_library_actions(6, T, library_name))[T][zero]
        print(f"  {library_name:14s} V={value:.6f}")
    print()

    _, top_rows = library_lp_dual_inspect_rows(6, T, "top_prefix_all", support_tolerance=support_tolerance)
    print("Top-prefix interval mass")
    global_interval_totals: dict[tuple[int, int] | None, float] = defaultdict(float)
    by_horizon: dict[int, dict[tuple[int, int] | None, float]] = defaultdict(lambda: defaultdict(float))
    by_regime: dict[tuple[int, tuple[int, ...], tuple[int, ...]], dict[tuple[int, int] | None, float]] = defaultdict(
        lambda: defaultdict(float)
    )
    for row in top_rows:
        for weight, action, _ in row.support:
            interval = _interval_from_action(action)
            mass = row.occupancy_probability * weight
            global_interval_totals[interval] += mass
            by_horizon[row.remaining_horizon][interval] += mass
            by_regime[(row.remaining_horizon, row.packet_type, row.packet_gaps)][interval] += mass
    print(f"  global: {_format_interval_distribution(global_interval_totals)}")
    print("  by remaining horizon:")
    for remaining_horizon, totals in sorted(by_horizon.items(), reverse=True):
        print(f"    rem={remaining_horizon:2d}: {_format_interval_distribution(totals)}")
    print("  top regime interval distributions:")
    regime_masses = {
        key: sum(totals.values())
        for key, totals in by_regime.items()
    }
    for (remaining_horizon, ptype, gaps), _ in sorted(regime_masses.items(), key=lambda item: (-item[1], item[0]))[:n]:
        print(
            f"    rem={remaining_horizon:2d} packet={ptype} gaps={gaps}"
            f" mass={regime_masses[(remaining_horizon, ptype, gaps)]:.6f}"
            f" intervals={_format_interval_distribution(by_regime[(remaining_horizon, ptype, gaps)])}"
        )
    print()

    print("Top-prefix top rows by occupancy")
    for row in sorted(top_rows, key=lambda item: (-item.occupancy_probability, item.time, item.state))[:n]:
        interval_totals: dict[tuple[int, int] | None, float] = defaultdict(float)
        for weight, action, _ in row.support:
            interval_totals[_interval_from_action(action)] += weight
        print(
            f"  rem={row.remaining_horizon:2d} state={row.state}"
            f" packet={row.packet_type} gaps={row.packet_gaps}"
            f" occ={row.occupancy_probability:.6f}"
            f" intervals={_format_interval_distribution(interval_totals)}"
        )
    print()

    print("One-run vs top-prefix differences")
    one_run_actions = _strategy_class_library_actions(6, T, "one_run")
    one_run_values = _library_lp_value_layers(6, T, one_run_actions)
    one_run_interval_rows = {
        (row.time, row.state): row
        for row in k6_one_run_interval_rule_rows(T, support_tolerance=support_tolerance)
    }
    correction_rows: list[tuple[float, LibraryLPDualInspectRow, float, tuple[tuple[tuple[int, int] | None, float], ...]]] = []
    for row in top_rows:
        continuation = one_run_values[row.remaining_horizon - 1]
        top_policy = tuple((weight, action) for weight, action, _ in row.support)
        top_step = _time_policy_step_value(6, row.state, top_policy, continuation)
        one_run_value = one_run_values[row.remaining_horizon][row.state]
        action_loss = one_run_value - top_step
        interval_row = one_run_interval_rows.get((row.time, row.state))
        if interval_row is None:
            q_by_action = {
                action: _next_state_value(row.state, action, continuation)
                for action in one_run_actions
            }
            dual = solve_adversary_dual(q_by_action, 6)
            support = tuple(
                K6OneRunIntervalActionRow(
                    weight=weight,
                    action=action,
                    edge_signature=_edge_signature(action),
                    interval=_interval_from_action(action),
                    relation_class=_classify_k6_one_run_interval_relation(_interval_from_action(action), row.state),
                    successor_packet_type=packet_type(canon(tuple(row.state[index] + action[index] for index in range(6)))),
                )
                for action, weight in dual.weights_by_action
                if weight >= support_tolerance
            )
        else:
            support = interval_row.support
        interval_distribution = _interval_distribution_for_interval_support(support)
        correction_rows.append((row.occupancy_probability * action_loss, row, action_loss, interval_distribution))
    for weighted_loss, row, action_loss, interval_distribution in sorted(
        correction_rows,
        key=lambda item: (-item[0], item[1].time, item[1].state),
    )[:n]:
        top_interval_totals: dict[tuple[int, int] | None, float] = defaultdict(float)
        for weight, action, _ in row.support:
            top_interval_totals[_interval_from_action(action)] += weight
        one_run_intervals = ", ".join(
            f"{_format_interval(interval)}:{weight:.3f}"
            for interval, weight in interval_distribution[:5]
        )
        print(
            f"  rem={row.remaining_horizon:2d}"
            f" packet={row.packet_type} gaps={row.packet_gaps}"
            f" state={row.state}"
            f" occ={row.occupancy_probability:.6f}"
            f" action_loss={action_loss:.6f}"
            f" weighted_loss={weighted_loss:.6f}"
            f" top_prefix={_format_interval_distribution(top_interval_totals)}"
            f" one_run=[{one_run_intervals}]"
        )
    print()

    print("Candidate distillation target")
    dominant_rules = 0
    for (remaining_horizon, ptype, gaps), totals in sorted(regime_masses.items(), key=lambda item: (-item[1], item[0]))[:n]:
        interval_totals = by_regime[(remaining_horizon, ptype, gaps)]
        total = sum(interval_totals.values())
        best_interval, best_mass = max(interval_totals.items(), key=lambda item: item[1])
        if total > 0 and best_mass / total >= 0.9:
            dominant_rules += 1
            print(
                f"  top-prefix rule: rem={remaining_horizon} packet={ptype} gaps={gaps}"
                f" -> interval={_format_interval(best_interval)} mass_share={best_mass / total:.3f}"
            )
    if dominant_rules == 0:
        print("  no >=90% top-prefix regime rules in printed set")
    print("  missing correction candidates:")
    tried_regimes = {
        (patch.remaining_horizon, patch.packet_type, patch.packet_gaps)
        for patch in _k6_one_run_patch_list()
    }
    tried_regimes.add((5, (1, 2, 2, 1), (1, 1, 2)))
    for weighted_loss, row, _, interval_distribution in sorted(correction_rows, key=lambda item: (-item[0], item[1].state))[:n]:
        if not interval_distribution:
            continue
        interval, weight = interval_distribution[0]
        if interval is None or interval[0] == 0 or weight < 0.5:
            continue
        regime = (row.remaining_horizon, row.packet_type, row.packet_gaps)
        print(
            f"    rem={row.remaining_horizon} packet={row.packet_type} gaps={row.packet_gaps}"
            f" nonprefix={_format_interval(interval)} mass={weight:.3f}"
            f" weighted_loss={weighted_loss:.6f}"
            f" tried={'yes' if regime in tried_regimes else 'no'}"
        )


def _format_interval_distribution_tuple(
    distribution: tuple[tuple[tuple[int, int] | None, float], ...],
) -> str:
    return ", ".join(f"{_format_interval(interval)}:{weight:.3f}" for interval, weight in distribution) or "-"


def _barycenter_global_summary(rows: tuple[BarycenterActionRow, ...]):
    totals: dict[tuple[str, str], dict[str, float]] = defaultdict(lambda: defaultdict(float))
    for row in rows:
        for packet in row.packet_summaries:
            key = (row.library_name, packet.status)
            weight = row.occupancy_probability * packet.packet_size
            totals[key]["mass"] += weight
            totals[key]["exposure"] += weight * packet.exposure
            totals[key]["split_rate"] += weight * packet.split_rate
    return totals


def _barycenter_top_bottom_summary(rows: tuple[BarycenterActionRow, ...]):
    totals: dict[str, dict[str, float]] = defaultdict(lambda: defaultdict(float))
    for row in rows:
        totals[row.library_name]["occupancy"] += row.occupancy_probability
        totals[row.library_name]["top1_bottom0"] += row.occupancy_probability * row.p_top1_bottom0
        totals[row.library_name]["top0_bottom1"] += row.occupancy_probability * row.p_top0_bottom1
        totals[row.library_name]["top_equals_bottom"] += row.occupancy_probability * row.p_top_equals_bottom
        totals[row.library_name]["covariance"] += row.occupancy_probability * row.top_bottom_covariance
    return totals


def _format_packet_statuses(row: BarycenterActionRow) -> str:
    return ",".join(
        f"{summary.packet_index}:{summary.status}:size{summary.packet_size}:exp{summary.exposure:.3f}:split{summary.split_rate:.3f}"
        for summary in row.packet_summaries
    )


def _classify_one_run_correction(distribution: tuple[tuple[tuple[int, int] | None, float], ...]) -> str:
    intervals = {interval for interval, weight in distribution if weight > 1e-8}
    if intervals == {(0, 0)}:
        return "top-alone"
    if intervals == {(0, 4)}:
        return "full-comb"
    if intervals == {(1, 4)}:
        return "tail-chase"
    if {(0, 0), (0, 4), (1, 4)}.issubset(intervals):
        return "mixed top/full/tail"
    if any(interval is not None and interval[0] > 0 and interval[1] < 4 for interval in intervals):
        return "middle-repair"
    return "other"


def print_k6_barycenter_action_anatomy_report(
    T: int,
    support_tolerance: float = 1e-8,
    n: int = 30,
) -> None:
    _, top_dual_rows = library_lp_dual_inspect_rows(6, T, "top_prefix_all", support_tolerance=support_tolerance)
    _, one_dual_rows = library_lp_dual_inspect_rows(6, T, "one_run", support_tolerance=support_tolerance)
    rows = tuple(
        [_barycenter_action_row_from_dual_row("top_prefix_all", row) for row in top_dual_rows]
        + [_barycenter_action_row_from_dual_row("one_run", row) for row in one_dual_rows]
    )
    print("k=6 barycenter action anatomy report")
    print()
    print(f"T: {T}")
    print(f"support tolerance: {support_tolerance:.3g}")
    print()

    print("Global barycenter exposure summary")
    summary = _barycenter_global_summary(rows)
    for library_name in ("top_prefix_all", "one_run"):
        print(f"  library={library_name}")
        for status in ("above_mean", "crosses_mean", "below_mean"):
            item = summary.get((library_name, status), {})
            mass = item.get("mass", 0.0)
            exposure = item.get("exposure", 0.0) / mass if mass else 0.0
            split_rate = item.get("split_rate", 0.0) / mass if mass else 0.0
            print(
                f"    {status:12s}"
                f" packet_mass={mass:.6f}"
                f" exposure={exposure:.6f}"
                f" split_rate={split_rate:.6f}"
            )
    print()

    print("Top-bottom correlation summary")
    top_bottom = _barycenter_top_bottom_summary(rows)
    for library_name in ("top_prefix_all", "one_run"):
        item = top_bottom[library_name]
        occupancy = item["occupancy"] or 1.0
        print(
            f"  {library_name:14s}"
            f" P(top=1,bottom=0)={item['top1_bottom0'] / occupancy:.6f}"
            f" P(top=0,bottom=1)={item['top0_bottom1'] / occupancy:.6f}"
            f" P(top=bottom)={item['top_equals_bottom'] / occupancy:.6f}"
            f" covariance={item['covariance'] / occupancy:.6f}"
        )
    print()

    top_rows_by_key = {
        (row.time, row.state): row for row in rows if row.library_name == "top_prefix_all"
    }
    top_dual_rows_by_key = {(row.time, row.state): row for row in top_dual_rows}
    one_rows_by_key = {
        (row.time, row.state): row for row in rows if row.library_name == "one_run"
    }
    one_run_values = _library_lp_value_layers(6, T, _strategy_class_library_actions(6, T, "one_run"))
    differences: list[tuple[float, BarycenterActionRow, BarycenterActionRow, float]] = []
    for key, top_row in top_rows_by_key.items():
        if key not in one_rows_by_key:
            continue
        continuation = one_run_values[top_row.remaining_horizon - 1]
        top_support = tuple((weight, action) for weight, action, _ in top_dual_rows_by_key[key].support)
        top_step = _time_policy_step_value(6, top_row.state, top_support, continuation)
        one_value = one_run_values[top_row.remaining_horizon][top_row.state]
        action_loss = one_value - top_step
        differences.append((top_row.occupancy_probability * action_loss, top_row, one_rows_by_key[key], action_loss))

    print("Top one_run-vs-top_prefix difference regimes")
    for weighted_loss, top_row, one_row, action_loss in sorted(differences, key=lambda item: (-item[0], item[1].state))[:n]:
        print(
            f"  rem={top_row.remaining_horizon:2d}"
            f" state={top_row.state}"
            f" mean={top_row.mean_score:.3f}"
            f" packet={top_row.packet_type} gaps={top_row.packet_gaps}"
            f" occ={top_row.occupancy_probability:.6f}"
            f" action_loss={action_loss:.6f}"
            f" weighted_loss={weighted_loss:.6f}"
        )
        print(f"    packet statuses: {_format_packet_statuses(one_row)}")
        print(f"    top_prefix intervals: {_format_interval_distribution_tuple(top_row.interval_distribution)}")
        print(f"    one_run intervals:    {_format_interval_distribution_tuple(one_row.interval_distribution)}")
        print(
            f"    top_prefix top/bottom: p10={top_row.p_top1_bottom0:.3f}"
            f" p01={top_row.p_top0_bottom1:.3f}"
            f" same={top_row.p_top_equals_bottom:.3f}"
            f" cov={top_row.top_bottom_covariance:.3f}"
        )
        print(
            f"    one_run top/bottom:    p10={one_row.p_top1_bottom0:.3f}"
            f" p01={one_row.p_top0_bottom1:.3f}"
            f" same={one_row.p_top_equals_bottom:.3f}"
            f" cov={one_row.top_bottom_covariance:.3f}"
        )
    print()

    print("Rule hints")
    label_totals: dict[str, float] = defaultdict(float)
    for row in rows:
        if row.library_name != "one_run":
            continue
        label_totals[_classify_one_run_correction(row.interval_distribution)] += row.occupancy_probability
    for label, mass in sorted(label_totals.items(), key=lambda item: (-item[1], item[0])):
        print(f"  {label:20s} occupancy={mass:.6f}")


